  function refreshLocalizedUi() {
    applyUiLocalization();
    syncControlsWithState();
    renderColorPanelPalettePresetOptions(currentPalettePresetId);
    renderPalettePresetPreview(currentPalettePresetId);
    renderNewProjectPalettePresetOptions(newProjectPalettePresetId);
    renderNewProjectPalettePresetPicker(newProjectPalettePresetId);
    const cachedEntries = Array.from(recentProjectsCache.values());
    syncStartupResumeState(cachedEntries);
    renderRecentProjectsList(cachedEntries);
  }

  function setUiLanguage(nextLanguage, { persist = true } = {}) {
    const normalized = normalizeUiLanguage(nextLanguage, uiLanguage);
    if (normalized === uiLanguage) {
      refreshLocalizedUi();
      return;
    }
    uiLanguage = normalized;
    setDocumentLanguage();
    if (persist) {
      storeUiLanguage(normalized);
    }
    refreshLocalizedUi();
  }

  function getMaxSpriteMultiplier() {
    const largest = Math.max(state.width || 0, state.height || 0);
    if (!largest) return 1;
    return Math.max(1, Math.floor(MAX_CANVAS_SIZE / largest));
  }

  function updateSpriteScaleControlLimits() {
    const input = dom.controls.spriteScaleInput;
    const button = dom.controls.applySpriteScale;
    const decrementButton = dom.controls.spriteScaleDecrement;
    const incrementButton = dom.controls.spriteScaleIncrement;
    if (!input) return;
    const maxMultiplier = getMaxSpriteMultiplier();
    if (maxMultiplier <= 1) {
      input.min = '1';
      input.max = '1';
      input.value = '1';
      input.disabled = true;
      if (button) button.setAttribute('disabled', 'true');
      if (decrementButton) decrementButton.setAttribute('disabled', 'true');
      if (incrementButton) incrementButton.setAttribute('disabled', 'true');
    } else {
      input.min = '1';
      input.max = String(maxMultiplier);
      const current = Math.max(1, Math.min(maxMultiplier, Math.floor(Number(input.value) || 1)));
      input.value = String(current);
      input.disabled = false;
      if (button) {
        if (current > 1) button.removeAttribute('disabled');
        else button.setAttribute('disabled', 'true');
      }
      if (decrementButton) {
        if (current <= 1) decrementButton.setAttribute('disabled', 'true');
        else decrementButton.removeAttribute('disabled');
      }
      if (incrementButton) {
        if (current >= maxMultiplier) incrementButton.setAttribute('disabled', 'true');
        else incrementButton.removeAttribute('disabled');
      }
    }
  }

  function adjustSpriteScaleInputBy(delta) {
    const input = dom.controls.spriteScaleInput;
    if (!input || input.disabled) {
      return;
    }
    const min = Math.max(1, Math.floor(Number(input.min) || 1));
    const max = Math.max(min, Math.floor(Number(input.max) || getMaxSpriteMultiplier()));
    const current = clamp(Math.floor(Number(input.value) || min), min, max);
    const next = clamp(current + Math.round(Number(delta) || 0), min, max);
    if (next === current) {
      updateSpriteScaleControlLimits();
      return;
    }
    input.value = String(next);
    updateSpriteScaleControlLimits();
  }

  // -------------------------------------------------------------------------
  // Autosave & File System Access support
  // -------------------------------------------------------------------------

  function updateAutosaveStatus(message, tone = 'info') {
    const statusNode = dom.controls.autosaveStatus;
    if (!statusNode) return;
    statusNode.textContent = message;
    statusNode.dataset.tone = tone;
  }

  function getAutosaveBlockedStatusMessage() {
    if (isResidentMultiConnectedRoom()) {
      return RESIDENT_CANVAS_AUTOSAVE_BLOCKED_STATUS;
    }
    if (multiState.connected && !isMultiMasterMode()) {
      return MULTI_REPLICA_AUTOSAVE_BLOCKED_STATUS;
    }
    return '';
  }

  function parseAutosaveTabLockPayload(raw) {
    if (typeof raw !== 'string' || !raw.trim()) {
      return null;
    }
    try {
      const parsed = JSON.parse(raw);
      if (!parsed || typeof parsed !== 'object') {
        return null;
      }
      const owner = typeof parsed.owner === 'string' ? parsed.owner : '';
      const expiresAt = Number(parsed.expiresAt);
      if (!owner || !Number.isFinite(expiresAt)) {
        return null;
      }
      return {
        owner,
        expiresAt: Math.round(expiresAt),
      };
    } catch (error) {
      return null;
    }
  }

  function readAutosaveTabLock() {
    if (!canUseSessionStorage) {
      return null;
    }
    try {
      return parseAutosaveTabLockPayload(window.localStorage.getItem(AUTOSAVE_TAB_LOCK_KEY) || '');
    } catch (error) {
      return null;
    }
  }

  function tryAcquireAutosaveTabLock() {
    if (!canUseSessionStorage) {
      return true;
    }
    const now = Date.now();
    const current = readAutosaveTabLock();
    if (
      current
      && current.owner !== autosaveTabInstanceId
      && current.expiresAt > now
    ) {
      return false;
    }
    const nextLock = {
      owner: autosaveTabInstanceId,
      expiresAt: now + AUTOSAVE_TAB_LOCK_TTL_MS,
    };
    try {
      window.localStorage.setItem(AUTOSAVE_TAB_LOCK_KEY, JSON.stringify(nextLock));
      const verified = readAutosaveTabLock();
      return Boolean(verified && verified.owner === autosaveTabInstanceId && verified.expiresAt === nextLock.expiresAt);
    } catch (error) {
      return true;
    }
  }

  function releaseAutosaveTabLock() {
    if (!canUseSessionStorage) {
      return;
    }
    const lock = readAutosaveTabLock();
    if (!lock || lock.owner !== autosaveTabInstanceId) {
      return;
    }
    try {
      window.localStorage.removeItem(AUTOSAVE_TAB_LOCK_KEY);
    } catch (error) {
      // Ignore localStorage errors.
    }
  }

  function shouldAnnounceAutosaveTabLockWait() {
    const now = Date.now();
    if ((now - autosaveTabLockNoticeAt) < AUTOSAVE_TAB_LOCK_NOTICE_THROTTLE_MS) {
      return false;
    }
    autosaveTabLockNoticeAt = now;
    return true;
  }

  function handleAutosaveStorageEvent(event) {
    if (
      !AUTOSAVE_SUPPORTED
      || (typeof StorageEvent !== 'undefined' && !(event instanceof StorageEvent))
    ) {
      return;
    }
    if (event.key !== AUTOSAVE_TAB_LOCK_KEY) {
      return;
    }
    if (autosaveWriteInFlight) {
      return;
    }
    if (!autosaveDirty && !autosaveWriteQueued) {
      return;
    }
    if (!event.newValue) {
      scheduleAutosaveSnapshot();
      return;
    }
    const nextLock = parseAutosaveTabLockPayload(event.newValue);
    if (!nextLock || nextLock.owner === autosaveTabInstanceId || nextLock.expiresAt <= Date.now()) {
      scheduleAutosaveSnapshot();
    }
  }

  function setupAutosaveControls() {
    const button = dom.controls.enableAutosave;
    if (!button) return;
    button.textContent = localizeText('ローカル自動保存（常時ON）', 'Local Autosave (Always ON)');
    button.disabled = true;
  }

  function sanitizeExportDirectoryDisplayLabel(value) {
    return typeof value === 'string' ? value.trim() : '';
  }

  function buildExportDirectoryDisplayLabel({ rootHandle = null, workspaceHandle = null, fallback = '' } = {}) {
    const rootName = sanitizeExportDirectoryDisplayLabel(rootHandle?.name || '');
    const workspaceName = sanitizeExportDirectoryDisplayLabel(workspaceHandle?.name || '');
    const fallbackName = sanitizeExportDirectoryDisplayLabel(fallback);
    if (rootName && workspaceName) {
      if (rootName === workspaceName) {
        return workspaceName;
      }
      return `${rootName}/${workspaceName}`;
    }
    return workspaceName || rootName || fallbackName;
  }

  function loadStoredExportDirectoryDisplayLabel() {
    if (!canUseSessionStorage) {
      return '';
    }
    try {
      return sanitizeExportDirectoryDisplayLabel(window.localStorage.getItem(EXPORT_DIRECTORY_DISPLAY_LABEL_KEY) || '');
    } catch (error) {
      return '';
    }
  }

  function storeExportDirectoryDisplayLabel(label) {
    if (!canUseSessionStorage) {
      return;
    }
    const normalized = sanitizeExportDirectoryDisplayLabel(label);
    try {
      if (normalized) {
        window.localStorage.setItem(EXPORT_DIRECTORY_DISPLAY_LABEL_KEY, normalized);
      } else {
        window.localStorage.removeItem(EXPORT_DIRECTORY_DISPLAY_LABEL_KEY);
      }
    } catch (error) {
      // Ignore localStorage errors.
    }
  }

  function clearStoredExportDirectoryDisplayLabel() {
    if (!canUseSessionStorage) {
      return;
    }
    try {
      window.localStorage.removeItem(EXPORT_DIRECTORY_DISPLAY_LABEL_KEY);
    } catch (error) {
      // Ignore localStorage errors.
    }
  }

  function setExportDirectoryDisplayLabel(label, { persist = true } = {}) {
    exportDirectoryDisplayLabel = sanitizeExportDirectoryDisplayLabel(label);
    if (persist) {
      storeExportDirectoryDisplayLabel(exportDirectoryDisplayLabel);
    }
    updateExportDestinationLabel();
  }

  function getExportDestinationLabelText() {
    if (!EXPORT_DIRECTORY_SUPPORTED) {
      return localizeText(
        '画像/GIF/SVG出力先: 固定出力先は使用しません（保存時に保存先を選択）',
        'Image/GIF/SVG destination: fixed folder is disabled (choose destination when saving)'
      );
    }
    const activeHandle = exportDirectoryHandle || pendingExportDirectoryHandle;
    const displayLabel = sanitizeExportDirectoryDisplayLabel(exportDirectoryDisplayLabel)
      || buildExportDirectoryDisplayLabel({
        workspaceHandle: activeHandle,
        fallback: EXPORT_WORKSPACE_DIR_NAME,
      });
    if (exportDirectoryHandle) {
      return localizeText(
        `画像/GIF/SVG出力先: ${displayLabel}/（フルパスはブラウザ仕様で非表示）`,
        `Image/GIF/SVG destination: ${displayLabel}/ (full path hidden by browser)`
      );
    }
    if (pendingExportDirectoryHandle) {
      return localizeText(
        `画像/GIF/SVG出力先: ${displayLabel}/（再許可が必要）`,
        `Image/GIF/SVG destination: ${displayLabel}/ (reauthorization required)`
      );
    }
    return localizeText(
      '画像/GIF/SVG出力先: 未固定（保存時に保存先を選択）',
      'Image/GIF/SVG destination: not fixed (choose destination when saving)'
    );
  }

  function updateExportDestinationLabel() {
    const labelText = getExportDestinationLabelText();
    const labelNodes = [
      dom.controls.exportDestinationLabel,
      dom.exportDialog?.destinationLabel,
      dom.newProject?.exportDestinationLabel,
    ];
    labelNodes.forEach(node => {
      if (node instanceof HTMLElement) {
        node.textContent = labelText;
      }
    });
  }

  function updateExportFolderStatus(message, tone = 'info') {
    const statusNode = dom.controls.exportFolderStatus;
    if (statusNode) {
      statusNode.hidden = !EXPORT_DIRECTORY_SUPPORTED;
      if (statusNode.hidden) {
        statusNode.textContent = '';
        delete statusNode.dataset.tone;
        updateExportDestinationLabel();
        return;
      }
      statusNode.textContent = message;
      statusNode.dataset.tone = tone;
    }
    updateExportDestinationLabel();
  }

  function updateExportFolderButtonLabel() {
    const buttons = [dom.controls.bindExportFolder, dom.newProject?.bindExportFolder];
    if (!buttons.length) {
      return;
    }
    if (!EXPORT_DIRECTORY_SUPPORTED) {
      buttons.forEach(button => {
        if (!(button instanceof HTMLButtonElement)) {
          return;
        }
        const isNewProjectButton = button === dom.newProject?.bindExportFolder;
        button.hidden = true;
        button.disabled = true;
        button.textContent = isNewProjectButton
          ? localizeText('保存先固定を使用しない', 'Disable fixed save destination')
          : localizeText('出力先固定を使用しない', 'Disable fixed export destination');
      });
      return;
    }
    buttons.forEach(button => {
      if (!(button instanceof HTMLButtonElement)) {
        return;
      }
      const isNewProjectButton = button === dom.newProject?.bindExportFolder;
      button.hidden = false;
      button.disabled = false;
      if (exportDirectoryHandle) {
        button.textContent = isNewProjectButton
          ? localizeText('保存先フォルダを変更', 'Change save folder')
          : localizeText('出力フォルダを変更', 'Change export folder');
        return;
      }
      if (pendingExportDirectoryHandle) {
        button.textContent = isNewProjectButton
          ? localizeText('保存先フォルダを再許可', 'Reauthorize save folder')
          : localizeText('出力フォルダを再許可', 'Reauthorize export folder');
        return;
      }
      button.textContent = isNewProjectButton
        ? localizeText('保存先フォルダを指定', 'Choose save folder')
        : localizeText('出力フォルダを設定', 'Set export folder');
    });
  }

  async function ensureExportWorkspaceDirectory(handle) {
    if (!handle || typeof handle.getDirectoryHandle !== 'function') {
      return handle;
    }
    try {
      return await handle.getDirectoryHandle(EXPORT_WORKSPACE_DIR_NAME, { create: true });
    } catch (error) {
      console.warn('Failed to create PiXiEED export workspace directory', error);
      return handle;
    }
  }

  function schedulePendingExportDirectoryPermission(handle) {
    pendingExportDirectoryHandle = handle || null;
    exportDirectoryHandle = null;
    if (handle) {
      const nextLabel = buildExportDirectoryDisplayLabel({
        workspaceHandle: handle,
        fallback: exportDirectoryDisplayLabel || EXPORT_WORKSPACE_DIR_NAME,
      });
      setExportDirectoryDisplayLabel(nextLabel);
    } else {
      updateExportDestinationLabel();
    }
    updateExportFolderButtonLabel();
    updateExportFolderStatus(
      localizeText(
        '出力フォルダ: 権限が必要です。ボタンを押して再許可してください',
        'Export folder: permission required. Press the button to reauthorize.'
      ),
      'warn'
    );
  }

  async function attemptExportDirectoryReauthorization() {
    if (!pendingExportDirectoryHandle) {
      return false;
    }
    const handle = pendingExportDirectoryHandle;
    const granted = await ensureHandlePermission(handle, { request: true });
    if (!granted) {
      schedulePendingExportDirectoryPermission(handle);
      return false;
    }
    pendingExportDirectoryHandle = null;
    exportDirectoryHandle = handle;
    const nextLabel = buildExportDirectoryDisplayLabel({
      workspaceHandle: handle,
      fallback: exportDirectoryDisplayLabel || EXPORT_WORKSPACE_DIR_NAME,
    });
    setExportDirectoryDisplayLabel(nextLabel);
    await storeExportDirectoryHandle(handle);
    updateExportFolderButtonLabel();
    updateExportFolderStatus(
      localizeText(
        `出力フォルダ: 設定済み (${EXPORT_WORKSPACE_DIR_NAME})`,
        `Export folder: set (${EXPORT_WORKSPACE_DIR_NAME})`
      ),
      'success'
    );
    return true;
  }

  async function requestExportDirectoryBinding() {
    if (!EXPORT_DIRECTORY_SUPPORTED || typeof window.showDirectoryPicker !== 'function') {
      updateExportFolderButtonLabel();
      updateExportFolderStatus(localizeText('出力フォルダ: このブラウザでは利用できません', 'Export folder: unsupported in this browser'), 'warn');
      return false;
    }
    try {
      const rootHandle = await window.showDirectoryPicker({
        id: EXPORT_DIRECTORY_PICKER_ID,
        mode: 'readwrite',
      });
      const grantedRoot = await ensureHandlePermission(rootHandle, { request: true });
      if (!grantedRoot) {
        schedulePendingExportDirectoryPermission(rootHandle);
        return false;
      }
      const workspaceHandle = await ensureExportWorkspaceDirectory(rootHandle);
      const grantedWorkspace = await ensureHandlePermission(workspaceHandle, { request: true });
      if (!grantedWorkspace) {
        schedulePendingExportDirectoryPermission(workspaceHandle);
        return false;
      }
      exportDirectoryHandle = workspaceHandle;
      pendingExportDirectoryHandle = null;
      exportDirectorySetupDismissed = false;
      const nextLabel = buildExportDirectoryDisplayLabel({
        rootHandle,
        workspaceHandle,
        fallback: EXPORT_WORKSPACE_DIR_NAME,
      });
      setExportDirectoryDisplayLabel(nextLabel);
      await storeExportDirectoryHandle(workspaceHandle);
      updateExportFolderButtonLabel();
      updateExportFolderStatus(
        localizeText(
          `出力フォルダ: 設定済み (${EXPORT_WORKSPACE_DIR_NAME})`,
          `Export folder: set (${EXPORT_WORKSPACE_DIR_NAME})`
        ),
        'success'
      );
      return true;
    } catch (error) {
      if (error && error.name === 'AbortError') {
        exportDirectorySetupDismissed = true;
        updateExportFolderStatus(localizeText('出力フォルダ: キャンセルしました', 'Export folder: cancelled'), 'warn');
        return false;
      }
      console.warn('Export directory binding failed', error);
      updateExportFolderStatus(localizeText('出力フォルダ: フォルダを選択できませんでした', 'Export folder: failed to select folder'), 'error');
      return false;
    }
  }

  function setupExportDirectoryControls() {
    const buttons = [
      dom.controls.bindExportFolder,
      dom.newProject?.bindExportFolder,
    ].filter(button => button instanceof HTMLButtonElement);
    if (!buttons.length) {
      updateExportDestinationLabel();
      return;
    }
    updateExportFolderButtonLabel();
    updateExportDestinationLabel();
    if (!EXPORT_DIRECTORY_SUPPORTED) {
      updateExportFolderStatus(
        localizeText(
          '出力フォルダ: 固定出力先は使用しません（保存時に保存先を選択）',
          'Export folder: fixed destination is disabled (choose destination when saving)'
        ),
        'info'
      );
      return;
    }
    buttons.forEach(button => {
      if (button.dataset.bound === 'true') {
        return;
      }
      button.dataset.bound = 'true';
      button.addEventListener('click', async () => {
        exportDirectorySetupDismissed = false;
        if (pendingExportDirectoryHandle && !exportDirectoryHandle) {
          const restored = await attemptExportDirectoryReauthorization();
          if (restored) {
            return;
          }
        }
        await requestExportDirectoryBinding();
      });
    });
  }

  async function initializeExportDirectoryBinding() {
    const storedDisplayLabel = loadStoredExportDirectoryDisplayLabel();
    setExportDirectoryDisplayLabel(storedDisplayLabel, { persist: false });
    setupExportDirectoryControls();
    if (!EXPORT_DIRECTORY_SUPPORTED) {
      return;
    }
    updateExportFolderStatus(localizeText('出力フォルダ: 初期化中…', 'Export folder: initializing...'), 'info');
    try {
      const handle = await loadStoredExportDirectoryHandle();
      if (!handle) {
        setExportDirectoryDisplayLabel('');
        updateExportFolderButtonLabel();
        updateExportFolderStatus(localizeText('出力フォルダ: 未設定', 'Export folder: not set'), 'info');
        return;
      }
      const granted = await ensureHandlePermission(handle, { request: false });
      if (granted) {
        exportDirectoryHandle = handle;
        pendingExportDirectoryHandle = null;
        const nextLabel = sanitizeExportDirectoryDisplayLabel(exportDirectoryDisplayLabel)
          || buildExportDirectoryDisplayLabel({
            workspaceHandle: handle,
            fallback: EXPORT_WORKSPACE_DIR_NAME,
          });
        setExportDirectoryDisplayLabel(nextLabel);
        updateExportFolderButtonLabel();
        updateExportFolderStatus(
          localizeText(
            `出力フォルダ: 設定済み (${EXPORT_WORKSPACE_DIR_NAME})`,
            `Export folder: set (${EXPORT_WORKSPACE_DIR_NAME})`
          ),
          'success'
        );
      } else {
        schedulePendingExportDirectoryPermission(handle);
      }
    } catch (error) {
      console.warn('Export directory initialisation failed', error);
      updateExportFolderButtonLabel();
      updateExportFolderStatus(localizeText('出力フォルダ: 初期化でエラーが発生しました', 'Export folder: initialization failed'), 'error');
    }
  }

  async function initializeAutosave() {
    setupAutosaveControls();
    if (!AUTOSAVE_SUPPORTED) {
      updateAutosaveStatus('自動保存: このブラウザでは利用できません', 'warn');
      return;
    }

    updateAutosaveStatus('自動保存: 端末内データを確認中…');

    try {
      const sanitizeResult = await sanitizeRecentProjectsStore({ announce: false });
      const recentEntries = Array.isArray(sanitizeResult?.entries) ? sanitizeResult.entries : [];
      const storedProjectId = await loadStoredAutosaveProjectId();
      let targetEntry = null;
      if (storedProjectId) {
        targetEntry = recentEntries.find(entry => entry?.id === storedProjectId) || null;
      }
      if (!targetEntry) {
        targetEntry = recentEntries[0] || null;
      }
      if (targetEntry) {
        const restored = await openRecentProject(targetEntry, { hideStartup: false, silent: true });
        if (restored) {
          updateAutosaveStatus('自動保存: 前回の端末内データを復元しました', 'success');
          return;
        }
      }
      setActiveAutosaveProjectId(storedProjectId || createAutosaveProjectId());
      markAutosaveDirty();
      scheduleAutosaveSnapshot();
      updateAutosaveStatus('自動保存: 端末内へ自動保存します', 'info');
    } catch (error) {
      console.warn('Autosave initialisation failed', error);
      updateAutosaveStatus('自動保存: 初期化でエラーが発生しました', 'error');
    }
  }

  function scheduleAutosaveSnapshot({ delayMs = AUTOSAVE_WRITE_DELAY } = {}) {
    if (!AUTOSAVE_SUPPORTED) return;
    if (autosaveRestoring) return;
    const blockedStatus = getAutosaveBlockedStatusMessage();
    if (blockedStatus) {
      if (autosaveWriteTimer !== null) {
        window.clearTimeout(autosaveWriteTimer);
        autosaveWriteTimer = null;
      }
      autosaveWriteDeadline = 0;
      updateAutosaveStatus(blockedStatus, 'info');
      return;
    }
    if (!autosaveDirty) return;
    const safeDelayMs = Math.max(120, Math.round(Number(delayMs) || AUTOSAVE_WRITE_DELAY));
    const deadline = Date.now() + safeDelayMs;
    if (
      autosaveWriteTimer !== null
      && Number.isFinite(autosaveWriteDeadline)
      && autosaveWriteDeadline > 0
      && autosaveWriteDeadline <= deadline
    ) {
      return;
    }
    if (autosaveWriteTimer !== null) {
      window.clearTimeout(autosaveWriteTimer);
    }
    autosaveWriteDeadline = deadline;
    autosaveWriteTimer = window.setTimeout(() => {
      autosaveWriteTimer = null;
      autosaveWriteDeadline = 0;
      writeAutosaveSnapshot().catch(error => {
        console.warn('Autosave failed', error);
        updateAutosaveStatus('自動保存: 保存に失敗しました', 'error');
      });
    }, Math.max(0, deadline - Date.now()));
  }

  function isAutosaveInteractionBusy() {
    return Boolean(
      pointerState.active
      || pointerState.selectionMove
      || virtualCursorDrawState.active
      || floatingDrawButtonState.drawSessionStarted
    );
  }

  function markSaveInteractionActivity() {
    lastSaveInteractionAt = Date.now();
  }

  function hasRecentSaveInteraction() {
    if (!Number.isFinite(lastSaveInteractionAt) || lastSaveInteractionAt <= 0) {
      return false;
    }
    return (Date.now() - lastSaveInteractionAt) < SAVE_INTERACTION_GRACE_MS;
  }

  function hasPendingAutosaveWork() {
    if (!AUTOSAVE_SUPPORTED) {
      return false;
    }
    return Boolean(
      autosaveDirty
      || autosaveWriteQueued
      || autosaveWriteInFlight
      || autosaveWriteTimer !== null
    );
  }

  function flushAutosaveSnapshotOnLifecycle({ force = false } = {}) {
    if (!AUTOSAVE_SUPPORTED) {
      return;
    }
    if (autosaveRestoring) {
      return;
    }
    if (!hasPendingAutosaveWork()) {
      return;
    }
    const blockedStatus = getAutosaveBlockedStatusMessage();
    if (blockedStatus) {
      return;
    }
    const now = Date.now();
    if (!force && (now - autosaveLifecycleFlushAt) < AUTOSAVE_LIFECYCLE_FLUSH_THROTTLE_MS) {
      return;
    }
    autosaveLifecycleFlushAt = now;
    if (autosaveWriteTimer !== null) {
      window.clearTimeout(autosaveWriteTimer);
      autosaveWriteTimer = null;
      autosaveWriteDeadline = 0;
    }
    if (autosaveWriteInFlight) {
      autosaveWriteQueued = true;
      return;
    }
    writeAutosaveSnapshot(true).catch(error => {
      console.warn('Autosave lifecycle flush failed', error);
      updateAutosaveStatus('自動保存: 保存に失敗しました', 'error');
    });
  }

  async function waitForAutosaveWriteIdle(timeoutMs = AUTOSAVE_WRITE_DELAY * 4) {
    const safeTimeoutMs = Math.max(250, Math.round(Number(timeoutMs) || 0));
    const deadline = Date.now() + safeTimeoutMs;
    while (autosaveWriteInFlight) {
      if (Date.now() >= deadline) {
        return false;
      }
      await new Promise(resolve => window.setTimeout(resolve, 16));
    }
    return true;
  }

  async function writeAutosaveSnapshot(force = false) {
    if (!AUTOSAVE_SUPPORTED) return;
    if (autosaveRestoring) return;
    const blockedStatus = getAutosaveBlockedStatusMessage();
    if (blockedStatus) {
      if (autosaveWriteTimer !== null) {
        window.clearTimeout(autosaveWriteTimer);
        autosaveWriteTimer = null;
      }
      autosaveWriteDeadline = 0;
      autosaveWriteQueued = false;
      updateAutosaveStatus(blockedStatus, 'info');
      return false;
    }
    if (!force && !autosaveDirty) return false;
    if (autosaveWriteInFlight) {
      autosaveWriteQueued = true;
      if (!force) {
        return false;
      }
      const idle = await waitForAutosaveWriteIdle();
      if (!idle || autosaveWriteInFlight) {
        return false;
      }
    }
    if (!force && isAutosaveInteractionBusy()) {
      autosaveWriteQueued = true;
      scheduleAutosaveSnapshot();
      return false;
    }
    if (!force && hasRecentSaveInteraction()) {
      autosaveWriteQueued = true;
      scheduleAutosaveSnapshot();
      return false;
    }
    if (!tryAcquireAutosaveTabLock()) {
      autosaveWriteQueued = true;
      scheduleAutosaveSnapshot();
      if (shouldAnnounceAutosaveTabLockWait()) {
        updateAutosaveStatus(
          localizeText(
            '自動保存: 別タブが保存中のため待機しています',
            'Autosave: waiting while another tab is saving'
          ),
          'info'
        );
      }
      return false;
    }
    autosaveWriteInFlight = true;
    autosaveWriteQueued = false;
    try {
      updateAutosaveStatus('自動保存: 端末内に保存中…');
      const snapshot = makeHistorySnapshot({ clonePixelData: false });
      const session = buildAutosaveSessionPayload();
      const packaged = buildPackagedProjectPayload(snapshot, { session });
      const projectId = await ensureActiveAutosaveProjectId();
      const dirtyGenerationAtStart = autosaveDirtyGeneration;
      const unsavedTokenAtStart = unsavedChangeToken;
      const savedEntry = await recordRecentProjectSnapshot(snapshot, packaged, {
        projectId,
        thumbnailIntervalMs: AUTOSAVE_THUMBNAIL_UPDATE_INTERVAL_MS,
      });
      if (!savedEntry) {
        throw new Error('Failed to record autosave snapshot');
      }
      const stillCurrentWrite = (
        autosaveProjectId === projectId
        && autosaveDirtyGeneration === dirtyGenerationAtStart
        && unsavedChangeToken === unsavedTokenAtStart
      );
      if (!stillCurrentWrite) {
        autosaveWriteQueued = true;
        updateAutosaveStatus('自動保存: 追加変更を保存します', 'info');
        return false;
      }
      autosaveDirty = false;
      markDocumentDurablySaved();
      updateAutosaveStatus('自動保存: 端末内に保存済み', 'success');
      return true;
    } catch (error) {
      throw error;
    } finally {
      autosaveWriteInFlight = false;
      releaseAutosaveTabLock();
      if (autosaveWriteQueued || autosaveDirty) {
        autosaveWriteQueued = false;
        scheduleAutosaveSnapshot();
      }
    }
  }

  async function restoreAutosaveDocument(handle) {
    if (!ensureCurrentClientCanReplaceActiveProject({ announce: false })) {
      return false;
    }
    try {
      const file = await handle.getFile();
      if (!file) {
        return false;
      }
      const text = await file.text();
      if (!text) {
        updateAutosaveStatus('自動保存: 新しいファイルに保存します');
        return false;
      }
      const parsedDocument = snapshotFromDocumentText(text);
      const snapshot = parsedDocument?.snapshot || null;
      const projectSession = parsedDocument?.projectSession || null;
      const dotStats = parsedDocument?.dotStats || null;
      if (!snapshot) {
        updateAutosaveStatus('自動保存: ファイルを読み込めませんでした', 'error');
        return false;
      }
      if (isTinyStartupSnapshot(snapshot)) {
        updateAutosaveStatus('自動保存: 起動時の 1x1 バックアップ読み込みをスキップしました', 'warn');
        return false;
      }
      synchronizeImportedSnapshotPalette(snapshot);
      autosaveRestoring = true;
      try {
        applyHistorySnapshot(snapshot, { forcePalettePresetSync: true });
        history.pending = null;
        if (projectSession) {
          history.limit = projectSession.historyLimit;
          history.past = projectSession.historyPast;
          history.future = projectSession.historyFuture;
          if (!(timelapseState.snapshots instanceof Array)) {
            timelapseState.snapshots = [];
          }
          timelapseState.snapshots.length = 0;
          projectSession.timelapse.snapshots.forEach(entry => {
            timelapseState.snapshots.push(entry);
          });
          timelapseState.enabled = projectSession.timelapse.enabled;
          timelapseState.fps = projectSession.timelapse.fps;
          timelapseState.warningShown = projectSession.timelapse.warningShown;
          timelapseState.sampleStep = projectSession.timelapse.sampleStep;
          timelapseState.lastCaptureToken = projectSession.timelapse.lastCaptureToken;
        } else {
          history.past = [];
          history.future = [];
          clearTimelapseRecording({ silent: true });
        }
      } finally {
        autosaveRestoring = false;
      }
      syncTimelapseControls();
      updateHistoryButtons();
      autosaveDirty = false;
      resetDocumentUnsavedChanges();
      syncPixfindSnapshotAfterDocumentReset();
      updateMemoryStatus();
      setTrackedProjectDotBaseline(snapshot, dotStats);
      return true;
    } catch (error) {
      autosaveRestoring = false;
      console.warn('Failed to restore autosave document', error);
      updateAutosaveStatus('自動保存: ファイルを読み込めませんでした', 'error');
      return false;
    }
  }

  async function getFileHandleInExportDirectory(filename, { create = true, requestPermission = false } = {}) {
    if (!exportDirectoryHandle || typeof exportDirectoryHandle.getFileHandle !== 'function') {
      return null;
    }
    const granted = await ensureHandlePermission(exportDirectoryHandle, { request: requestPermission });
    if (!granted) {
      if (requestPermission) {
        schedulePendingExportDirectoryPermission(exportDirectoryHandle);
      }
      return null;
    }
    try {
      return await exportDirectoryHandle.getFileHandle(filename, { create: Boolean(create) });
    } catch (error) {
      console.warn('Failed to create/open file in export directory', error);
      return null;
    }
  }

  async function requestAutosaveBinding(options = {}) {
    if (!FILE_HANDLE_AUTOSAVE_SUPPORTED) return;
    try {
      const suggestedNameOption = typeof options.suggestedName === 'string' ? options.suggestedName.trim() : '';
      const suggestedName = suggestedNameOption || createAutosaveFileName();
      let handle = await getFileHandleInExportDirectory(suggestedName, {
        create: true,
        requestPermission: true,
      });
      let boundFromExportDirectory = Boolean(handle);
      if (!handle && EXPORT_DIRECTORY_SUPPORTED && typeof window.showDirectoryPicker === 'function' && !exportDirectorySetupDismissed) {
        const bound = await requestExportDirectoryBinding();
        if (bound) {
          handle = await getFileHandleInExportDirectory(suggestedName, {
            create: true,
            requestPermission: true,
          });
          boundFromExportDirectory = Boolean(handle);
        }
      }
      if (!handle) {
        handle = await window.showSaveFilePicker({
          suggestedName,
          types: [
            {
              description: 'PiXiEEDraw ドキュメント',
              accept: {
                'application/json': ['.json', '.pxdraw', '.pixieedraw'],
                'application/x-pixieedraw': ['.pixieedraw'],
              },
            },
          ],
        });
        boundFromExportDirectory = false;
      }
      const granted = await ensureHandlePermission(handle, { request: true });
      if (!granted) {
        updateAutosaveStatus('自動保存: 権限が必要です', 'warn');
        return;
      }
      autosaveHandle = handle;
      pendingAutosaveHandle = null;
      clearPendingPermissionListener();
      await storeAutosaveHandle(handle);
      if (dom.controls.enableAutosave) {
        dom.controls.enableAutosave.textContent = 'ローカル自動保存（常時ON）';
      }
      updateAutosaveStatus(
        boundFromExportDirectory
          ? `自動保存: ${EXPORT_WORKSPACE_DIR_NAME} フォルダ内に保存中…`
          : '自動保存: 保存中…'
      );
      markAutosaveDirty();
      await writeAutosaveSnapshot(true);
    } catch (error) {
      if (error && error.name === 'AbortError') {
        updateAutosaveStatus('自動保存: キャンセルしました', 'warn');
        return;
      }
      console.warn('Autosave binding failed', error);
      updateAutosaveStatus('自動保存: ファイルを選択できませんでした', 'error');
    }
  }

  async function ensureAutosaveForLensImport() {
    if (!AUTOSAVE_SUPPORTED) {
      return;
    }
    if (!autosaveProjectId) {
      setActiveAutosaveProjectId(createAutosaveProjectId());
    }
    markAutosaveDirty();
    scheduleAutosaveSnapshot();
    updateAutosaveStatus('PiXiEELENS の取り込み内容を端末内に自動保存します', 'info');
  }

  async function ensureHandlePermission(handle, { request = false } = {}) {
    if (!handle) return false;
    const opts = { mode: 'readwrite' };
    const canQuery = typeof handle.queryPermission === 'function';
    const canRequest = typeof handle.requestPermission === 'function';

    if (!canQuery) {
      if (!request || !canRequest) {
        return false;
      }
      const outcome = await handle.requestPermission(opts);
      return outcome === 'granted';
    }

    let permission = await handle.queryPermission(opts);
    if (permission === 'granted') {
      return true;
    }
    if (!request || !canRequest) {
      return false;
    }
    permission = await handle.requestPermission(opts);
    return permission === 'granted';
  }

  function schedulePendingAutosavePermission(handle) {
    pendingAutosaveHandle = handle;
    autosaveHandle = null;
    clearPendingPermissionListener();
    updateAutosaveStatus('自動保存: 権限が必要です。キャンバスをクリックして再許可してください', 'warn');
    if (dom.controls.enableAutosave) {
      dom.controls.enableAutosave.textContent = 'ローカル自動保存（常時ON）';
    }
    const listener = (event) => {
      const target = event?.target instanceof Element ? event.target : null;
      if (!target) {
        return;
      }
      const isEditable = Boolean(target.closest('input, textarea, select, [contenteditable="true"], [contenteditable=""]'));
      if (isEditable) {
        return;
      }
      const isAutosaveButton = Boolean(
        dom.controls.enableAutosave
          && (target === dom.controls.enableAutosave || target.closest('#enableAutosave') === dom.controls.enableAutosave)
      );
      const isCanvasTap = Boolean(
        (dom.canvasViewport && dom.canvasViewport.contains(target))
          || isCanvasSurfaceTarget(target)
      );
      if (!isAutosaveButton && !isCanvasTap) {
        return;
      }
      clearPendingPermissionListener();
      attemptAutosaveReauthorization().catch(error => {
        console.warn('Autosave reauthorization failed', error);
        updateAutosaveStatus('自動保存: 権限を付与できませんでした', 'error');
      });
    };
    autosavePermissionListener = listener;
    window.addEventListener('pointerdown', listener, true);
  }

  function clearPendingPermissionListener() {
    if (!autosavePermissionListener) return;
    window.removeEventListener('pointerdown', autosavePermissionListener, true);
    autosavePermissionListener = null;
  }

  // -------------------------------------------------------------------------
  // iOS IndexedDB snapshot fallback
  // -------------------------------------------------------------------------

  function upgradeIosSnapshotDatabase(db) {
    if (!db) return;
    if (!db.objectStoreNames.contains(IOS_SNAPSHOT_STORE_NAME)) {
      db.createObjectStore(IOS_SNAPSHOT_STORE_NAME, { keyPath: 'id' });
    }
  }

  function ensureIosSnapshotDatabase() {
    if (!IOS_SNAPSHOT_SUPPORTED) {
      return Promise.resolve(null);
    }
    if (iosSnapshotDbPromise) {
      return iosSnapshotDbPromise;
    }
    iosSnapshotDbPromise = new Promise((resolve, reject) => {
      let settled = false;
      const resolveOnce = (value) => {
        if (settled) {
          return;
        }
        settled = true;
        resolve(value);
      };
      const rejectOnce = (error) => {
        if (settled) {
          return;
        }
        settled = true;
        reject(error);
      };
      const request = window.indexedDB.open(IOS_SNAPSHOT_DB_NAME, IOS_SNAPSHOT_DB_VERSION);
      request.onupgradeneeded = event => {
        const database = event.target.result;
        upgradeIosSnapshotDatabase(database);
      };
      request.onsuccess = () => {
        const database = request.result;
        if (database) {
          database.onversionchange = () => {
            database.close();
          };
        }
        resolveOnce(database);
      };
      request.onerror = () => {
        rejectOnce(request.error || new Error('Failed to open iOS snapshot database'));
      };
      request.onblocked = () => {
        rejectOnce(new Error('iOS snapshot database is blocked by another tab'));
      };
    })
      .catch(error => {
        console.warn('Failed to initialise iOS snapshot database', error);
        if (
          error
          && /blocked/i.test(String(error?.message || ''))
          && (Date.now() - iosSnapshotBlockedNoticeAt) > 3000
        ) {
          iosSnapshotBlockedNoticeAt = Date.now();
          updateAutosaveStatus(
            localizeText(
              'iOS復元: 別タブで同時に開かれているため一時保存を保留しています',
              'iOS restore: snapshot save is paused because another tab is open'
            ),
            'warn'
          );
        }
        iosSnapshotDbPromise = null;
        return null;
      });
    return iosSnapshotDbPromise;
  }

  function bindIosSnapshotUnloadListener() {
    if (!IOS_SNAPSHOT_SUPPORTED) return;
    if (iosSnapshotUnloadListenerBound) return;
    const flush = () => {
      persistIosSnapshot(true).catch(() => {
        // Ignore unload persistence failures
      });
    };
    window.addEventListener('beforeunload', flush);
    window.addEventListener('pagehide', flush);
    iosSnapshotUnloadListenerBound = true;
  }

  function scheduleIosSnapshotPersist() {
    if (!IOS_SNAPSHOT_SUPPORTED) return;
    if (iosSnapshotRestoring) return;
    iosSnapshotDirty = true;
    if (iosSnapshotTimer !== null) {
      return;
    }
    iosSnapshotTimer = window.setTimeout(() => {
      iosSnapshotTimer = null;
      const shouldWrite = iosSnapshotDirty;
      iosSnapshotDirty = false;
      if (!shouldWrite) return;
      persistIosSnapshot().catch(error => {
        console.warn('Failed to persist iOS snapshot', error);
      });
    }, IOS_SNAPSHOT_WRITE_DELAY);
  }

  async function persistIosSnapshot(force = false) {
    if (!IOS_SNAPSHOT_SUPPORTED) return;
    if (iosSnapshotRestoring) return;
    if (!force && !iosSnapshotDirty) return;
    const database = await ensureIosSnapshotDatabase();
    if (!database) {
      return;
    }
    iosSnapshotDirty = false;
    let snapshotText = '';
    try {
      const snapshot = makeHistorySnapshot();
      const payload = serializeDocumentSnapshot(snapshot);
      snapshotText = JSON.stringify({
        version: DOCUMENT_FILE_VERSION,
        snapshot: payload,
      });
    } catch (error) {
      console.warn('Failed to create iOS snapshot payload', error);
      return;
    }
    let data = snapshotText;
    let compressed = false;
    if (snapshotText.length > IOS_SNAPSHOT_COMPRESSION_THRESHOLD) {
      try {
        data = textCompression.compressToUTF16(snapshotText);
        if (typeof data === 'string' && data.length) {
          compressed = true;
        } else {
          data = snapshotText;
        }
      } catch (error) {
        console.warn('Failed to compress iOS snapshot payload', error);
        data = snapshotText;
      }
    }
    await new Promise((resolve, reject) => {
      try {
        const transaction = database.transaction(IOS_SNAPSHOT_STORE_NAME, 'readwrite');
        transaction.oncomplete = () => resolve();
        transaction.onabort = () => reject(transaction.error || new Error('iOS snapshot transaction aborted'));
        transaction.onerror = () => reject(transaction.error || new Error('iOS snapshot transaction error'));
        const store = transaction.objectStore(IOS_SNAPSHOT_STORE_NAME);
        store.put({
          id: IOS_SNAPSHOT_KEY,
          data,
          compressed,
          savedAt: Date.now(),
          size: snapshotText.length,
        });
      } catch (error) {
        reject(error);
      }
    }).catch(error => {
      iosSnapshotDirty = true;
      throw error;
    });
  }

  async function restoreIosSnapshotFallback() {
    if (!IOS_SNAPSHOT_SUPPORTED) return false;
    const database = await ensureIosSnapshotDatabase();
    if (!database) {
      return false;
    }
    const record = await new Promise((resolve, reject) => {
      try {
        const transaction = database.transaction(IOS_SNAPSHOT_STORE_NAME, 'readonly');
        transaction.oncomplete = () => {};
        transaction.onabort = () => reject(transaction.error || new Error('iOS snapshot read aborted'));
        transaction.onerror = () => reject(transaction.error || new Error('iOS snapshot read error'));
        const store = transaction.objectStore(IOS_SNAPSHOT_STORE_NAME);
        const request = store.get(IOS_SNAPSHOT_KEY);
        request.onsuccess = () => resolve(request.result || null);
        request.onerror = () => reject(request.error || new Error('iOS snapshot get failed'));
      } catch (error) {
        reject(error);
      }
    }).catch(error => {
      console.warn('Failed to read iOS snapshot', error);
      return null;
    });
    if (!record || !record.data) {
      return false;
    }
    let snapshotText = '';
    if (record.compressed) {
      try {
        snapshotText = textCompression.decompressFromUTF16(record.data) || '';
      } catch (error) {
        console.warn('Failed to decompress iOS snapshot payload', error);
        snapshotText = '';
      }
    } else if (typeof record.data === 'string') {
      snapshotText = record.data;
    }
    if (!snapshotText) {
      return false;
    }
    let payload;
    try {
      const parsed = JSON.parse(snapshotText);
      payload = parsed && typeof parsed === 'object' && parsed.snapshot ? parsed.snapshot : parsed;
    } catch (error) {
      console.warn('Failed to parse iOS snapshot payload', error);
      return false;
    }
    let snapshot;
    try {
      snapshot = deserializeDocumentPayload(payload);
    } catch (error) {
      console.warn('Failed to deserialize iOS snapshot', error);
      return false;
    }
    if (isTinyStartupSnapshot(snapshot)) {
      return false;
    }
    synchronizeImportedSnapshotPalette(snapshot);
    iosSnapshotRestoring = true;
    try {
      const prevFrameCount = Array.isArray(state.frames) ? state.frames.length : 0;
      applyHistorySnapshot(snapshot, { forcePalettePresetSync: true });
      history.past = [];
      history.future = [];
      history.pending = null;
      clearTimelapseRecording({ silent: true });
      resetDocumentUnsavedChanges();
      updateMemoryStatus();
      setTrackedProjectDotBaseline(snapshot, null);
    } finally {
      iosSnapshotRestoring = false;
    }
    return true;
  }

  async function initializeIosSnapshotFallback() {
    if (!IOS_SNAPSHOT_SUPPORTED) return;
    if (iosSnapshotInitialized) return;
    iosSnapshotInitialized = true;
    try {
      const restored = await restoreIosSnapshotFallback();
      if (restored) {
        console.info('Restored canvas from iOS IndexedDB snapshot');
      }
    } catch (error) {
      console.warn('Failed to restore iOS snapshot', error);
    }
    bindIosSnapshotUnloadListener();
  }

  async function attemptAutosaveReauthorization() {
    if (!pendingAutosaveHandle) {
      return false;
    }
    const handle = pendingAutosaveHandle;
    clearPendingPermissionListener();
    const granted = await ensureHandlePermission(handle, { request: true });
    if (!granted) {
      updateAutosaveStatus('自動保存: 権限が必要です。右のボタンから再許可してください', 'warn');
      schedulePendingAutosavePermission(handle);
      return false;
    }
    pendingAutosaveHandle = null;
    autosaveHandle = handle;
    if (dom.controls.enableAutosave) {
      dom.controls.enableAutosave.textContent = 'ローカル自動保存（常時ON）';
    }
    try {
      const restored = await restoreAutosaveDocument(handle);
      if (restored) {
        updateAutosaveStatus('自動保存: 端末内データを読み込みました', 'success');
      } else {
        updateAutosaveStatus('自動保存: 端末内へ自動保存します', 'info');
      }
    } catch (error) {
      console.warn('Autosave restore after reauthorization failed', error);
      updateAutosaveStatus('自動保存: 既存バックアップの読み込みに失敗しました', 'error');
    }
    return true;
  }

  async function openDocumentsAsProjectTabs(items, loader, { source = 'open' } = {}) {
    if (!ensureCurrentClientCanReplaceActiveProject()) {
      return false;
    }
    if (openProjectTabBusy) {
      return false;
    }
    const queue = Array.isArray(items) ? items.filter(Boolean) : [];
    if (!queue.length || typeof loader !== 'function') {
      return false;
    }
    ensureOpenProjectTabsInitialized();
    const availableSlots = Math.max(0, MAX_OPEN_PROJECT_TABS - openProjectTabs.length);
    if (availableSlots <= 0) {
      updateAutosaveStatus(
        localizeText(
          `同時に開けるプロジェクトは最大 ${MAX_OPEN_PROJECT_TABS} 件です`,
          `You can open up to ${MAX_OPEN_PROJECT_TABS} projects at once`
        ),
        'warn'
      );
      return false;
    }
    openProjectTabBusy = true;
    try {
      const targets = queue.slice(0, availableSlots);
      const truncatedCount = Math.max(0, queue.length - targets.length);
      await persistActiveOpenProjectTab({ flushAutosave: true });
      let openedCount = 0;
      let failedCount = 0;
      for (let index = 0; index < targets.length; index += 1) {
        const item = targets[index];
        try {
          const loaded = await loader(item);
          if (!loaded) {
            failedCount += 1;
            continue;
          }
          const appended = appendOpenProjectTabFromCurrentState({
            activate: true,
            source,
          });
          if (!appended) {
            failedCount += 1;
            break;
          }
          openedCount += 1;
        } catch (error) {
          console.warn('Failed to open project as tab', error);
          failedCount += 1;
        }
      }
      if (!openedCount) {
        if (truncatedCount > 0 || failedCount > 0) {
          updateAutosaveStatus(
            localizeText(
              `複数読み込みに失敗しました（失敗 ${failedCount} / 上限で未追加 ${truncatedCount}）`,
              `Failed to open projects (failed ${failedCount} / skipped by limit ${truncatedCount})`
            ),
            'warn'
          );
        }
        return false;
      }
      const summaryJa = `複数読み込み: 開いた ${openedCount}件`
        + (failedCount > 0 ? ` / 失敗 ${failedCount}件` : '')
        + (truncatedCount > 0 ? ` / 上限で未追加 ${truncatedCount}件（最大${MAX_OPEN_PROJECT_TABS}）` : '');
      const summaryEn = `Opened ${openedCount} project tab(s)`
        + (failedCount > 0 ? ` / Failed ${failedCount}` : '')
        + (truncatedCount > 0 ? ` / Skipped by limit ${truncatedCount} (max ${MAX_OPEN_PROJECT_TABS})` : '');
      updateAutosaveStatus(
        localizeText(summaryJa, summaryEn),
        (failedCount > 0 || truncatedCount > 0) ? 'warn' : 'success'
      );
      renderOpenProjectTabs();
      return true;
    } finally {
      openProjectTabBusy = false;
    }
  }

  async function openRecentProjectAsTab(entry, { hideStartup = true } = {}) {
    if (!entry || typeof entry !== 'object') {
      return false;
    }
    if (!ensureCurrentClientCanReplaceActiveProject()) {
      return false;
    }
    const projectId = normalizeAutosaveProjectId(entry.id || '');
    if (openProjectTabBusy) {
      return false;
    }
    ensureOpenProjectTabsInitialized();
    const existingIndex = projectId ? findOpenProjectTabIndexByProjectId(projectId) : -1;
    if (existingIndex >= 0) {
      const existingTab = openProjectTabs[existingIndex];
      const switched = await activateOpenProjectTab(existingTab?.id || '');
      if (switched && hideStartup) {
        hideStartupScreen();
      }
      return switched;
    }
    if (openProjectTabs.length >= MAX_OPEN_PROJECT_TABS) {
      updateAutosaveStatus(
        localizeText(
          `同時に開けるプロジェクトは最大 ${MAX_OPEN_PROJECT_TABS} 件です`,
          `You can open up to ${MAX_OPEN_PROJECT_TABS} projects at once`
        ),
        'warn'
      );
      return false;
    }
    openProjectTabBusy = true;
    try {
      await persistActiveOpenProjectTab({ flushAutosave: true });
      const loaded = await openRecentProject(entry, {
        hideStartup: false,
        silent: true,
      });
      if (!loaded) {
        return false;
      }
      const appended = appendOpenProjectTabFromCurrentState({
        activate: true,
        source: 'local-recent',
        projectId: projectId || autosaveProjectId,
      });
      if (!appended) {
        return false;
      }
      if (hideStartup) {
        hideStartupScreen();
      }
      updateAutosaveStatus('自動保存: 端末内プロジェクトを開きました', 'success');
      return true;
    } finally {
      openProjectTabBusy = false;
    }
  }

  async function openDocumentDialog() {
    if (!ensureCurrentClientCanReplaceActiveProject()) {
      return false;
    }
    if (!canCurrentClientImportExternalData()) {
      setMultiStatus(localizeText('参加/視聴モードでは読み込み/インポートはマスターのみ操作できます', 'In participant/viewer mode, only the master can open/import files'), 'warn');
      return false;
    }
    if (typeof window.showOpenFilePicker === 'function') {
      try {
        const handles = await window.showOpenFilePicker({
          multiple: true,
          excludeAcceptAllOption: false,
          types: [
            {
              description: '対応ファイル (PiXiEEDraw / PNG / GIF)',
              accept: {
                'application/json': ['.json', '.pxdraw', '.pixieedraw'],
                'application/x-pixieedraw': ['.pixieedraw'],
                'image/png': ['.png'],
                'image/gif': ['.gif'],
              },
            },
          ],
        });
        if (!Array.isArray(handles) || !handles.length) {
          return false;
        }
        return await openDocumentsAsProjectTabs(
          handles,
          async handle => loadDocumentFromHandle(handle, { suppressAutosaveStatus: true }),
          { source: 'open-picker' }
        );
      } catch (error) {
        if (error && error.name === 'AbortError') {
          return false;
        }
        console.warn('Document open failed', error);
        const message = error?.source === 'image-import'
          ? '画像の読み込みに失敗しました'
          : 'ドキュメントを開けませんでした';
        updateAutosaveStatus(message, 'error');
        return false;
      }
    }
    return openDocumentViaInput();
  }

  function openDocumentViaInput() {
    return new Promise(resolve => {
      const input = document.createElement('input');
      input.type = 'file';
      input.multiple = true;
      const acceptTypes = [
        '.json',
        '.pxdraw',
        '.pixieedraw',
        '.png',
        '.gif',
        'application/json',
        'application/x-pixieedraw',
        'image/png',
        'image/gif',
      ];
      if (IS_IOS_DEVICE) {
        acceptTypes.push('.txt', 'text/plain');
      }
      input.accept = acceptTypes.join(',');
      input.style.display = 'none';
      let settled = false;
      const finish = success => {
        if (settled) return;
        settled = true;
        resolve(Boolean(success));
      };
      const cleanup = () => {
        input.value = '';
        input.remove();
      };
      input.addEventListener('change', async () => {
        const files = Array.from(input.files || []);
        cleanup();
        if (!files.length) {
          finish(false);
          return;
        }
        try {
          const opened = await openDocumentsAsProjectTabs(
            files,
            async file => {
              if (isImportableImageFile(file)) {
                return await loadDocumentFromImageFile(file);
              }
              const text = await file.text();
              return await loadDocumentFromText(text, null, { suppressAutosaveStatus: true });
            },
            { source: 'open-input' }
          );
          finish(opened);
        } catch (error) {
          console.warn('Document load failed', error);
          updateAutosaveStatus('ドキュメントを開けませんでした', 'error');
          finish(false);
        }
      });
      input.addEventListener('cancel', () => {
        cleanup();
        finish(false);
      });
      input.addEventListener('click', () => {
        input.value = '';
      });
      document.body.appendChild(input);
      input.click();
    });
  }

  function isGifFile(file) {
    if (!file) return false;
    const type = typeof file.type === 'string' ? file.type.toLowerCase() : '';
    if (type === 'image/gif') {
      return true;
    }
    const name = typeof file.name === 'string' ? file.name.toLowerCase() : '';
    return name.endsWith('.gif');
  }

  function isImportableImageFile(file) {
    if (!file) return false;
    const type = typeof file.type === 'string' ? file.type.toLowerCase() : '';
    if (type === 'image/png' || type === 'image/gif') {
      return true;
    }
    const name = typeof file.name === 'string' ? file.name.toLowerCase() : '';
    return name.endsWith('.png') || name.endsWith('.gif');
  }

  function createImageImportError(message, cause) {
    const error = new Error(message);
    error.source = 'image-import';
    if (cause) {
      error.cause = cause;
    }
    return error;
  }

  function normalizeImportFrameDuration(durationMs) {
    const numeric = Number(durationMs);
    if (!Number.isFinite(numeric) || numeric <= 0) {
      return DEFAULT_IMPORT_FRAME_DURATION;
    }
    return clamp(Math.round(numeric), IMPORT_FRAME_DURATION_MIN_MS, IMPORT_FRAME_DURATION_MAX_MS);
  }

  function resolveImageImportTargetSize(width, height, { integerScaleFactor = 1 } = {}) {
    const sourceWidth = Math.max(1, Math.floor(Number(width) || 0));
    const sourceHeight = Math.max(1, Math.floor(Number(height) || 0));
    if (!sourceWidth || !sourceHeight) {
      throw createImageImportError('画像サイズが不正です');
    }
    if (sourceWidth > MAX_IMAGE_IMPORT_SOURCE_SIZE || sourceHeight > MAX_IMAGE_IMPORT_SOURCE_SIZE) {
      throw createImageImportError(`読み込み元画像は最大 ${MAX_IMAGE_IMPORT_SOURCE_SIZE}px までです`);
    }
    const normalizedScaleFactor = Math.max(1, Math.floor(Number(integerScaleFactor) || 1));
    const autoIntegerScaled = normalizedScaleFactor > 1
      && sourceWidth % normalizedScaleFactor === 0
      && sourceHeight % normalizedScaleFactor === 0;
    const effectiveSourceWidth = autoIntegerScaled
      ? Math.max(1, Math.floor(sourceWidth / normalizedScaleFactor))
      : sourceWidth;
    const effectiveSourceHeight = autoIntegerScaled
      ? Math.max(1, Math.floor(sourceHeight / normalizedScaleFactor))
      : sourceHeight;
    if (effectiveSourceWidth <= MAX_CANVAS_SIZE && effectiveSourceHeight <= MAX_CANVAS_SIZE) {
      return {
        sourceWidth,
        sourceHeight,
        width: effectiveSourceWidth,
        height: effectiveSourceHeight,
        scaled: autoIntegerScaled,
        integerScaleFactor: autoIntegerScaled ? normalizedScaleFactor : 1,
      };
    }
    const ratio = Math.min(MAX_CANVAS_SIZE / effectiveSourceWidth, MAX_CANVAS_SIZE / effectiveSourceHeight);
    const widthScaled = clamp(Math.floor(effectiveSourceWidth * ratio), 1, MAX_CANVAS_SIZE);
    const heightScaled = clamp(Math.floor(effectiveSourceHeight * ratio), 1, MAX_CANVAS_SIZE);
    return {
      sourceWidth,
      sourceHeight,
      width: widthScaled,
      height: heightScaled,
      scaled: widthScaled !== sourceWidth
        || heightScaled !== sourceHeight
        || autoIntegerScaled,
      integerScaleFactor: autoIntegerScaled ? normalizedScaleFactor : 1,
    };
  }

  function getImageImportCheckFrameIndexes(frameCount) {
    const total = Math.max(0, Math.floor(Number(frameCount) || 0));
    if (total <= 0) {
      return [];
    }
    if (total === 1) {
      return [0];
    }
    const indexes = [0, Math.floor((total - 1) / 2), total - 1];
    const seen = new Set();
    const output = [];
    for (let i = 0; i < indexes.length; i += 1) {
      const index = indexes[i];
      if (seen.has(index)) {
        continue;
      }
      seen.add(index);
      output.push(index);
    }
    return output;
  }

  function getGreatestCommonDivisor(a, b) {
    let x = Math.abs(Math.floor(Number(a) || 0));
    let y = Math.abs(Math.floor(Number(b) || 0));
    if (!x || !y) {
      return 0;
    }
    while (y !== 0) {
      const next = x % y;
      x = y;
      y = next;
    }
    return x;
  }

  function quickCheckImageDataNearestUpscale(imageData, factor) {
    if (!imageData || !(imageData.data instanceof Uint8ClampedArray)) {
      return false;
    }
    const width = Math.max(1, Math.floor(Number(imageData.width) || 0));
    const height = Math.max(1, Math.floor(Number(imageData.height) || 0));
    const scale = Math.max(1, Math.floor(Number(factor) || 1));
    if (scale <= 1 || width % scale !== 0 || height % scale !== 0) {
      return false;
    }
    const data = imageData.data;
    const sampleCols = Math.max(1, Math.min(IMPORT_INTEGER_SCALE_SAMPLE_GRID, Math.floor(width / scale)));
    const sampleRows = Math.max(1, Math.min(IMPORT_INTEGER_SCALE_SAMPLE_GRID, Math.floor(height / scale)));
    const stepX = width / sampleCols;
    const stepY = height / sampleRows;
    for (let row = 0; row < sampleRows; row += 1) {
      const sampleY = Math.min(height - 1, Math.floor((row + 0.5) * stepY));
      const blockY = Math.floor(sampleY / scale) * scale;
      for (let col = 0; col < sampleCols; col += 1) {
        const sampleX = Math.min(width - 1, Math.floor((col + 0.5) * stepX));
        const blockX = Math.floor(sampleX / scale) * scale;
        const sampleBase = (sampleY * width + sampleX) * 4;
        const blockBase = (blockY * width + blockX) * 4;
        if (
          data[sampleBase] !== data[blockBase]
          || data[sampleBase + 1] !== data[blockBase + 1]
          || data[sampleBase + 2] !== data[blockBase + 2]
          || data[sampleBase + 3] !== data[blockBase + 3]
        ) {
          return false;
        }
      }
    }
    return true;
  }

  function isImageDataNearestNeighborUpscaled(imageData, factor) {
    if (!imageData || !(imageData.data instanceof Uint8ClampedArray)) {
      return false;
    }
    const width = Math.max(1, Math.floor(Number(imageData.width) || 0));
    const height = Math.max(1, Math.floor(Number(imageData.height) || 0));
    const scale = Math.max(1, Math.floor(Number(factor) || 1));
    if (scale <= 1 || width % scale !== 0 || height % scale !== 0) {
      return false;
    }
    const data = imageData.data;
    let hasInterBlockDifference = false;
    const stride = width * 4;
    for (let blockY = 0; blockY < height; blockY += scale) {
      for (let blockX = 0; blockX < width; blockX += scale) {
        const blockBase = (blockY * width + blockX) * 4;
        const r = data[blockBase];
        const g = data[blockBase + 1];
        const b = data[blockBase + 2];
        const a = data[blockBase + 3];
        if (!hasInterBlockDifference) {
          if (blockX >= scale) {
            const leftBase = blockBase - (scale * 4);
            if (
              data[leftBase] !== r
              || data[leftBase + 1] !== g
              || data[leftBase + 2] !== b
              || data[leftBase + 3] !== a
            ) {
              hasInterBlockDifference = true;
            }
          }
          if (!hasInterBlockDifference && blockY >= scale) {
            const topBase = blockBase - (scale * stride);
            if (
              data[topBase] !== r
              || data[topBase + 1] !== g
              || data[topBase + 2] !== b
              || data[topBase + 3] !== a
            ) {
              hasInterBlockDifference = true;
            }
          }
        }
        for (let localY = 0; localY < scale; localY += 1) {
          let pixelBase = ((blockY + localY) * width + blockX) * 4;
          for (let localX = 0; localX < scale; localX += 1) {
            if (
              data[pixelBase] !== r
              || data[pixelBase + 1] !== g
              || data[pixelBase + 2] !== b
              || data[pixelBase + 3] !== a
            ) {
              return false;
            }
            pixelBase += 4;
          }
        }
      }
    }
    return hasInterBlockDifference;
  }

  function detectNearestNeighborIntegerScaleForFrames(frames, width, height) {
    if (!Array.isArray(frames) || !frames.length) {
      return 1;
    }
    const sourceWidth = Math.max(1, Math.floor(Number(width) || 0));
    const sourceHeight = Math.max(1, Math.floor(Number(height) || 0));
    const gcd = getGreatestCommonDivisor(sourceWidth, sourceHeight);
    if (gcd < 2) {
      return 1;
    }
    const frameIndexes = getImageImportCheckFrameIndexes(frames.length);
    if (!frameIndexes.length) {
      return 1;
    }
    for (let factor = gcd; factor >= 2; factor -= 1) {
      if (gcd % factor !== 0) {
        continue;
      }
      let quickValid = true;
      for (let i = 0; i < frameIndexes.length; i += 1) {
        const frameInfo = frames[frameIndexes[i]];
        const imageData = frameInfo?.imageData;
        if (!quickCheckImageDataNearestUpscale(imageData, factor)) {
          quickValid = false;
          break;
        }
      }
      if (!quickValid) {
        continue;
      }
      let fullValid = true;
      for (let i = 0; i < frameIndexes.length; i += 1) {
        const frameInfo = frames[frameIndexes[i]];
        const imageData = frameInfo?.imageData;
        if (!isImageDataNearestNeighborUpscaled(imageData, factor)) {
          fullValid = false;
          break;
        }
      }
      if (fullValid) {
        return factor;
      }
    }
    return 1;
  }

  function createImageDataFromPixels(pixels, width, height) {
    if (typeof ImageData === 'function') {
      try {
        return new ImageData(pixels, width, height);
      } catch (error) {
        // Fall through to canvas-based creation.
      }
    }
    const canvas = document.createElement('canvas');
    canvas.width = width;
    canvas.height = height;
    const ctx2d = canvas.getContext('2d');
    if (!ctx2d || typeof ctx2d.createImageData !== 'function') {
      throw createImageImportError('画像を処理できませんでした');
    }
    const imageData = ctx2d.createImageData(width, height);
    imageData.data.set(pixels);
    return imageData;
  }

  function resizeImageDataNearest(imageData, targetWidth, targetHeight) {
    if (!imageData || !Number.isFinite(imageData.width) || !Number.isFinite(imageData.height)) {
      throw createImageImportError('画像を処理できませんでした');
    }
    const sourceWidth = Math.max(1, Math.floor(imageData.width));
    const sourceHeight = Math.max(1, Math.floor(imageData.height));
    const width = Math.max(1, Math.floor(targetWidth));
    const height = Math.max(1, Math.floor(targetHeight));
    if (sourceWidth === width && sourceHeight === height) {
      return imageData;
    }
    const source = imageData.data instanceof Uint8ClampedArray ? imageData.data : null;
    if (!source || source.length < sourceWidth * sourceHeight * 4) {
      throw createImageImportError('画像を処理できませんでした');
    }
    const output = new Uint8ClampedArray(width * height * 4);
    for (let y = 0; y < height; y += 1) {
      const srcY = Math.min(sourceHeight - 1, Math.floor(y * sourceHeight / height));
      const srcRow = srcY * sourceWidth;
      const dstRow = y * width;
      for (let x = 0; x < width; x += 1) {
        const srcX = Math.min(sourceWidth - 1, Math.floor(x * sourceWidth / width));
        const srcBase = (srcRow + srcX) * 4;
        const dstBase = (dstRow + x) * 4;
        output[dstBase] = source[srcBase];
        output[dstBase + 1] = source[srcBase + 1];
        output[dstBase + 2] = source[srcBase + 2];
        output[dstBase + 3] = source[srcBase + 3];
      }
    }
    return createImageDataFromPixels(output, width, height);
  }

  function resizeImportFrames(frames, targetWidth, targetHeight) {
    if (!Array.isArray(frames) || !frames.length) {
      return [];
    }
    return frames.map((frameInfo) => {
      const imageData = frameInfo?.imageData;
      if (!imageData || !Number.isFinite(imageData.width) || !Number.isFinite(imageData.height)) {
        return {
          ...frameInfo,
          imageData: null,
        };
      }
      const resized = resizeImageDataNearest(imageData, targetWidth, targetHeight);
      return {
        ...frameInfo,
        imageData: resized,
      };
    });
  }

  function buildIndexedPaletteFromFrameDataList(frameDataList, maxColors = MAX_IMPORTED_PALETTE_COLORS) {
    const frames = Array.isArray(frameDataList) ? frameDataList : [];
    const normalizedMaxColors = clamp(
      Math.round(Number(maxColors) || MAX_IMPORTED_PALETTE_COLORS),
      1,
      MAX_IMPORTED_PALETTE_COLORS
    );
    const orderedColors = [];
    const colorCounts = new Map();
    for (let frameIndex = 0; frameIndex < frames.length; frameIndex += 1) {
      const data = frames[frameIndex];
      if (!(data instanceof Uint8ClampedArray)) {
        continue;
      }
      const pixelCount = Math.floor(data.length / 4);
      for (let i = 0; i < pixelCount; i += 1) {
        const base = i * 4;
        const a = data[base + 3];
        if (a === 0) {
          continue;
        }
        const r = data[base];
        const g = data[base + 1];
        const b = data[base + 2];
        const key = `${r},${g},${b},${a}`;
        const existing = colorCounts.get(key);
        if (existing) {
          existing.count += 1;
        } else {
          const entry = { r, g, b, a, count: 1 };
          colorCounts.set(key, entry);
          orderedColors.push(entry);
        }
      }
    }
    const sourceColorCount = orderedColors.length;
    let palette = sourceColorCount <= normalizedMaxColors
      ? orderedColors.map(color => normalizeColorValue(color))
      : quantizeRgbaColors(orderedColors, normalizedMaxColors);
    if (!palette.length) {
      palette = [{ r: 0, g: 0, b: 0, a: 0 }];
    }
    const dedupedPalette = [];
    const dedupedLookup = new Map();
    palette.forEach((color) => {
      const normalized = normalizeColorValue(color);
      const key = getPaletteColorKey(normalized);
      if (!dedupedLookup.has(key)) {
        dedupedLookup.set(key, dedupedPalette.length);
        dedupedPalette.push(normalized);
      }
    });
    palette = dedupedPalette.length ? dedupedPalette : [{ r: 0, g: 0, b: 0, a: 0 }];
    const colorMap = new Map();
    orderedColors.forEach((entry) => {
      const key = getPaletteColorKey(entry);
      const exactIndex = dedupedLookup.get(key);
      if (Number.isInteger(exactIndex) && exactIndex >= 0) {
        colorMap.set(key, exactIndex);
        return;
      }
      colorMap.set(key, findNearestPaletteColorIndexByRgba(entry, palette, 0));
    });

    const frameIndices = frames.map((data) => {
      if (!(data instanceof Uint8ClampedArray)) {
        return new Int16Array(0);
      }
      const pixelCount = Math.floor(data.length / 4);
      const indices = new Int16Array(pixelCount).fill(-1);
      for (let i = 0; i < pixelCount; i += 1) {
        const base = i * 4;
        const a = data[base + 3];
        if (a === 0) {
          continue;
        }
        const r = data[base];
        const g = data[base + 1];
        const b = data[base + 2];
        const key = `${r},${g},${b},${a}`;
        const paletteIndex = colorMap.get(key);
        if (paletteIndex !== undefined) {
          indices[i] = paletteIndex;
        }
      }
      return indices;
    });

    return {
      palette,
      frameIndices,
      overflow: false,
      reduced: sourceColorCount > palette.length,
      sourceColorCount,
    };
  }

  function dataUrlToBlob(dataUrl) {
    if (typeof dataUrl !== 'string' || !dataUrl.startsWith('data:')) {
      return null;
    }
    const match = dataUrl.match(/^data:([^;]+);base64,(.*)$/);
    if (!match) {
      return null;
    }
    const mimeType = match[1] || 'application/octet-stream';
    const base64Data = match[2] || '';
    try {
      const binary = atob(base64Data);
      const length = binary.length;
      const bytes = new Uint8Array(length);
      for (let i = 0; i < length; i += 1) {
        bytes[i] = binary.charCodeAt(i);
      }
      return new Blob([bytes], { type: mimeType });
    } catch (error) {
      console.warn('Failed to convert data URL to blob', error);
      return null;
    }
  }

  async function loadDocumentFromImageFile(file) {
    if (!ensureCurrentClientCanReplaceActiveProject()) {
      return false;
    }
    let importResult;
    try {
      importResult = await decodeImageFileToFrames(file);
    } catch (error) {
      throw createImageImportError('画像を読み込めませんでした', error);
    }

    const framesData = Array.isArray(importResult?.frames) ? importResult.frames : [];
    if (!framesData.length) {
      throw createImageImportError('画像を読み込めませんでした');
    }

    const inferredWidth = Number(importResult?.width ?? framesData[0]?.imageData?.width ?? 0);
    const inferredHeight = Number(importResult?.height ?? framesData[0]?.imageData?.height ?? 0);
    if (!Number.isFinite(inferredWidth) || !Number.isFinite(inferredHeight) || inferredWidth <= 0 || inferredHeight <= 0) {
      throw createImageImportError('画像サイズが不正です');
    }

    const integerScaleFactor = detectNearestNeighborIntegerScaleForFrames(framesData, inferredWidth, inferredHeight);
    const importSize = resolveImageImportTargetSize(inferredWidth, inferredHeight, { integerScaleFactor });
    const width = importSize.width;
    const height = importSize.height;
    const normalizedFramesData = importSize.scaled
      ? resizeImportFrames(framesData, width, height)
      : framesData;

    const paletteSource = state.palette && state.palette.length
      ? state.palette
      : createInitialState({ width, height }).palette;

    const frames = [];
    let palette = [];
    let activePaletteIndex = 0;
    let secondaryPaletteIndex = 0;
    let activeRgb = { r: 255, g: 255, b: 255, a: 255 };

    const extractedFrameData = normalizedFramesData.map((frameInfo) => (
      frameInfo?.imageData?.data instanceof Uint8ClampedArray
        ? frameInfo.imageData.data
        : null
    ));
    const extraction = buildIndexedPaletteFromFrameDataList(extractedFrameData);
    const canUseImportedPalette = (
      !extraction.overflow
      && Array.isArray(extraction.frameIndices)
      && extraction.frameIndices.length === normalizedFramesData.length
    );

    if (canUseImportedPalette) {
      palette = extraction.palette.length
        ? extraction.palette.map(color => ({ ...color }))
        : [{ r: 0, g: 0, b: 0, a: 0 }];
      activePaletteIndex = 0;
      secondaryPaletteIndex = Math.min(1, Math.max(0, palette.length - 1));
      activeRgb = { ...palette[activePaletteIndex] };
      normalizedFramesData.forEach((frameInfo, index) => {
        const layer = createLayer(localizeText('画像レイヤー', 'Image Layer'), width, height);
        const frameIndices = extraction.frameIndices[index];
        if (frameIndices instanceof Int16Array && frameIndices.length === layer.indices.length) {
          layer.indices = new Int16Array(frameIndices);
        } else {
          layer.indices.fill(-1);
        }
        layer.direct = null;
        frames.push({
          id: crypto.randomUUID ? crypto.randomUUID() : `frame-${Date.now().toString(36)}-${index}`,
          name: getDefaultFrameName(index + 1),
          duration: normalizeImportFrameDuration(frameInfo?.duration),
          layers: [layer],
        });
      });
    } else {
      palette = paletteSource.map(color => ({ ...color }));
      activePaletteIndex = palette.length
        ? clamp(state.activePaletteIndex ?? 0, 0, palette.length - 1)
        : 0;
      secondaryPaletteIndex = palette.length
        ? clamp(state.secondaryPaletteIndex ?? activePaletteIndex, 0, palette.length - 1)
        : activePaletteIndex;
      activeRgb = state.activeRgb
        ? { ...state.activeRgb }
        : (palette[activePaletteIndex] ? { ...palette[activePaletteIndex] } : { r: 255, g: 255, b: 255, a: 255 });

      normalizedFramesData.forEach((frameInfo, index) => {
        const layer = createLayer(localizeText('画像レイヤー', 'Image Layer'), width, height);
        layer.indices.fill(-1);
        const direct = ensureLayerDirect(layer, width, height);
        if (frameInfo?.imageData?.data instanceof Uint8ClampedArray
          && frameInfo.imageData.width === width
          && frameInfo.imageData.height === height) {
          direct.set(frameInfo.imageData.data);
        } else {
          direct.fill(0);
        }
        frames.push({
          id: crypto.randomUUID ? crypto.randomUUID() : `frame-${Date.now().toString(36)}-${index}`,
          name: getDefaultFrameName(index + 1),
          duration: normalizeImportFrameDuration(frameInfo?.duration),
          layers: [layer],
        });
      });
    }

    const activeLayerId = frames[0]?.layers[0]?.id;
    if (!activeLayerId) {
      throw createImageImportError('画像を読み込めませんでした');
    }

    const documentName = normalizeDocumentName(typeof file?.name === 'string' ? file.name : state.documentName);
    const activeToolGroup = TOOL_GROUPS[state.activeToolGroup] ? state.activeToolGroup : (TOOL_TO_GROUP[state.tool] || 'pen');

    const snapshot = {
      width,
      height,
      scale: normalizeZoomScale(state.scale, state.scale || MIN_ZOOM_SCALE),
      pan: { x: 0, y: 0 },
      tool: state.tool,
      brushSize: state.brushSize,
      outlineSize: state.outlineSize,
      palette,
      activePaletteIndex,
      secondaryPaletteIndex,
      activeRgb,
      frames,
      activeFrame: 0,
      activeLayer: activeLayerId,
      selectionMask: null,
      selectionBounds: null,
      showGrid: state.showGrid ?? true,
      showMajorGrid: state.showMajorGrid ?? true,
      gridScreenStep: state.gridScreenStep ?? 8,
      majorGridSpacing: state.majorGridSpacing ?? 16,
      backgroundMode: state.backgroundMode ?? 'dark',
      uiTheme: normalizeUiTheme(state.uiTheme, DEFAULT_UI_THEME),
      documentName,
      showPixelGuides: state.showPixelGuides ?? true,
      mirror: normalizeMirrorAxisState(state.mirror, width, height),
      showVirtualCursor: state.showVirtualCursor ?? false,
      showChecker: state.showChecker ?? true,
      onionSkin: normalizeOnionSkinState(state.onionSkin),
      dualLeftRail: false,
      activeToolGroup,
      lastGroupTool: { ...DEFAULT_GROUP_TOOL, ...(state.lastGroupTool || {}) },
      activeLeftTab: state.activeLeftTab ?? 'tools',
      activeRightTab: state.activeRightTab ?? 'frames',
    };

    applyHistorySnapshot(snapshot, { forcePalettePresetSync: true });
    history.past = [];
    history.future = [];
    history.pending = null;
    clearTimelapseRecording({ silent: true });
    resetDocumentUnsavedChanges();
    updateHistoryButtons();
    resetExportScaleDefaults();
    syncPixfindSnapshotAfterDocumentReset();
    setTrackedProjectDotBaseline(snapshot, null);

    autosaveHandle = null;
    pendingAutosaveHandle = null;
    clearPendingPermissionListener();
    setActiveAutosaveProjectId(createAutosaveProjectId());
    markAutosaveDirty();
    scheduleAutosaveSnapshot();
    const paletteReductionLabel = extraction.reduced
      ? localizeText(
        ` / 減色 ${extraction.sourceColorCount}色→${palette.length}色`,
        ` / Reduced ${extraction.sourceColorCount} colors to ${palette.length}`
      )
      : '';
    if (importSize.scaled) {
      const integerScaleLabel = importSize.integerScaleFactor > 1
        ? ` / 整数倍縮小 x${importSize.integerScaleFactor}`
        : '';
      updateAutosaveStatus(
        `画像を読み込みました (${importSize.sourceWidth}x${importSize.sourceHeight} → ${width}x${height}${integerScaleLabel})${paletteReductionLabel} / 端末内へ自動保存します`,
        'success'
      );
    } else {
      updateAutosaveStatus(`画像を読み込みました${paletteReductionLabel} / 端末内へ自動保存します`, 'success');
    }
    scheduleSessionPersist();
    return true;
  }

  async function fallbackRestoreAutosaveAfterLensFailure() {
    if (!lensImportRequested) {
      return;
    }
    if (!AUTOSAVE_SUPPORTED) {
      return;
    }
    try {
      const entries = await loadRecentProjectsMetadata();
      if (!entries.length) {
        return;
      }
      const target = autosaveProjectId
        ? (entries.find(entry => entry?.id === autosaveProjectId) || entries[0])
        : entries[0];
      const restored = await openRecentProject(target, { hideStartup: false, silent: true });
      if (restored) {
        updateAutosaveStatus('自動保存: 端末内データを復元しました', 'info');
      }
    } catch (error) {
      console.warn('Failed to restore autosave after PiXiEELENS import failure', error);
    }
  }

  function clearLensImportRequestParam() {
    if (typeof window === 'undefined' || typeof window.location === 'undefined') {
      return;
    }
    try {
      const currentUrl = new URL(window.location.href);
      if (!currentUrl.searchParams.has('lens')) {
        return;
      }
      currentUrl.searchParams.delete('lens');
      window.history.replaceState({}, document.title, currentUrl.toString());
    } catch (error) {
      // Ignore URL manipulation errors.
    }
  }

  function setLensImportSessionFlag() {
    if (!canUseSessionStorage) {
      return;
    }
    try {
      window.sessionStorage.setItem(LENS_IMPORT_SESSION_FLAG, '1');
    } catch (error) {
      // ignore
    }
  }

  function clearLensImportSessionFlag() {
    if (canUseSessionStorage) {
      try {
        window.sessionStorage.removeItem(LENS_IMPORT_SESSION_FLAG);
      } catch (error) {
        // ignore
      }
    }
    lensImportRequested = false;
  }

  function removeLensImportPayload() {
    try {
      window.localStorage.removeItem(LENS_IMPORT_STORAGE_KEY);
    } catch (error) {
      // ignore
    }
  }

  function finalizeLensImportAttempt({ clearPayload = false } = {}) {
    if (clearPayload) {
      removeLensImportPayload();
    }
    clearLensImportSessionFlag();
  }

  async function maybeImportLensCapture() {
    let shouldImport = false;
    try {
      const params = new URLSearchParams(window.location.search);
      shouldImport = params.get('lens') === '1';
    } catch (error) {
      shouldImport = false;
    }
    if (!shouldImport && lensImportRequested) {
      shouldImport = true;
    }
    if (!shouldImport) {
      return false;
    }

    let rawPayload = null;
    try {
      rawPayload = window.localStorage.getItem(LENS_IMPORT_STORAGE_KEY);
    } catch (error) {
      console.warn('PiXiEELENS transfer storage is not available', error);
    }

    let payload = null;
    if (rawPayload) {
      try {
        payload = JSON.parse(rawPayload);
      } catch (error) {
        console.warn('Failed to parse PiXiEELENS transfer payload', error);
      }
    }

    clearLensImportRequestParam();

    if (!payload || typeof payload !== 'object' || typeof payload.dataUrl !== 'string') {
      updateAutosaveStatus('PiXiEELENS からのデータが見つかりませんでした', 'warn');
      await fallbackRestoreAutosaveAfterLensFailure();
      finalizeLensImportAttempt({ clearPayload: true });
      return false;
    }

    if (payload.expiresAt && Number.isFinite(payload.expiresAt) && Date.now() > payload.expiresAt) {
      updateAutosaveStatus('PiXiEELENS からのデータが期限切れです。再度送信してください。', 'warn');
      await fallbackRestoreAutosaveAfterLensFailure();
      finalizeLensImportAttempt({ clearPayload: true });
      return false;
    }

    const blob = dataUrlToBlob(payload.dataUrl);
    if (!blob) {
      updateAutosaveStatus('PiXiEELENS の画像データを読み込めませんでした', 'error');
      await fallbackRestoreAutosaveAfterLensFailure();
      finalizeLensImportAttempt({ clearPayload: true });
      return false;
    }

    const inferredName = typeof payload.filename === 'string' && payload.filename
      ? payload.filename
      : 'pixiee-lens.png';
    let file;
    try {
      file = new File([blob], inferredName, { type: blob.type || 'image/png' });
    } catch (error) {
      file = blob;
      file.name = inferredName;
    }

    try {
      const imported = await openDocumentsAsProjectTabs(
        [file],
        async lensFile => {
          const loaded = await loadDocumentFromImageFile(lensFile);
          if (!loaded) {
            return false;
          }
          await ensureAutosaveForLensImport();
          return true;
        },
        { source: 'lens' }
      );
      if (!imported) {
        finalizeLensImportAttempt({ clearPayload: true });
        return false;
      }
      hideStartupScreen();
      if (AUTOSAVE_SUPPORTED) {
        try {
          await writeAutosaveSnapshot(true);
        } catch (error) {
          console.warn('Immediate autosave after PiXiEELENS import failed', error);
        }
      }
      updateAutosaveStatus(
        localizeText(
          'PiXiEELENS の画像を別プロジェクトタブで開きました',
          'Opened PiXiEELENS capture in a separate project tab'
        ),
        'success'
      );
      finalizeLensImportAttempt({ clearPayload: true });
      return true;
    } catch (error) {
      console.warn('Failed to import capture from PiXiEELENS', error);
      updateAutosaveStatus('PiXiEELENS の取り込みに失敗しました', 'error');
      await fallbackRestoreAutosaveAfterLensFailure();
      finalizeLensImportAttempt();
      return false;
    }
  }

  async function decodeImageFileToFrames(file) {
    if (isGifFile(file)) {
      return await decodeGifFileToFrames(file);
    }
    const imageData = await decodeImageFileToImageData(file);
    if (!imageData) {
      throw createImageImportError('画像を読み込めませんでした');
    }
    return {
      width: imageData.width,
      height: imageData.height,
      frames: [
        {
          imageData,
          duration: DEFAULT_IMPORT_FRAME_DURATION,
        },
      ],
    };
  }

  async function decodeGifFileToFrames(file) {
    if (!file) {
      throw createImageImportError('ファイルが選択されていません');
    }
    let buffer;
    try {
      buffer = await file.arrayBuffer();
    } catch (error) {
      throw createImageImportError('画像を読み込めませんでした', error);
    }
    if (!(buffer instanceof ArrayBuffer) || buffer.byteLength === 0) {
      throw createImageImportError('画像を読み込めませんでした');
    }

    const bytes = new Uint8Array(buffer);
    const mimeType = typeof file.type === 'string' && file.type ? file.type : 'image/gif';
    if (typeof window !== 'undefined' && typeof window.ImageDecoder === 'function') {
      try {
        const decoded = await decodeGifWithImageDecoder(bytes, mimeType);
        if (decoded && Array.isArray(decoded.frames) && decoded.frames.length >= 1) {
          return decoded;
        }
      } catch (error) {
        console.warn('ImageDecoder GIF decode failed, falling back to JavaScript decoder', error);
      }
    }
    const decodedByReader = decodeGifWithReader(bytes);
    // If a static GIF decodes oddly in the JS reader path, fall back to browser image decode.
    if (decodedByReader && Array.isArray(decodedByReader.frames) && decodedByReader.frames.length === 1) {
      try {
        const fallbackImageData = await decodeImageFileToImageData(file);
        if (fallbackImageData
          && fallbackImageData.width === decodedByReader.width
          && fallbackImageData.height === decodedByReader.height) {
          decodedByReader.frames[0] = {
            imageData: fallbackImageData,
            duration: decodedByReader.frames[0]?.duration ?? DEFAULT_IMPORT_FRAME_DURATION,
          };
        }
      } catch (error) {
        console.warn('Static GIF fallback decode failed', error);
      }
    }
    return decodedByReader;
  }

  async function decodeGifWithImageDecoder(buffer, mimeType) {
    let decoder;
    try {
      decoder = new ImageDecoder({ data: buffer, type: mimeType });
    } catch (error) {
      throw createImageImportError('画像を読み込めませんでした', error);
    }
    try {
      const track = decoder.tracks?.selectedTrack ?? decoder.tracks?.[0] ?? null;
      const frameCount = Number(track?.frameCount);
      const total = Number.isFinite(frameCount) && frameCount > 0 ? frameCount : 1;
      const frames = [];
      for (let i = 0; i < total; i += 1) {
        const result = await decoder.decode({ frameIndex: i, completeFramesOnly: true });
        const bitmap = result?.image;
        const imageData = imageBitmapToImageData(bitmap);
        if (bitmap && typeof bitmap.close === 'function') {
          bitmap.close();
        }
        const durationSeconds = Number(result?.duration);
        frames.push({
          imageData,
          duration: Number.isFinite(durationSeconds) && durationSeconds > 0
            ? durationSeconds * 1000
            : DEFAULT_IMPORT_FRAME_DURATION,
        });
      }
      const width = frames[0]?.imageData?.width ?? 0;
      const height = frames[0]?.imageData?.height ?? 0;
      if (!frames.length || !width || !height) {
        throw new Error('GIF decode returned no frames');
      }
      return {
        frames,
        width,
        height,
        loopCount: typeof track?.repetitionCount === 'number' ? track.repetitionCount : null,
      };
    } catch (error) {
      throw createImageImportError('画像を読み込めませんでした', error);
    } finally {
      if (decoder && typeof decoder.close === 'function') {
        decoder.close();
      }
    }
  }

  function decodeGifWithReader(bytes) {
    if (!(bytes instanceof Uint8Array)) {
      bytes = new Uint8Array(bytes);
    }
    let reader;
    try {
      reader = new GifReader(bytes);
    } catch (error) {
      throw createImageImportError('画像を読み込めませんでした', error);
    }
    const width = Number(reader.width);
    const height = Number(reader.height);
    if (!Number.isFinite(width) || !Number.isFinite(height) || width <= 0 || height <= 0) {
      throw createImageImportError('画像サイズが不正です');
    }
    const frameCount = Number(reader.numFrames());
    if (!Number.isFinite(frameCount) || frameCount <= 0) {
      throw createImageImportError('GIFにフレームが含まれていません');
    }
    const pixels = new Uint8ClampedArray(width * height * 4);
    const restoreBuffer = new Uint8ClampedArray(pixels.length);
    const backgroundColor = typeof reader.getBackgroundColor === 'function' ? reader.getBackgroundColor() : null;
    const backgroundIndex = typeof reader.getBackgroundIndex === 'function' ? reader.getBackgroundIndex() : null;
    const frames = [];
    let previousFrameInfo = null;

    if (backgroundColor && backgroundColor.a > 0) {
      fillGifCanvas(pixels, backgroundColor);
    } else {
      pixels.fill(0);
    }

    for (let i = 0; i < frameCount; i += 1) {
      const info = reader.frameInfo(i);

      if (previousFrameInfo) {
        if (previousFrameInfo.disposal === 2) {
          const fillColor = resolveDisposalFillColor(previousFrameInfo, backgroundColor, backgroundIndex);
          clearGifFrameRect(pixels, width, height, previousFrameInfo, fillColor);
        } else if (previousFrameInfo.disposal === 3) {
          pixels.set(restoreBuffer);
        }
      }

      if (info.disposal === 3) {
        restoreBuffer.set(pixels);
      }

      reader.decodeAndBlitFrameRGBA(i, pixels);
      const framePixels = new Uint8ClampedArray(pixels);
      const delayHundredths = Number(info.delay);
      frames.push({
        imageData: new ImageData(framePixels, width, height),
        duration: Number.isFinite(delayHundredths) && delayHundredths > 0
          ? delayHundredths * 10
          : DEFAULT_IMPORT_FRAME_DURATION,
      });

      previousFrameInfo = info;
    }

    return {
      frames,
      width,
      height,
      loopCount: typeof reader.loopCount === 'function' ? reader.loopCount() : null,
    };
  }

  function fillGifCanvas(pixels, color) {
    if (!color) {
      pixels.fill(0);
      return;
    }
    for (let i = 0; i < pixels.length; i += 4) {
      pixels[i] = color.r;
      pixels[i + 1] = color.g;
      pixels[i + 2] = color.b;
      pixels[i + 3] = color.a;
    }
  }

  function resolveDisposalFillColor(frameInfo, backgroundColor, backgroundIndex) {
    if (!backgroundColor) {
      return null;
    }
    const transparentIndex = typeof frameInfo?.transparent_index === 'number' ? frameInfo.transparent_index : null;
    if (transparentIndex !== null && transparentIndex >= 0) {
      if (typeof backgroundIndex === 'number' && backgroundIndex === transparentIndex) {
        return null;
      }
    }
    return backgroundColor;
  }

  function clearGifFrameRect(pixels, width, height, frame, fillColor = null) {
    const rawX = Number(frame.x);
    const rawY = Number(frame.y);
    const rawW = Number(frame.width);
    const rawH = Number(frame.height);
    const x = clamp(Number.isFinite(rawX) ? rawX : 0, 0, width);
    const y = clamp(Number.isFinite(rawY) ? rawY : 0, 0, height);
    const availableW = width - x;
    const availableH = height - y;
    const w = clamp(Number.isFinite(rawW) ? rawW : availableW, 0, availableW);
    const h = clamp(Number.isFinite(rawH) ? rawH : availableH, 0, availableH);
    if (w === 0 || h === 0) {
      return;
    }
    for (let row = 0; row < h; row += 1) {
      const offset = ((y + row) * width + x) * 4;
      if (!fillColor) {
        pixels.fill(0, offset, offset + w * 4);
      } else {
        let cursor = offset;
        for (let col = 0; col < w; col += 1) {
          pixels[cursor] = fillColor.r;
          pixels[cursor + 1] = fillColor.g;
          pixels[cursor + 2] = fillColor.b;
          pixels[cursor + 3] = fillColor.a;
          cursor += 4;
        }
      }
    }
  }

  async function decodeImageFileToImageData(file) {
    if (!file) {
      throw createImageImportError('ファイルが選択されていません');
    }
    if (typeof createImageBitmap === 'function') {
      try {
        const bitmap = await createImageBitmap(file);
        try {
          return imageBitmapToImageData(bitmap);
        } finally {
          if (typeof bitmap.close === 'function') {
            bitmap.close();
          }
        }
      } catch (error) {
        console.warn('createImageBitmap failed, falling back to Image', error);
      }
    }
    return await imageElementToImageData(file);
  }

  function imageBitmapToImageData(bitmap) {
    if (!bitmap || !bitmap.width || !bitmap.height) {
      throw createImageImportError('画像サイズが不正です');
    }
    const canvas = document.createElement('canvas');
    canvas.width = bitmap.width;
    canvas.height = bitmap.height;
    const ctx = canvas.getContext('2d');
    if (!ctx) {
      throw createImageImportError('画像を処理できませんでした');
    }
    ctx.drawImage(bitmap, 0, 0);
    return ctx.getImageData(0, 0, canvas.width, canvas.height);
  }

  function imageElementToImageData(file) {
    return new Promise((resolve, reject) => {
      const url = URL.createObjectURL(file);
      const image = new Image();
      image.decoding = 'async';
      image.onload = () => {
        try {
          const width = image.naturalWidth || image.width;
          const height = image.naturalHeight || image.height;
          if (!width || !height) {
            throw createImageImportError('画像サイズが不正です');
          }
          const canvas = document.createElement('canvas');
          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');
          if (!ctx) {
            throw createImageImportError('画像を処理できませんでした');
          }
          ctx.drawImage(image, 0, 0);
          const data = ctx.getImageData(0, 0, width, height);
          resolve(data);
        } catch (error) {
          reject(createImageImportError('画像を処理できませんでした', error));
        } finally {
          URL.revokeObjectURL(url);
        }
      };
      image.onerror = event => {
        URL.revokeObjectURL(url);
        reject(createImageImportError('画像の読み込みに失敗しました'));
      };
      image.src = url;
    });
  }

  async function openExportDialog() {
    if (!ensureCurrentClientCanExportProject({ announce: true })) {
      return;
    }
    const config = dom.exportDialog;
    if (!config) {
      exportProjectWithFallback();
      return;
    }
    if (EXPORT_DIRECTORY_SUPPORTED) {
      if (pendingExportDirectoryHandle && !exportDirectoryHandle) {
        await attemptExportDirectoryReauthorization();
      } else if (!exportDirectoryHandle && !exportDirectorySetupDismissed) {
        await requestExportDirectoryBinding();
      }
    }
    const dialog = config.dialog;
    if (dialog && typeof dialog.showModal === 'function') {
      refreshExportScaleControls();
      updateExportFormatAvailability();
      updateExportOriginalToggleUI();
      dialog.showModal();
      window.requestAnimationFrame(() => {
        queueExportAdRender();
      });
    } else {
      exportProjectWithFallback();
    }
  }

  function queueExportAdRender() {
    const dialog = dom.exportDialog?.dialog;
    const adSlot = dom.exportDialog?.adSlot;
    if (!(dialog instanceof HTMLDialogElement) || !dialog.open || !(adSlot instanceof HTMLElement)) {
      return;
    }
    if (exportAdRequested) {
      return;
    }
    if (adSlot.dataset.loaded === '1' || adSlot.getAttribute('data-adsbygoogle-status') === 'done') {
      exportAdRequested = true;
      return;
    }
    // Keep export slot out of global AdSense queue until dialog is open and width is measurable.
    if (!adSlot.classList.contains('adsbygoogle')) {
      adSlot.classList.add('adsbygoogle');
    }

    const getWidth = () => {
      try {
        const rect = adSlot.getBoundingClientRect();
        return (rect && rect.width) || adSlot.clientWidth || adSlot.offsetWidth || 0;
      } catch (error) {
        return adSlot.clientWidth || adSlot.offsetWidth || 0;
      }
    };

    let attempts = 0;
    const MAX_ATTEMPTS = 24;
    const renderWhenReady = () => {
      if (!(dialog instanceof HTMLDialogElement) || !dialog.open) {
        exportAdRequested = false;
        return;
      }
      const width = getWidth();
      if (width <= 0) {
        attempts += 1;
        if (attempts < MAX_ATTEMPTS) {
          window.requestAnimationFrame(renderWhenReady);
          return;
        }
        exportAdRequested = false;
        return;
      }
      exportAdRequested = true;
      try {
        (window.adsbygoogle = window.adsbygoogle || []).push({});
        adSlot.dataset.loaded = '1';
      } catch (error) {
        exportAdRequested = false;
      }
    };

    window.requestAnimationFrame(renderWhenReady);
  }

  function closeExportDialog() {
    const dialog = dom.exportDialog?.dialog;
    if (dialog && dialog.open) {
      dialog.close();
    }
  }

  function openShortcutHelpDialog() {
    const dialog = dom.shortcutHelp?.dialog;
    if (!(dialog instanceof HTMLDialogElement) || typeof dialog.showModal !== 'function') {
      return;
    }
    if (dialog.open) {
      return;
    }
    dialog.showModal();
    window.requestAnimationFrame(() => {
      dom.controls.closeShortcutHelp?.focus?.({ preventScroll: true });
    });
  }

  function closeShortcutHelpDialog() {
    const dialog = dom.shortcutHelp?.dialog;
    if (dialog instanceof HTMLDialogElement && dialog.open) {
      dialog.close();
    }
  }

  function parseUpdateHistoryTimestamp(value) {
    const timestamp = Date.parse(value);
    return Number.isFinite(timestamp) ? timestamp : 0;
  }

  function normalizeUpdateHistoryEntry(entry) {
    if (!entry || typeof entry !== 'object') {
      return null;
    }
    const at = typeof entry.at === 'string' ? entry.at : '';
    const timestamp = parseUpdateHistoryTimestamp(at);
    if (!timestamp) {
      return null;
    }
    const title = typeof entry.title === 'string' ? entry.title.trim() : '';
    if (!title) {
      return null;
    }
    const detailsSource = Array.isArray(entry.details) ? entry.details : [];
    const details = detailsSource
      .map(detail => (typeof detail === 'string' ? detail.trim() : ''))
      .filter(Boolean);
    const idSource = typeof entry.id === 'string' ? entry.id.trim() : '';
    const id = idSource || `${at}:${title}`;
    return {
      id,
      at,
      timestamp,
      title,
      details,
    };
  }

  function loadStoredUpdateHistoryEntries() {
    if (!canUseSessionStorage) {
      return [];
    }
    try {
      const raw = window.localStorage.getItem(UPDATE_HISTORY_STORAGE_KEY);
      if (!raw) {
        return [];
      }
      const parsed = JSON.parse(raw);
      if (!Array.isArray(parsed)) {
        return [];
      }
      return parsed;
    } catch (error) {
      return [];
    }
  }

  function saveStoredUpdateHistoryEntries(entries) {
    if (!canUseSessionStorage) {
      return;
    }
    try {
      const payload = Array.isArray(entries)
        ? entries.map(entry => ({
          id: entry.id,
          at: entry.at,
          title: entry.title,
          details: Array.isArray(entry.details) ? entry.details : [],
        }))
        : [];
      window.localStorage.setItem(UPDATE_HISTORY_STORAGE_KEY, JSON.stringify(payload));
    } catch (error) {
      // Ignore localStorage errors.
    }
  }

  function getUpdateHistoryEntries() {
    const cutoff = Date.now() - UPDATE_HISTORY_RETENTION_MS;
    const mergedById = new Map();
    const source = [
      ...loadStoredUpdateHistoryEntries(),
      ...BUILTIN_UPDATE_HISTORY_ENTRIES,
    ];
    source.forEach(entry => {
      const normalized = normalizeUpdateHistoryEntry(entry);
      if (!normalized) {
        return;
      }
      if (normalized.timestamp < cutoff) {
        return;
      }
      const previous = mergedById.get(normalized.id);
      if (!previous || normalized.timestamp >= previous.timestamp) {
        mergedById.set(normalized.id, normalized);
      }
    });
    const merged = Array.from(mergedById.values()).sort((a, b) => b.timestamp - a.timestamp);
    saveStoredUpdateHistoryEntries(merged);
    return merged;
  }

  function formatUpdateHistoryDate(timestamp, fallback = '') {
    if (!Number.isFinite(timestamp) || timestamp <= 0) {
      return fallback;
    }
    const d = new Date(timestamp);
    const y = d.getFullYear();
    const m = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    const hh = String(d.getHours()).padStart(2, '0');
    const mm = String(d.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${day} ${hh}:${mm}`;
  }

  function renderUpdateHistoryPanel() {
    const list = dom.updateHistory?.list;
    if (!(list instanceof HTMLElement)) {
      return;
    }
    list.replaceChildren();
    const entries = getUpdateHistoryEntries();
    if (!entries.length) {
      const empty = document.createElement('p');
      empty.className = 'help-text';
      empty.textContent = '更新履歴は準備中です。';
      list.appendChild(empty);
      return;
    }
    entries.forEach(entry => {
      const item = document.createElement('article');
      item.className = 'update-history-item';
      item.setAttribute('role', 'listitem');
      const head = document.createElement('div');
      head.className = 'update-history-item__head';
      const title = document.createElement('h3');
      title.className = 'update-history-item__title';
      title.textContent = entry.title;
      const time = document.createElement('time');
      time.className = 'update-history-item__time';
      time.dateTime = entry.at;
      time.textContent = formatUpdateHistoryDate(entry.timestamp, entry.at);
      head.append(title, time);
      item.appendChild(head);
      if (entry.details.length) {
        const detailList = document.createElement('ul');
        detailList.className = 'update-history-item__details';
        entry.details.forEach(detail => {
          const row = document.createElement('li');
          row.textContent = detail;
          detailList.appendChild(row);
        });
        item.appendChild(detailList);
      }
      list.appendChild(item);
    });
  }

  function openUpdateHistoryDialog() {
    const dialog = dom.updateHistory?.dialog;
    if (!(dialog instanceof HTMLDialogElement) || typeof dialog.showModal !== 'function') {
      return;
    }
    renderUpdateHistoryPanel();
    if (dialog.open) {
      return;
    }
    dialog.showModal();
    window.requestAnimationFrame(() => {
      dom.updateHistory?.close?.focus?.({ preventScroll: true });
    });
  }

  function closeUpdateHistoryDialog() {
    const dialog = dom.updateHistory?.dialog;
    if (dialog instanceof HTMLDialogElement && dialog.open) {
      dialog.close();
    }
  }

  function setupUpdateHistoryDialog() {
    const dialog = dom.updateHistory?.dialog;
    if (!(dialog instanceof HTMLDialogElement) || typeof dialog.showModal !== 'function') {
      if (dialog) {
        dialog.hidden = true;
      }
      return;
    }
    dom.updateHistory?.close?.addEventListener('click', () => {
      closeUpdateHistoryDialog();
    });
    dialog.addEventListener('cancel', event => {
      event.preventDefault();
      closeUpdateHistoryDialog();
    });
  }

  function openToolSpotlightDialog() {
    const dialog = dom.toolSpotlight?.dialog;
    if (!(dialog instanceof HTMLDialogElement) || typeof dialog.showModal !== 'function') {
      return;
    }
    if (dialog.open) {
      return;
    }
    dialog.showModal();
    window.requestAnimationFrame(() => {
      dom.toolSpotlight?.close?.focus?.({ preventScroll: true });
    });
  }

  function closeToolSpotlightDialog() {
    const dialog = dom.toolSpotlight?.dialog;
    if (dialog instanceof HTMLDialogElement && dialog.open) {
      dialog.close();
    }
  }

  function canShowExportInterstitial() {
    const dialog = dom.exportInterstitial?.dialog;
    if (!(dialog instanceof HTMLDialogElement) || typeof dialog.showModal !== 'function') {
      return false;
    }
    if (!canUseSessionStorage) {
      return true;
    }
    try {
      const lastShownAt = Number(window.localStorage.getItem(EXPORT_INTERSTITIAL_LAST_SHOWN_KEY) || 0);
      if (!Number.isFinite(lastShownAt) || lastShownAt <= 0) {
        return true;
      }
      return Date.now() - lastShownAt >= EXPORT_INTERSTITIAL_COOLDOWN_MS;
    } catch (error) {
      return true;
    }
  }

  function markExportInterstitialShown() {
    if (!canUseSessionStorage) {
      return;
    }
    try {
      window.localStorage.setItem(EXPORT_INTERSTITIAL_LAST_SHOWN_KEY, String(Date.now()));
    } catch (error) {
      // Ignore localStorage errors.
    }
  }

  function queueExportInterstitialAdRender() {
    const dialog = dom.exportInterstitial?.dialog;
    const adSlot = dom.exportInterstitial?.adSlot;
    if (!(dialog instanceof HTMLDialogElement) || !dialog.open || !(adSlot instanceof HTMLElement)) {
      return;
    }
    if (exportInterstitialAdRequested) {
      return;
    }
    if (adSlot.dataset.loaded === '1' || adSlot.getAttribute('data-adsbygoogle-status') === 'done') {
      exportInterstitialAdRequested = true;
      return;
    }
    if (!adSlot.classList.contains('adsbygoogle')) {
      adSlot.classList.add('adsbygoogle');
    }

    const getWidth = () => {
      try {
        const rect = adSlot.getBoundingClientRect();
        return (rect && rect.width) || adSlot.clientWidth || adSlot.offsetWidth || 0;
      } catch (error) {
        return adSlot.clientWidth || adSlot.offsetWidth || 0;
      }
    };

    let attempts = 0;
    const MAX_ATTEMPTS = 36;
    const renderWhenReady = () => {
      if (!(dialog instanceof HTMLDialogElement) || !dialog.open) {
        exportInterstitialAdRequested = false;
        return;
      }
      const width = getWidth();
      if (width <= 0) {
        attempts += 1;
        if (attempts < MAX_ATTEMPTS) {
          window.requestAnimationFrame(renderWhenReady);
          return;
        }
        exportInterstitialAdRequested = false;
        return;
      }
      exportInterstitialAdRequested = true;
      try {
        (window.adsbygoogle = window.adsbygoogle || []).push({});
        adSlot.dataset.loaded = '1';
      } catch (error) {
        exportInterstitialAdRequested = false;
      }
    };

    window.requestAnimationFrame(renderWhenReady);
  }

  function closeExportInterstitial({ showToolSpotlight = false } = {}) {
    const dialog = dom.exportInterstitial?.dialog;
    if (!(dialog instanceof HTMLDialogElement)) {
      return;
    }
    const wasOpen = dialog.open;
    if (wasOpen) {
      dialog.close();
    }
    exportInterstitialAdRequested = false;
    document.body.classList.remove('is-export-interstitial-active');
    if (showToolSpotlight && wasOpen) {
      window.requestAnimationFrame(() => {
        openToolSpotlightDialog();
      });
    }
  }

  function setupTopActionButtons() {
    dom.topActionButtons = Array.from(document.querySelectorAll('[data-ui-action]'));
    if (!Array.isArray(dom.topActionButtons) || !dom.topActionButtons.length) {
      return;
    }
    syncExternalToolActionButtons();
    dom.topActionButtons.forEach(button => {
      if (!(button instanceof HTMLButtonElement) || button.dataset.actionBound === 'true') {
        return;
      }
      button.dataset.actionBound = 'true';
      button.addEventListener('click', () => {
        const action = button.dataset.uiAction || '';
        if (!action) {
          return;
        }
        runUiAction(action, { sourceButton: button });
      });
    });
  }

  function showExportInterstitialAfterImageExport() {
    const dialog = dom.exportInterstitial?.dialog;
    if (!(dialog instanceof HTMLDialogElement) || typeof dialog.showModal !== 'function') {
      return;
    }
    if (dialog.open) {
      return;
    }
    if (!canShowExportInterstitial()) {
      return;
    }
    markExportInterstitialShown();
    dialog.showModal();
    document.body.classList.add('is-export-interstitial-active');
    queueExportInterstitialAdRender();
    window.requestAnimationFrame(() => {
      dom.exportInterstitial?.close?.focus?.({ preventScroll: true });
    });
  }

  function exportProjectWithFallback() {
    if (!ensureCurrentClientCanExportProject({ announce: true })) {
      return;
    }
    const residentPngOnly = isResidentMultiConnectedRoom();
    const choice = window.prompt(
      residentPngOnly
        ? '出力形式を入力してください (png)'
        : '出力形式を入力してください (png / jpeg / svg / grid / gif / timelapse / pixfind / project)',
      'png'
    );
    if (!choice) {
      return;
    }
    const inputMode = choice.trim().toLowerCase();
    if (inputMode === 'contest') {
      updateAutosaveStatus('コンテスト投稿は現在停止中です', 'warn');
      return;
    }
    if (
      inputMode !== 'png'
      && inputMode !== 'jpg'
      && inputMode !== 'jpeg'
      && inputMode !== 'svg'
      && inputMode !== 'grid'
      && inputMode !== 'gridpng'
      && inputMode !== 'spritemap'
      && inputMode !== 'spritesheet'
      && inputMode !== 'gif'
      && inputMode !== 'timelapse'
      && inputMode !== 'pixfind'
      && inputMode !== 'project'
    ) {
      window.alert('png / jpeg / svg / spritemap / grid / gif / timelapse / pixfind / project のいずれかを入力してください。');
      return;
    }
    const normalized = normalizeExportFormat(inputMode);
    if (!ensureCurrentClientCanExportProject({ announce: true, format: normalized })) {
      return;
    }
    if (normalized === 'png' || normalized === 'gridpng' || normalized === 'spritemap') {
      const candidates = getExportScaleCandidates(normalized);
      applyExportScaleConstraints(candidates);
      syncExportScaleInputs();
      const maxScale = exportMaxScale || 1;
      if (maxScale > 1 && exportSheetInfo) {
        const minW = exportSheetInfo.sheetWidth;
        const minH = exportSheetInfo.sheetHeight;
        const maxW = minW * maxScale;
        const maxH = minH * maxScale;
        const scaleInput = window.prompt(
          `書き出し倍率を入力してください (1〜${maxScale})\n幅 ${minW}〜${maxW}PX / 高さ ${minH}〜${maxH}PX`,
          String(exportScale),
        );
        if (scaleInput === null) {
          return;
        }
        exportScaleUserOverride = true;
        setExportScale(scaleInput);
      }
      if (normalized === 'gridpng') {
        const tileWidthInput = window.prompt('分割サイズの横幅(px)を入力してください', String(exportGridTileWidth));
        if (tileWidthInput === null) {
          return;
        }
        const tileHeightInput = window.prompt('分割サイズの高さ(px)を入力してください', String(exportGridTileHeight));
        if (tileHeightInput === null) {
          return;
        }
        exportGridTileWidth = normalizeExportGridTileSize(tileWidthInput, exportGridTileWidth);
        exportGridTileHeight = normalizeExportGridTileSize(tileHeightInput, exportGridTileHeight);
        syncExportGridInputs();
        scheduleSessionPersist({ includeSnapshots: false });
        exportProjectAsGridPng();
      } else if (normalized === 'spritemap') {
        exportProjectAsSpriteMap();
      } else {
        exportProjectAsPng();
      }
    } else if (normalized === 'jpeg') {
      exportProjectAsJpeg();
    } else if (normalized === 'svg') {
      exportProjectAsSvg();
    } else if (normalized === 'gif') {
      exportProjectAsGif();
    } else if (normalized === 'timelapse') {
      exportTimelapseGif();
    } else if (normalized === 'pixfind') {
      exportProjectToPixfind();
    } else if (normalized === 'project') {
      saveProjectAsPixieedraw();
    }
  }

  function normalizeTimelapseFps(value) {
    const parsed = Number(value);
    if (!Number.isFinite(parsed)) {
      return TIMELAPSE_DEFAULT_FPS;
    }
    return clamp(Math.round(parsed), TIMELAPSE_MIN_FPS, TIMELAPSE_MAX_FPS);
  }

  function createTimelapseFrameEntryFromState() {
    const width = Math.max(1, Number(state.width) || 1);
    const height = Math.max(1, Number(state.height) || 1);
    const frames = Array.isArray(state.frames) ? state.frames : [];
    if (!frames.length) {
      return null;
    }
    const frameIndex = clamp(Math.round(Number(state.activeFrame) || 0), 0, frames.length - 1);
    const frame = frames[frameIndex];
    if (!frame) {
      return null;
    }
    const pixels = compositeFramePixels(frame, width, height, state.palette);
    return {
      width,
      height,
      pixels: compressUint8Array(pixels, { clamped: true }),
    };
  }

  function createTimelapseFrameEntryFromSnapshot(snapshot) {
    if (!snapshot || typeof snapshot !== 'object') {
      return null;
    }
    let resolved = snapshot;
    const sampleIndices = snapshot?.frames?.[0]?.layers?.[0]?.indices;
    if (!(sampleIndices instanceof Int16Array)) {
      try {
        resolved = decompressHistorySnapshot(snapshot);
      } catch (error) {
        return null;
      }
    }
    const width = Math.max(1, Number(resolved.width) || 1);
    const height = Math.max(1, Number(resolved.height) || 1);
    const frames = Array.isArray(resolved.frames) ? resolved.frames : [];
    if (!frames.length) {
      return null;
    }
    const frameIndex = clamp(Math.round(Number(resolved.activeFrame) || 0), 0, frames.length - 1);
    const frame = frames[frameIndex] || frames[0];
    if (!frame) {
      return null;
    }
    const palette = Array.isArray(resolved.palette) ? resolved.palette : state.palette;
    const pixels = compositeFramePixels(frame, width, height, palette);
    return {
      width,
      height,
      pixels: compressUint8Array(pixels, { clamped: true }),
    };
  }

  function thinTimelapseSnapshotsIfNeeded() {
    const snapshots = timelapseState.snapshots;
    if (!Array.isArray(snapshots) || snapshots.length <= TIMELAPSE_MAX_STEPS) {
      return false;
    }
    for (let index = snapshots.length - 2; index >= 1; index -= 2) {
      snapshots.splice(index, 1);
    }
    timelapseState.sampleStep = Math.max(1, timelapseState.sampleStep * 2);
    return true;
  }

  function captureTimelapseFrameFromState() {
    if (!timelapseState.enabled) {
      return;
    }
    const entry = createTimelapseFrameEntryFromState();
    if (!entry) {
      return;
    }
    timelapseState.snapshots.push(entry);
    timelapseState.lastCaptureToken = unsavedChangeToken;
    const thinned = thinTimelapseSnapshotsIfNeeded();
    if (thinned && !timelapseState.warningShown) {
      timelapseState.warningShown = true;
      updateAutosaveStatus('タイムラプス記録が増えたため自動で間引きしました', 'warn');
    }
    syncTimelapseControls();
    updateMemoryStatus();
  }

  function flushPendingTimelapseCapture({ force = false } = {}) {
    const queued = timelapseCaptureQueued;
    const hasMissingCapture = timelapseState.lastCaptureToken !== unsavedChangeToken;
    if (timelapseCaptureTimer !== null) {
      window.clearTimeout(timelapseCaptureTimer);
      timelapseCaptureTimer = null;
    }
    if (!queued && !hasMissingCapture && !force) {
      return false;
    }
    timelapseCaptureQueued = false;
    if (!timelapseState.enabled) {
      return false;
    }
    if (!queued && !hasMissingCapture) {
      return false;
    }
    captureTimelapseFrameFromState();
    return true;
  }

  function scheduleTimelapseCaptureFromState({ immediate = false } = {}) {
    if (!timelapseState.enabled) {
      return;
    }
    timelapseCaptureQueued = true;
    if (immediate) {
      flushPendingTimelapseCapture();
      return;
    }
    if (timelapseCaptureTimer !== null) {
      return;
    }
    timelapseCaptureTimer = window.setTimeout(() => {
      timelapseCaptureTimer = null;
      flushPendingTimelapseCapture();
    }, TIMELAPSE_CAPTURE_DEBOUNCE_MS);
  }

  function syncTimelapseControls() {
    const stepCount = timelapseState.snapshots.length;
    const fps = normalizeTimelapseFps(timelapseState.fps);
    const sampleInfo = timelapseState.sampleStep > 1
      ? localizeText(` / 間引きx${timelapseState.sampleStep}`, ` / thinning x${timelapseState.sampleStep}`)
      : '';
    timelapseState.fps = fps;

    if (dom.controls.toggleTimelapse instanceof HTMLInputElement) {
      dom.controls.toggleTimelapse.checked = Boolean(timelapseState.enabled);
    }
    if (dom.controls.timelapseClear instanceof HTMLButtonElement) {
      dom.controls.timelapseClear.disabled = stepCount <= 0;
    }
    if (dom.controls.timelapseFps instanceof HTMLInputElement) {
      dom.controls.timelapseFps.value = String(fps);
    }
    if (dom.controls.timelapseStatus) {
      const status = timelapseState.enabled ? 'ON' : 'OFF';
      dom.controls.timelapseStatus.textContent = localizeText(
        `タイムラプス: ${status} (${stepCount}ステップ / ${fps}fps${sampleInfo})`,
        `Timelapse: ${status} (${stepCount} steps / ${fps}fps${sampleInfo})`
      );
    }
  }

  function clearTimelapseRecording({ silent = false } = {}) {
    if (timelapseCaptureTimer !== null) {
      window.clearTimeout(timelapseCaptureTimer);
      timelapseCaptureTimer = null;
    }
    timelapseCaptureQueued = false;
    timelapseState.snapshots.length = 0;
    timelapseState.warningShown = false;
    timelapseState.sampleStep = 1;
    timelapseState.lastCaptureToken = -1;
    syncTimelapseControls();
    if (!silent) {
      updateAutosaveStatus('タイムラプス記録をクリアしました', 'info');
    }
    updateMemoryStatus();
  }

  function setTimelapseEnabled(enabled, { persist = true } = {}) {
    const next = Boolean(enabled);
    if (timelapseState.enabled === next) {
      syncTimelapseControls();
      return;
    }
    timelapseState.enabled = next;
    if (next) {
      const shouldCaptureStart = timelapseState.snapshots.length === 0
        || timelapseState.lastCaptureToken !== unsavedChangeToken;
      if (shouldCaptureStart) {
        scheduleTimelapseCaptureFromState({ immediate: true });
      }
    } else if (timelapseCaptureTimer !== null) {
      window.clearTimeout(timelapseCaptureTimer);
      timelapseCaptureTimer = null;
      timelapseCaptureQueued = false;
    }
    syncTimelapseControls();
    updateAutosaveStatus(
      next ? 'タイムラプス記録をONにしました' : 'タイムラプス記録をOFFにしました',
      'info'
    );
    if (persist) {
      scheduleSessionPersist({ includeSnapshots: false });
    }
  }

  function resolveTimelapseFrameEntry(entry) {
    if (!entry || typeof entry !== 'object') {
      return null;
    }
    const width = Math.max(1, Number(entry.width) || 1);
    const height = Math.max(1, Number(entry.height) || 1);
    let pixels;
    try {
      pixels = decodeUint8Data(entry.pixels, { clamped: true });
    } catch (error) {
      return null;
    }
    const expectedLength = width * height * 4;
    if (!pixels || pixels.length !== expectedLength) {
      return null;
    }
    return {
      width,
      height,
      pixels: pixels instanceof Uint8ClampedArray ? pixels : new Uint8ClampedArray(pixels),
    };
  }

  function buildTimelapseExportEntries() {
    flushPendingTimelapseCapture();
    const snapshots = timelapseState.snapshots.slice();
    if (timelapseState.enabled && timelapseState.lastCaptureToken !== unsavedChangeToken) {
      const current = createTimelapseFrameEntryFromState();
      if (current) {
        snapshots.push(current);
      }
    }
    return snapshots;
  }

  async function exportTimelapseGif() {
    if (!ensureCurrentClientCanExportProject({ announce: true, format: 'timelapse' })) {
      return;
    }
    if (timelapseState.snapshots.length <= 0 && timelapseState.lastCaptureToken < 0) {
      updateAutosaveStatus('タイムラプス記録がありません。設定でONにして描画してください。', 'warn');
      return;
    }
    const snapshots = buildTimelapseExportEntries();
    if (!snapshots.length) {
      updateAutosaveStatus('タイムラプス記録がありません', 'warn');
      return;
    }

    try {
      updateAutosaveStatus('タイムラプスGIFを書き出し中…', 'info');
      const candidates = getExportScaleCandidates();
      const selectedScale = applyExportScaleConstraints(candidates);
      syncExportScaleInputs();
      const targetWidth = Math.max(1, Number(state.width) || 1);
      const targetHeight = Math.max(1, Number(state.height) || 1);
      const framePixels = [];
      let skippedSizeMismatch = 0;
      let skippedInvalid = 0;

      for (let i = 0; i < snapshots.length; i += 1) {
        const resolved = resolveTimelapseFrameEntry(snapshots[i]);
        if (!resolved) {
          skippedInvalid += 1;
          continue;
        }
        const width = resolved.width;
        const height = resolved.height;
        if (width !== targetWidth || height !== targetHeight) {
          skippedSizeMismatch += 1;
          continue;
        }
        framePixels.push(resolved.pixels);
      }

      if (!framePixels.length) {
        updateAutosaveStatus('タイムラプスGIFを書き出せませんでした', 'error');
        return;
      }

      const fps = normalizeTimelapseFps(timelapseState.fps);
      timelapseState.fps = fps;
      const frameDuration = clamp(Math.round(1000 / fps), 16, 2000);
      const frameDurations = new Array(framePixels.length).fill(frameDuration);
      const scaledSet = scaleFrameSetNearestNeighbor(framePixels, targetWidth, targetHeight, selectedScale);
      const gifBytes = buildGifFromPixels(
        scaledSet.framePixels,
        frameDurations,
        scaledSet.width,
        scaledSet.height
      );
      const tasks = [{
        blob: new Blob([gifBytes], { type: 'image/gif' }),
        filename: createExportFileName('gif', selectedScale > 1 ? `timelapse_x${selectedScale}` : 'timelapse'),
        shareText: `タイムラプスGIFを書き出しました (${framePixels.length}ステップ${selectedScale > 1 ? ` / ×${selectedScale}` : ''})`,
      }];
      const result = await deliverExportTasks(tasks, {
        mimeType: 'image/gif',
        fileExtensions: ['.gif'],
        shareTitle: state.documentName || 'PiXiEEDraw',
        shareText: 'タイムラプスGIFを書き出しました',
      });

      const detailParts = [`${framePixels.length}ステップ`];
      if (selectedScale > 1) {
        detailParts.push(`×${selectedScale}`);
      }
      const skipped = skippedSizeMismatch + skippedInvalid;
      if (skipped > 0) {
        detailParts.push(`除外 ${skipped}`);
      }
      const detail = detailParts.join(' / ');
      if (result.exportedCount === result.total) {
        updateAutosaveStatus(`タイムラプスGIFを書き出しました (${detail})`, 'success');
      } else if (result.wasCancelled) {
        updateAutosaveStatus('タイムラプスGIFの書き出しをキャンセルしました', 'warn');
      } else if (result.exportedCount > 0 && result.hadFailure) {
        updateAutosaveStatus('タイムラプスGIFを書き出しましたが一部失敗しました', 'warn');
      } else {
        updateAutosaveStatus('タイムラプスGIFの書き出しに失敗しました', 'error');
      }
      if (result.exportedCount > 0) {
        markDocumentDurablySaved();
        if (result.exportedCount === result.total && !result.wasCancelled && !result.hadFailure) {
          const companionResult = await maybeSaveProjectCompanionAfterExport('timelapse', {
            exportedCount: result.exportedCount,
            wasCancelled: result.wasCancelled,
          });
          announceProjectCompanionSaveResult('timelapse', companionResult);
        }
        showExportInterstitialAfterImageExport();
      }
      syncTimelapseControls();
    } catch (error) {
      console.error('Timelapse export failed', error);
      updateAutosaveStatus('タイムラプスGIFの書き出しに失敗しました', 'error');
    }
  }

  function normalizeFpsValue(value) {
    return clamp(Math.round(Number(value) || 0), 1, 60);
  }

  function getDurationFromFps(fps) {
    if (!Number.isFinite(fps) || fps <= 0) {
      return 1000 / 12;
    }
    return 1000 / fps;
  }

  function updateAnimationFpsDisplay(fps, durationMs) {
    if (dom.controls.animationFps) {
      dom.controls.animationFps.value = String(fps);
    }
    if (dom.controls.animationFpsMs) {
      const rounded = Math.max(1, Math.round(Number(durationMs) || 0));
      dom.controls.animationFpsMs.textContent = `${rounded}ms`;
    }
  }

  function syncAnimationFpsDisplayFromState() {
    const frame = getActiveFrame();
    const duration = frame && Number.isFinite(frame.duration) && frame.duration > 0
      ? frame.duration
      : 1000 / 12;
    const fps = normalizeFpsValue(Math.round(1000 / duration));
    updateAnimationFpsDisplay(fps, duration);
  }

  function applyFpsToAllFrames(fpsValue) {
    if (!canCurrentClientEditProjectStructure()) {
      setMultiStatus(localizeText('参加/視聴モードではfps設定はマスターのみ変更できます', 'In participant/viewer mode, only the master can change FPS'), 'warn');
      return;
    }
    const frames = state.frames;
    if (!Array.isArray(frames) || !frames.length) {
      return;
    }
    const clampedFps = normalizeFpsValue(fpsValue);
    const nextDuration = getDurationFromFps(clampedFps);
    const hasChange = frames.some(frame => Math.abs(frame.duration - nextDuration) > 0.001);
    if (!hasChange) {
      updateAnimationFpsDisplay(clampedFps, nextDuration);
      return;
    }
    beginHistory('setAllFrameFps');
    frames.forEach(frame => {
      frame.duration = nextDuration;
    });
    markHistoryDirty();
    commitHistory();
    scheduleSessionPersist();
    renderTimelineMatrix();
    updateAnimationFpsDisplay(clampedFps, nextDuration);
  }

  function setActiveFrameIndex(nextIndex, {
    wrap = false,
    persist = true,
    render = true,
    syncUi = true,
  } = {}) {
    const frames = state.frames;
    if (!Array.isArray(frames) || !frames.length) {
      return null;
    }
    const length = frames.length;
    const normalizedIndex = wrap
      ? ((Math.round(nextIndex) % length) + length) % length
      : clamp(Math.round(nextIndex), 0, length - 1);
    const previousIndex = state.activeFrame;
    state.activeFrame = normalizedIndex;
    const frame = frames[normalizedIndex];
    if (frame && (!frame.layers.some(layer => layer.id === state.activeLayer) || !state.activeLayer)) {
      const lastLayer = frame.layers[frame.layers.length - 1];
      if (lastLayer) {
        state.activeLayer = lastLayer.id;
      }
    }
    if (isMultiAssignedCellRestrictedEditorMode()) {
      enforceGuestAssignedLayerSelection({ announce: false });
    }
    if (persist) {
      scheduleSessionPersist();
    }
    if (render) {
      if (previousIndex !== normalizedIndex) {
        renderFrameList();
        renderLayerList();
        requestRender();
        requestOverlayRender();
      } else {
        syncAnimationFpsDisplayFromState();
        syncActiveFrameSettingsUI();
      }
    }
    if (syncUi) {
      updatePixfindModeUI();
    }
    return frame;
  }

  function stepActiveFrame(offset, options = {}) {
    const frames = state.frames;
    if (!Array.isArray(frames) || !frames.length) {
      return;
    }
    const wrap = options.wrap !== false;
    const persist = options.persist !== false;
    const render = options.render !== false;
    const syncUi = options.syncUi !== false;
    const nextIndex = state.activeFrame + Number(offset || 0);
    setActiveFrameIndex(nextIndex, { wrap, persist, render, syncUi });
  }

  function setActiveLayerTrackIndex(nextIndex, {
    persist = true,
    render = true,
    syncUi = true,
  } = {}) {
    const frame = getActiveFrame();
    if (!frame || !Array.isArray(frame.layers) || !frame.layers.length) {
      return null;
    }
    if (isMultiAssignedCellRestrictedEditorMode()) {
      enforceGuestAssignedLayerSelection({ announce: false });
      return getActiveLayer();
    }
    const normalizedIndex = clamp(Math.round(Number(nextIndex) || 0), 0, frame.layers.length - 1);
    const nextLayer = frame.layers[normalizedIndex];
    if (!nextLayer) {
      return null;
    }
    const previousLayerId = state.activeLayer;
    state.activeLayer = nextLayer.id;
    if (persist) {
      scheduleSessionPersist();
    }
    if (render) {
      if (previousLayerId !== nextLayer.id) {
        renderFrameList();
        renderLayerList();
        requestRender();
        requestOverlayRender();
      } else {
        syncActiveLayerSettingsUI();
      }
    }
    if (syncUi) {
      updatePixfindModeUI();
    }
    return nextLayer;
  }

  function stepActiveLayerTrack(offset, options = {}) {
    const frame = getActiveFrame();
    if (!frame || !Array.isArray(frame.layers) || !frame.layers.length) {
      return null;
    }
    const currentIndex = getActiveLayerIndex();
    const baseIndex = currentIndex >= 0 ? currentIndex : frame.layers.length - 1;
    const nextIndex = baseIndex + Number(offset || 0);
    return setActiveLayerTrackIndex(nextIndex, options);
  }

  function addOrDuplicateFrameAfterActive({ duplicate = false } = {}) {
    if (state.playback.isPlaying) {
      return false;
    }
    if (!canCurrentClientEditProjectStructure()) {
      setMultiStatus(
        localizeText(
          duplicate
            ? '参加/視聴モードではフレーム複製はマスターのみ操作できます'
            : '参加/視聴モードではフレーム追加はマスターのみ操作できます',
          duplicate
            ? 'In participant/viewer mode, only the master can duplicate frames'
            : 'In participant/viewer mode, only the master can add frames'
        ),
        'warn'
      );
      return false;
    }
    const baseFrame = getActiveFrame();
    if (!baseFrame) {
      return false;
    }
    clearTimelineSelection();
    beginHistory(duplicate ? 'duplicateFrame' : 'addFrame');
    const sourceLayers = duplicate ? baseFrame.layers : baseFrame.layers;
    const newFrame = createFrame(
      getDefaultFrameName(state.frames.length + 1),
      sourceLayers,
      state.width,
      state.height
    );
    if (duplicate) {
      newFrame.duration = Number.isFinite(baseFrame.duration) && baseFrame.duration > 0
        ? baseFrame.duration
        : newFrame.duration;
      newFrame.name = getDefaultFrameName(state.activeFrame + 2);
    }
    state.frames.splice(state.activeFrame + 1, 0, newFrame);
    state.activeFrame += 1;
    state.activeLayer = newFrame.layers[newFrame.layers.length - 1].id;
    markHistoryDirty();
    scheduleSessionPersist();
    renderFrameList();
    renderLayerList();
    requestRender();
    requestOverlayRender();
    commitHistory();
    updateAutosaveStatus(
      localizeText(
        duplicate ? 'フレームを複製しました' : 'フレームを追加しました',
        duplicate ? 'Frame duplicated' : 'Frame added'
      ),
      'success'
    );
    return true;
  }

  function togglePlaybackFromShortcut() {
    if (state.playback.isPlaying) {
      stopPlayback();
      return true;
    }
    startPlayback();
    return Boolean(state.playback.isPlaying);
  }

  function openNewProjectDialog() {
    if (!ensureCurrentClientCanReplaceActiveProject()) {
      return;
    }
    const config = dom.newProject;
    if (!config) {
      void promptNewProjectFallback();
      return;
    }
    const dialog = config.dialog;
    if (dialog && typeof dialog.showModal === 'function') {
      if (config.nameInput) {
        const currentName = state.documentName || DEFAULT_DOCUMENT_NAME;
        config.nameInput.value = extractDocumentBaseName(currentName);
      }
      if (config.widthInput) {
        config.widthInput.value = String(state.width);
      }
      if (config.heightInput) {
        config.heightInput.value = String(state.height);
      }
      if (config.palettePreset) {
        const normalizedPreset = normalizeNewProjectPalettePreset(
          newProjectPalettePresetId,
          NEW_PROJECT_PALETTE_PRESET_DEFAULT
        );
        renderNewProjectPalettePresetOptions(normalizedPreset);
        config.palettePreset.value = normalizedPreset;
        renderNewProjectPalettePresetPicker(normalizedPreset);
        setNewProjectPalettePresetPickerOpen(false);
      }
      dialog.showModal();
      window.requestAnimationFrame(() => {
        config.nameInput?.focus();
        config.nameInput?.select?.();
      });
      return;
    }
    void promptNewProjectFallback();
  }

  function setupExportDialog() {
    const config = dom.exportDialog;
    if (!config) {
      return;
    }
    const dialog = config.dialog;
    const supportsDialog = dialog && typeof dialog.showModal === 'function';
    const bind = (element, handler) => {
      if (element) {
        element.addEventListener('click', handler);
      }
    };
    bind(config.confirm, () => {
      const mode = normalizeExportFormat(config.format?.value || 'png');
      if (!ensureCurrentClientCanExportProject({ announce: true, format: mode })) {
        updateExportFormatAvailability();
        return;
      }
      if (mode === 'gif') {
        exportProjectAsGif();
      } else if (mode === 'jpeg') {
        exportProjectAsJpeg();
      } else if (mode === 'svg') {
        exportProjectAsSvg();
      } else if (mode === 'spritemap') {
        exportProjectAsSpriteMap();
      } else if (mode === 'gridpng') {
        exportProjectAsGridPng();
      } else if (mode === 'timelapse') {
        exportTimelapseGif();
      } else if (mode === 'contest') {
        updateAutosaveStatus('コンテスト投稿は現在停止中です', 'warn');
      } else if (mode === 'pixfind') {
        exportProjectToPixfind();
      } else if (mode === 'project') {
        saveProjectAsPixieedraw();
      } else {
        exportProjectAsPng();
      }
      closeExportDialog();
    });
    bind(config.cancel, () => {
      closeExportDialog();
    });
    if (supportsDialog && dialog) {
      dialog.addEventListener('cancel', event => {
        event.preventDefault();
        closeExportDialog();
      });
    } else if (dialog) {
      dialog.hidden = true;
    }
    if (!supportsDialog && config.adContainer) {
      config.adContainer.hidden = true;
    }
    if (config.format && config.format.dataset.bound !== 'true') {
      config.format.dataset.bound = 'true';
      config.format.addEventListener('change', () => {
        refreshExportScaleControls();
        updateExportFormatAvailability();
        updateExportOriginalToggleUI();
      });
    }
    if (config.includeOriginalToggle instanceof HTMLInputElement && config.includeOriginalToggle.dataset.bound !== 'true') {
      config.includeOriginalToggle.dataset.bound = 'true';
      config.includeOriginalToggle.checked = exportIncludeOriginalSize;
      config.includeOriginalToggle.addEventListener('change', event => {
        exportIncludeOriginalSize = Boolean(event.target.checked);
        scheduleSessionPersist({ includeSnapshots: false });
        updateExportOriginalToggleUI();
      });
    }
    if (config.saveProjectCompanionToggle instanceof HTMLInputElement
      && config.saveProjectCompanionToggle.dataset.bound !== 'true') {
      config.saveProjectCompanionToggle.dataset.bound = 'true';
      config.saveProjectCompanionToggle.checked = exportSaveProjectCompanion;
      config.saveProjectCompanionToggle.addEventListener('change', event => {
        exportSaveProjectCompanion = Boolean(event.target.checked);
        scheduleSessionPersist({ includeSnapshots: false });
        updateExportProjectCompanionToggleUI();
      });
    }
    if (config.contestPostToggle instanceof HTMLInputElement
      && config.contestPostToggle.dataset.bound !== 'true') {
      config.contestPostToggle.dataset.bound = 'true';
      config.contestPostToggle.checked = exportContestPostAfterSave;
      config.contestPostToggle.addEventListener('change', event => {
        exportContestPostAfterSave = Boolean(event.target.checked);
        scheduleSessionPersist({ includeSnapshots: false });
        updateExportContestPostToggleUI();
      });
    }

    const slider = config.scaleSlider;
    if (slider && slider.dataset.bound !== 'true') {
      slider.dataset.bound = 'true';
      slider.addEventListener('input', event => {
        exportScaleUserOverride = true;
        setExportScale(event.target.value);
      });
    }

    const scaleInput = config.scaleInput;
    if (scaleInput && scaleInput.dataset.bound !== 'true') {
      scaleInput.dataset.bound = 'true';
      scaleInput.addEventListener('change', event => {
        exportScaleUserOverride = true;
        setExportScale(event.target.value);
      });
    }

    const widthInput = config.pixelWidthInput;
    if (widthInput && widthInput.dataset.bound !== 'true') {
      widthInput.dataset.bound = 'true';
      widthInput.addEventListener('change', event => {
        exportScaleUserOverride = true;
        if (!exportSheetInfo) {
          syncExportScaleInputs();
          return;
        }
        const desiredWidth = Math.round(Number(event.target.value));
        if (!Number.isFinite(desiredWidth) || desiredWidth <= 0) {
          syncExportScaleInputs();
          return;
        }
        const baseWidth = Math.max(1, exportSheetInfo.sheetWidth);
        const targetScale = clamp(Math.round(desiredWidth / baseWidth), 1, exportMaxScale || 1);
        setExportScale(targetScale);
      });
    }

    const heightInput = config.pixelHeightInput;
    if (heightInput && heightInput.dataset.bound !== 'true') {
      heightInput.dataset.bound = 'true';
      heightInput.addEventListener('change', event => {
        exportScaleUserOverride = true;
        if (!exportSheetInfo) {
          syncExportScaleInputs();
          return;
        }
        const desiredHeight = Math.round(Number(event.target.value));
        if (!Number.isFinite(desiredHeight) || desiredHeight <= 0) {
          syncExportScaleInputs();
          return;
        }
        const baseHeight = Math.max(1, exportSheetInfo.sheetHeight);
        const targetScale = clamp(Math.round(desiredHeight / baseHeight), 1, exportMaxScale || 1);
        setExportScale(targetScale);
      });
    }

    const gridWidthInput = config.gridWidthInput;
    if (gridWidthInput instanceof HTMLInputElement && gridWidthInput.dataset.bound !== 'true') {
      gridWidthInput.dataset.bound = 'true';
      gridWidthInput.addEventListener('change', event => {
        exportGridTileWidth = normalizeExportGridTileSize(event.target.value, exportGridTileWidth);
        syncExportGridInputs();
        scheduleSessionPersist({ includeSnapshots: false });
      });
    }

    const gridHeightInput = config.gridHeightInput;
    if (gridHeightInput instanceof HTMLInputElement && gridHeightInput.dataset.bound !== 'true') {
      gridHeightInput.dataset.bound = 'true';
      gridHeightInput.addEventListener('change', event => {
        exportGridTileHeight = normalizeExportGridTileSize(event.target.value, exportGridTileHeight);
        syncExportGridInputs();
        scheduleSessionPersist({ includeSnapshots: false });
      });
    }

    syncExportGridInputs();
    updateExportFormatAvailability();
    updateExportOriginalToggleUI();
  }

  function setupExportInterstitialDialog() {
    const dialog = dom.exportInterstitial?.dialog;
    if (!(dialog instanceof HTMLDialogElement) || typeof dialog.showModal !== 'function') {
      if (dialog) {
        dialog.hidden = true;
      }
      return;
    }
    dom.exportInterstitial?.close?.addEventListener('click', () => {
      closeExportInterstitial({ showToolSpotlight: true });
    });
    dialog.addEventListener('cancel', event => {
      event.preventDefault();
      closeExportInterstitial({ showToolSpotlight: true });
    });
    dialog.addEventListener('close', () => {
      exportInterstitialAdRequested = false;
      document.body.classList.remove('is-export-interstitial-active');
    });
  }

  function setupToolSpotlightDialog() {
    const dialog = dom.toolSpotlight?.dialog;
    if (!(dialog instanceof HTMLDialogElement) || typeof dialog.showModal !== 'function') {
      if (dialog) {
        dialog.hidden = true;
      }
      return;
    }
    dom.toolSpotlight?.close?.addEventListener('click', () => {
      closeToolSpotlightDialog();
    });
    dom.toolSpotlight?.goHome?.addEventListener('click', () => {
      closeToolSpotlightDialog();
    });
    dom.toolSpotlight?.openContest?.addEventListener('click', () => {
      closeToolSpotlightDialog();
    });
    dialog.addEventListener('cancel', event => {
      event.preventDefault();
      closeToolSpotlightDialog();
    });
  }

  function closeNewProjectDialog() {
    setNewProjectPalettePresetPickerOpen(false);
    const dialog = dom.newProject?.dialog;
    if (dialog && dialog.open) {
      dialog.close();
    }
  }

  async function handleNewProjectSubmit() {
    const config = dom.newProject;
    if (config?.form && typeof config.form.reportValidity === 'function') {
      if (!config.form.reportValidity()) {
        return;
      }
    }
    const rawName = config?.nameInput?.value ?? state.documentName;
    const name = normalizeDocumentName(rawName);
    const widthValue = config?.widthInput?.value;
    const heightValue = config?.heightInput?.value;
    const palettePresetValue = config?.palettePreset?.value;
    const width = Number(widthValue);
    const height = Number(heightValue);
    const created = await createNewProject({
      name,
      width,
      height,
      palettePreset: palettePresetValue,
      promptExportDirectory: false,
    });
    if (created) {
      if (config?.nameInput) {
        config.nameInput.value = extractDocumentBaseName(name);
      }
      closeNewProjectDialog();
    } else {
      window.alert(`キャンバスサイズは${MIN_CANVAS_SIZE}〜${MAX_CANVAS_SIZE}の数値で入力してください。`);
    }
  }

  async function promptNewProjectFallback() {
    if (!ensureCurrentClientCanReplaceActiveProject()) {
      return;
    }
    const name = window.prompt('ファイル名を入力してください', state.documentName || DEFAULT_DOCUMENT_NAME);
    if (name === null) return;
    const widthRaw = window.prompt(`キャンバスの横幅 (${MIN_CANVAS_SIZE}〜${MAX_CANVAS_SIZE})`, String(state.width));
    if (widthRaw === null) return;
    const heightRaw = window.prompt(`キャンバスの縦幅 (${MIN_CANVAS_SIZE}〜${MAX_CANVAS_SIZE})`, String(state.height));
    if (heightRaw === null) return;
    const width = Number(widthRaw);
    const height = Number(heightRaw);
    if (!(await createNewProject({
      name,
      width,
      height,
      promptExportDirectory: false,
    }))) {
      window.alert(`キャンバスサイズは${MIN_CANVAS_SIZE}〜${MAX_CANVAS_SIZE}の数値で入力してください。`);
    }
  }

  async function ensureExportDirectoryForNewProject() {
    if (!EXPORT_DIRECTORY_SUPPORTED || exportDirectoryHandle) {
      return;
    }
    if (pendingExportDirectoryHandle) {
      const restored = await attemptExportDirectoryReauthorization();
      if (restored || exportDirectoryHandle) {
        return;
      }
    }
    if (typeof window.showDirectoryPicker !== 'function') {
      return;
    }
    exportDirectorySetupDismissed = false;
    updateExportFolderStatus(
      localizeText(
        '新規作成: 画像/GIFの保存先フォルダを選択してください',
        'New project: choose a folder for image/GIF exports'
      ),
      'info'
    );
    const bound = await requestExportDirectoryBinding();
    if (!bound && !exportDirectoryHandle) {
      updateExportFolderStatus(
        localizeText(
          '新規作成: 保存先フォルダは未設定のまま続行します（保存時に選択可能）',
          'New project: continuing without a fixed export folder (you can choose on each save)'
        ),
        'warn'
      );
    }
  }

  async function createNewProject({
    name,
    width,
    height,
    palettePreset = newProjectPalettePresetId,
    promptExportDirectory = false,
  }) {
    if (!ensureCurrentClientCanReplaceActiveProject()) {
      return false;
    }
    const widthNumber = lockedCanvasWidth !== null ? lockedCanvasWidth : Number(width);
    const heightNumber = lockedCanvasHeight !== null ? lockedCanvasHeight : Number(height);
    if (!Number.isFinite(widthNumber) || !Number.isFinite(heightNumber)) {
      return false;
    }
    if (promptExportDirectory) {
      try {
        await ensureExportDirectoryForNewProject();
      } catch (error) {
        console.warn('Failed to prepare export directory during new project creation', error);
      }
    }
    const clampedWidth = clamp(Math.round(widthNumber), MIN_CANVAS_SIZE, MAX_CANVAS_SIZE);
    const clampedHeight = clamp(Math.round(heightNumber), MIN_CANVAS_SIZE, MAX_CANVAS_SIZE);
    const normalizedPalettePreset = normalizeNewProjectPalettePreset(
      palettePreset,
      newProjectPalettePresetId || NEW_PROJECT_PALETTE_PRESET_DEFAULT
    );
    setNewProjectPalettePresetId(normalizedPalettePreset);
    const snapshot = createInitialState({
      width: clampedWidth,
      height: clampedHeight,
      name,
      uiTheme: state.uiTheme,
      palettePreset: normalizedPalettePreset,
    });

    applyHistorySnapshot(snapshot);
    setCurrentPalettePresetId(normalizedPalettePreset, { syncControl: true });
    history.past = [];
    history.future = [];
    history.pending = null;
    clearTimelapseRecording({ silent: true });
    resetDocumentUnsavedChanges();
    updateHistoryButtons();
    resetExportScaleDefaults();
    syncPixfindSnapshotAfterDocumentReset();
    setTrackedProjectDotBaseline(snapshot, null);

    autosaveHandle = null;
    pendingAutosaveHandle = null;
    clearPendingPermissionListener();
    setActiveAutosaveProjectId(createAutosaveProjectId());
    markAutosaveDirty();
    if (AUTOSAVE_SUPPORTED && autosaveWriteTimer !== null) {
      window.clearTimeout(autosaveWriteTimer);
      autosaveWriteTimer = null;
    }
    let savedImmediately = false;
    if (AUTOSAVE_SUPPORTED) {
      for (let attempt = 0; attempt < NEW_PROJECT_IMMEDIATE_AUTOSAVE_ATTEMPTS && !savedImmediately; attempt += 1) {
        try {
          savedImmediately = await writeAutosaveSnapshot(true);
        } catch (error) {
          console.warn('Immediate autosave after creating a new project failed', error);
          savedImmediately = false;
        }
      }
    }
    if (savedImmediately) {
      updateAutosaveStatus('自動保存: 新規プロジェクトを端末内に保存しました', 'success');
    } else if (AUTOSAVE_SUPPORTED) {
      scheduleAutosaveSnapshot();
      updateAutosaveStatus('自動保存: 新規プロジェクトの即時保存に失敗したため再試行します', 'warn');
    } else {
      updateAutosaveStatus('自動保存: このブラウザでは利用できません', 'warn');
    }
    scheduleSessionPersist();
    return true;
  }

  function createStartupQuickProjectName() {
    const now = new Date();
    const yyyy = String(now.getFullYear());
    const mm = String(now.getMonth() + 1).padStart(2, '0');
    const dd = String(now.getDate()).padStart(2, '0');
    const hh = String(now.getHours()).padStart(2, '0');
    const mi = String(now.getMinutes()).padStart(2, '0');
    return normalizeDocumentName(`${DEFAULT_DOCUMENT_BASENAME}_${yyyy}${mm}${dd}_${hh}${mi}`);
  }

  function setStartupQuickSetupStatus(message, tone = 'info') {
    const node = dom.startup?.quickSetupStatus;
    if (!(node instanceof HTMLElement)) {
      return;
    }
    node.textContent = message;
    if (tone && tone !== 'info') {
      node.dataset.tone = tone;
    } else {
      delete node.dataset.tone;
    }
  }

  async function runStartupQuickSetup() {
    const quickButton = dom.startup?.quickSetupButton;
    if (!(quickButton instanceof HTMLButtonElement) || quickButton.disabled) {
      return;
    }
    quickButton.disabled = true;
    quickButton.setAttribute('aria-busy', 'true');
    try {
      setStartupQuickSetupStatus(localizeText('かんたん初期設定: 新規作成を準備しています…', 'Quick setup: preparing a new project...'));
      const created = await createNewProject({
        name: createStartupQuickProjectName(),
        width: lockedCanvasWidth !== null ? lockedCanvasWidth : DEFAULT_CANVAS_SIZE,
        height: lockedCanvasHeight !== null ? lockedCanvasHeight : DEFAULT_CANVAS_SIZE,
        promptExportDirectory: true,
      });
      if (!created) {
        setStartupQuickSetupStatus(localizeText('かんたん初期設定に失敗しました。通常の「新規作成」をお試しください。', 'Quick setup failed. Please try "New Project".'), 'error');
        return;
      }
      setStartupQuickSetupStatus(localizeText('かんたん初期設定が完了しました。', 'Quick setup completed.'), 'success');
      hideStartupScreen();
    } catch (error) {
      console.warn('Startup quick setup failed', error);
      setStartupQuickSetupStatus(localizeText('かんたん初期設定に失敗しました。通常の「新規作成」をお試しください。', 'Quick setup failed. Please try "New Project".'), 'error');
    } finally {
      quickButton.removeAttribute('aria-busy');
      quickButton.disabled = false;
    }
  }

  function hasDismissedStartupScreen() {
    if (!canUseSessionStorage) {
      return false;
    }
    try {
      return window.localStorage.getItem(STARTUP_SCREEN_DISMISSED_KEY) === '1';
    } catch (error) {
      return false;
    }
  }

  function markStartupScreenDismissed() {
    if (!canUseSessionStorage) {
      return;
    }
    try {
      window.localStorage.setItem(STARTUP_SCREEN_DISMISSED_KEY, '1');
    } catch (error) {
      // Ignore storage errors (private mode or quota exceeded)
    }
  }

  function showStartupScreen() {
    const container = dom.startup?.screen;
    if (!container) {
      return;
    }
    if (AUTOSAVE_SUPPORTED) {
      refreshRecentProjectsUI().catch(error => {
        console.warn('Failed to refresh recent projects', error);
      });
    } else if (dom.startup?.recentSection) {
      dom.startup.recentSection.hidden = true;
    }
    if (startupVisible) {
      return;
    }
    startupVirtualCursorState = state.showVirtualCursor;
    if (state.showVirtualCursor) {
      setVirtualCursorEnabled(false, { persist: false });
    }
    startupVisible = true;
    container.hidden = false;
    container.setAttribute('aria-hidden', 'false');
    document.body.classList.add('is-startup-active');
    window.requestAnimationFrame(() => {
      container.focus?.({ preventScroll: true });
      const startupTargets = [
        dom.startup?.resumeButton,
        dom.startup?.newButton,
        dom.startup?.openButton,
        dom.startup?.skipButton,
      ];
      const defaultTarget = startupTargets.find(target => target instanceof HTMLElement && !target.hasAttribute('disabled')) || container;
      defaultTarget?.focus?.({ preventScroll: true });
    });
  }

  function hideStartupScreen() {
    const container = dom.startup?.screen;
    if (!container || !startupVisible) {
      return;
    }
    markStartupScreenDismissed();
    startupVisible = false;
    container.hidden = true;
    container.setAttribute('aria-hidden', 'true');
    document.body.classList.remove('is-startup-active');
    if (startupVirtualCursorState === true) {
      setVirtualCursorEnabled(true, { persist: false });
    }
    startupVirtualCursorState = null;
    if (lensImportRequested) {
      window.history.replaceState({}, document.title, window.location.href);
      lensImportRequested = false;
    }
  }

  function hasSeenUpdateToast(updateId = '') {
    if (!canUseSessionStorage) {
      return false;
    }
    const normalizedUpdateId = typeof updateId === 'string' ? updateId.trim() : '';
    if (!normalizedUpdateId) {
      return false;
    }
    try {
      if (window.localStorage.getItem(`${UPDATE_TOAST_SEEN_PREFIX}${normalizedUpdateId}`) === '1') {
        return true;
      }
      return window.localStorage.getItem(STARTUP_UPDATE_TOAST_HIDDEN_KEY) === normalizedUpdateId;
    } catch (error) {
      return false;
    }
  }

  function markUpdateToastSeen(updateId = '') {
    if (!canUseSessionStorage) {
      return;
    }
    const normalizedUpdateId = typeof updateId === 'string' ? updateId.trim() : '';
    if (!normalizedUpdateId) {
      return;
    }
    try {
      window.localStorage.setItem(`${UPDATE_TOAST_SEEN_PREFIX}${normalizedUpdateId}`, '1');
      window.localStorage.setItem(STARTUP_UPDATE_TOAST_HIDDEN_KEY, normalizedUpdateId);
    } catch (error) {
      // Ignore localStorage errors.
    }
  }

  function setUpdateToastVisibility(visible, { markSeen = false } = {}) {
    const updateToast = dom.startup?.updateToast;
    if (!updateToast) {
      return;
    }
    const shouldShow = Boolean(visible);
    updateToast.hidden = !shouldShow;
    updateToast.setAttribute('aria-hidden', shouldShow ? 'false' : 'true');
    if (shouldShow && markSeen) {
      markUpdateToastSeen(updateToast.dataset.updateId || '');
    }
  }

  function showUpdateToast({ manual = false } = {}) {
    setUpdateToastVisibility(true, { markSeen: !manual });
  }

  function hideUpdateToast() {
    setUpdateToastVisibility(false);
  }

  function setupStartupScreen() {
    const container = dom.startup?.screen;
    if (!container) {
      return;
    }
    getUpdateHistoryEntries();
    if (dom.startup?.hint) {
      dom.startup.hint.textContent = AUTOSAVE_SUPPORTED
        ? localizeText(
          '描画内容はこの端末に自動保存され、起動時に前回データを復元できます。',
          'Your drawing is autosaved on this device and restored when you reopen.'
        )
        : localizeText(
          'このブラウザでは自動保存が利用できません。保存/出力から手動保存してください。',
          'Autosave is not available in this browser. Please save manually from Save / Export.'
        );
    }
    if (dom.startup?.quickSetupButton instanceof HTMLButtonElement) {
      if (AUTOSAVE_SUPPORTED) {
        dom.startup.quickSetupButton.textContent = localizeText('新規作成（かんたん開始）', 'New Project (Quick Start)');
        setStartupQuickSetupStatus(localizeText('新規作成すると、この端末に自動保存を開始します。', 'Creating a new project starts autosave on this device.'));
      } else {
        dom.startup.quickSetupButton.textContent = localizeText('新規作成（かんたん開始）', 'New Project (Quick Start)');
        setStartupQuickSetupStatus(
          localizeText(
            'このブラウザは自動保存未対応です。開始後は「保存/出力」から書き出してください。',
            'This browser does not support autosave. Please export manually after starting.'
          ),
          'warn'
        );
      }
    }
    const updateToast = dom.startup?.updateToast;
    if (updateToast) {
      const updateId = updateToast.dataset.updateId || '';
      const seen = hasSeenUpdateToast(updateId);
      if (seen) {
        hideUpdateToast();
      } else {
        showUpdateToast();
      }
    }
    dom.startup?.updateToastCloseButton?.addEventListener('click', () => {
      hideUpdateToast();
    });
    container.addEventListener('keydown', event => {
      if (!startupVisible) {
        return;
      }
      if (event.key === 'Escape') {
        event.preventDefault();
        hideStartupScreen();
        return;
      }
      if (event.key === 'Tab') {
        const focusableSelectors = 'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])';
        const focusableElements = Array.from(container.querySelectorAll(focusableSelectors))
          .filter(element => !element.hasAttribute('disabled') && element.offsetParent !== null);
        if (!focusableElements.length) {
          event.preventDefault();
          container.focus();
          return;
        }
        const first = focusableElements[0];
        const last = focusableElements[focusableElements.length - 1];
        if (event.shiftKey) {
          if (document.activeElement === first || document.activeElement === container) {
            event.preventDefault();
            last.focus();
          }
        } else if (document.activeElement === last) {
          event.preventDefault();
          first.focus();
        }
      }
    });
    dom.startup?.newButton?.addEventListener('click', () => {
      hideStartupScreen();
      openNewProjectDialog();
    });
    dom.startup?.resumeButton?.addEventListener('click', async () => {
      const firstEntry = Array.from(recentProjectsCache.values())[0] || null;
      if (!firstEntry) {
        updateAutosaveStatus(
          localizeText(
            '端末内プロジェクトがありません。新規作成またはファイルを開いてください。',
            'No local project found. Create a new one or open a file.'
          ),
          'warn'
        );
        return;
      }
      const opened = await openRecentProjectAsTab(firstEntry, { hideStartup: true });
      if (!opened) {
        refreshRecentProjectsUI().catch(error => {
          console.warn('Failed to refresh recent projects', error);
        });
      }
    });
    dom.startup?.openButton?.addEventListener('click', async () => {
      const opened = await openDocumentDialog();
      if (opened) {
        hideStartupScreen();
      }
    });
    dom.startup?.quickSetupButton?.addEventListener('click', async () => {
      await runStartupQuickSetup();
    });
    dom.startup?.skipButton?.addEventListener('click', () => {
      hideStartupScreen();
    });
    dom.startup?.recentList?.addEventListener('click', async event => {
      const target = event.target instanceof Element ? event.target : null;
      if (!target) {
        return;
      }
      const deleteButton = target.closest('button[data-startup-recent-delete-id]');
      if (deleteButton instanceof HTMLButtonElement) {
        event.preventDefault();
        event.stopPropagation();
        const projectId = deleteButton.dataset.startupRecentDeleteId || '';
        if (!projectId) {
          return;
        }
        const entry = recentProjectsCache.get(projectId) || null;
        const displayLabel = extractDocumentBaseName(entry?.fileName || entry?.name || DEFAULT_DOCUMENT_NAME);
        const accepted = window.confirm(
          localizeText(
            `端末内プロジェクト「${displayLabel}」を削除しますか？\nこの操作は取り消せません。`,
            `Delete local project "${displayLabel}"?\nThis action cannot be undone.`
          )
        );
        if (!accepted) {
          return;
        }
        const card = deleteButton.closest('.startup-recent-card');
        const openButton = card instanceof HTMLElement
          ? card.querySelector('button[data-startup-recent-open-id]')
          : null;
        deleteButton.disabled = true;
        if (openButton instanceof HTMLButtonElement) {
          openButton.disabled = true;
        }
        try {
          const removed = await removeRecentProjectEntry(projectId);
          if (removed) {
            releaseAutosaveProjectId(projectId);
            updateAutosaveStatus(
              localizeText(
                `端末内プロジェクトを削除しました (${displayLabel})`,
                `Deleted local project (${displayLabel})`
              ),
              'info'
            );
          } else if (AUTOSAVE_SUPPORTED) {
            refreshRecentProjectsUI().catch(error => {
              console.warn('Failed to refresh recent projects', error);
            });
          }
        } catch (error) {
          console.warn('Failed to remove recent project', error);
          updateAutosaveStatus(
            localizeText(
              '端末内プロジェクトを削除できませんでした',
              'Failed to delete local project'
            ),
            'error'
          );
          deleteButton.disabled = false;
          if (openButton instanceof HTMLButtonElement) {
            openButton.disabled = false;
          }
        }
        return;
      }

      const openButton = target.closest('button[data-startup-recent-open-id]');
      if (!(openButton instanceof HTMLButtonElement)) {
        return;
      }
      const projectId = openButton.dataset.startupRecentOpenId || '';
      const entry = projectId ? recentProjectsCache.get(projectId) : null;
      if (!entry) {
        if (AUTOSAVE_SUPPORTED) {
          refreshRecentProjectsUI().catch(error => {
            console.warn('Failed to refresh recent projects', error);
          });
        }
        return;
      }
      openButton.disabled = true;
      const success = await openRecentProjectAsTab(entry, { hideStartup: true });
      if (!success) {
        openButton.disabled = false;
      }
    });
    if (AUTOSAVE_SUPPORTED) {
      refreshRecentProjectsUI().catch(error => {
        console.warn('Failed to refresh recent projects', error);
      });
      syncStartupResumeState(Array.from(recentProjectsCache.values()));
    } else if (dom.startup?.recentSection) {
      dom.startup.recentSection.hidden = true;
      syncStartupResumeState([]);
    }
  }

  async function loadDocumentFromHandle(handle, options = {}) {
    try {
      const file = await handle.getFile();
      if (isImportableImageFile(file)) {
        return await loadDocumentFromImageFile(file);
      }
      const text = await file.text();
      return await loadDocumentFromText(text, handle, options);
    } catch (error) {
      if (error?.name !== 'NotAllowedError') {
        console.warn('Document handle load failed', error);
      }
      const message = error && error.name === 'AbortError'
        ? null
        : (
          error?.name === 'NotAllowedError'
            ? 'この端末では旧ファイル権限が無効です。端末内プロジェクトから開いてください。'
            : (error?.source === 'image-import' ? '画像の読み込みに失敗しました' : 'ドキュメントを開けませんでした')
        );
      if (message) {
        updateAutosaveStatus(message, 'error');
      }
      return false;
    }
  }

  async function loadDocumentFromText(text, handle, options = {}) {
    if (!ensureCurrentClientCanReplaceActiveProject({ announce: !options?.suppressAutosaveStatus })) {
      return false;
    }
    let parsedDocument = null;
    try {
      parsedDocument = snapshotFromDocumentText(text);
    } catch (error) {
      console.warn('Failed to parse document', error);
      updateAutosaveStatus('ドキュメントの読み込みに失敗しました', 'error');
      return false;
    }
    const snapshot = parsedDocument?.snapshot || null;
    const projectSession = parsedDocument?.projectSession || null;
    const preserveDotStats = Boolean(options?.projectId || options?.openedFromRecent || options?.preserveDotStats);
    const dotStats = preserveDotStats ? (parsedDocument?.dotStats || null) : null;
    if (!snapshot) {
      updateAutosaveStatus('ドキュメントの読み込みに失敗しました', 'error');
      return false;
    }
    synchronizeImportedSnapshotPalette(snapshot);

    autosaveRestoring = true;
    try {
      applyHistorySnapshot(snapshot, { forcePalettePresetSync: true });
      history.pending = null;
      if (projectSession) {
        history.limit = projectSession.historyLimit;
        history.past = projectSession.historyPast;
        history.future = projectSession.historyFuture;

        if (!(timelapseState.snapshots instanceof Array)) {
          timelapseState.snapshots = [];
        }
        timelapseState.snapshots.length = 0;
        projectSession.timelapse.snapshots.forEach(entry => {
          timelapseState.snapshots.push(entry);
        });
        timelapseState.enabled = projectSession.timelapse.enabled;
        timelapseState.fps = projectSession.timelapse.fps;
        timelapseState.warningShown = projectSession.timelapse.warningShown;
        timelapseState.sampleStep = projectSession.timelapse.sampleStep;
        timelapseState.lastCaptureToken = projectSession.timelapse.lastCaptureToken;
      } else {
        history.past = [];
        history.future = [];
        clearTimelapseRecording({ silent: true });
      }
    } finally {
      autosaveRestoring = false;
    }
    syncTimelapseControls();
    updateHistoryButtons();
    updateMemoryStatus();
    resetDocumentUnsavedChanges();
    resetExportScaleDefaults();
    syncPixfindSnapshotAfterDocumentReset();
    setTrackedProjectDotBaseline(snapshot, dotStats);

    const requestedProjectId = normalizeAutosaveProjectId(options?.projectId || '');
    setActiveAutosaveProjectId(requestedProjectId || createAutosaveProjectId());
    markAutosaveDirty();
    scheduleSessionPersist();
    scheduleAutosaveSnapshot();
    if (!options?.suppressAutosaveStatus) {
      if (options?.openedFromRecent) {
        updateAutosaveStatus('自動保存: 端末内プロジェクトを読み込みました', 'success');
      } else {
        updateAutosaveStatus('自動保存: 読み込み内容を端末内に保存します', 'info');
      }
    }
    return true;
  }

  function normalizeProjectHistoryLimit(value, fallback = history.limit) {
    const fallbackLimit = Math.max(
      MIN_HISTORY_LIMIT,
      Math.round(Number(fallback) || DEFAULT_HISTORY_LIMIT)
    );
    const parsed = Math.round(Number(value));
    if (!Number.isFinite(parsed)) {
      return fallbackLimit;
    }
    return Math.max(MIN_HISTORY_LIMIT, parsed);
  }

  function serializeProjectHistorySnapshot(entry) {
    if (!entry || typeof entry !== 'object') {
      return null;
    }
    let snapshot = null;
    try {
      snapshot = decompressHistorySnapshot(entry);
    } catch (error) {
      return null;
    }
    try {
      return serializeDocumentSnapshot(snapshot);
    } catch (error) {
      return null;
    }
  }

  function serializeProjectHistoryList(list, historyLimit) {
    if (!Array.isArray(list) || !list.length) {
      return [];
    }
    const safeLimit = normalizeProjectHistoryLimit(historyLimit, history.limit);
    const serialized = [];
    for (let index = 0; index < list.length; index += 1) {
      const payload = serializeProjectHistorySnapshot(list[index]);
      if (payload) {
        serialized.push(payload);
      }
    }
    if (serialized.length > safeLimit) {
      return serialized.slice(serialized.length - safeLimit);
    }
    return serialized;
  }

  function serializeProjectTimelapseSnapshots() {
    flushPendingTimelapseCapture({ force: true });
    if (!Array.isArray(timelapseState.snapshots) || !timelapseState.snapshots.length) {
      return [];
    }
    const snapshots = [];
    timelapseState.snapshots.forEach(entry => {
      const resolved = resolveTimelapseFrameEntry(entry);
      if (!resolved) {
        return;
      }
      snapshots.push({
        width: resolved.width,
        height: resolved.height,
        pixels: encodeTypedArray(resolved.pixels),
      });
    });
    return snapshots;
  }

  function buildProjectSessionPayload() {
    const historyLimit = normalizeProjectHistoryLimit(history.limit, DEFAULT_HISTORY_LIMIT);
    return {
      historyLimit,
      historyPast: serializeProjectHistoryList(history.past, historyLimit),
      historyFuture: serializeProjectHistoryList(history.future, historyLimit),
      timelapse: {
        enabled: Boolean(timelapseState.enabled),
        fps: normalizeTimelapseFps(timelapseState.fps),
        warningShown: Boolean(timelapseState.warningShown),
        sampleStep: Math.max(1, Math.round(Number(timelapseState.sampleStep) || 1)),
        lastCaptureToken: Number.isFinite(Number(timelapseState.lastCaptureToken))
          ? Math.round(Number(timelapseState.lastCaptureToken))
          : -1,
        snapshots: serializeProjectTimelapseSnapshots(),
      },
    };
  }

  function buildAutosaveSessionPayload() {
    return {
      historyLimit: normalizeProjectHistoryLimit(history.limit, DEFAULT_HISTORY_LIMIT),
      historyPast: [],
      historyFuture: [],
      timelapse: {
        enabled: Boolean(timelapseState.enabled),
        fps: normalizeTimelapseFps(timelapseState.fps),
        warningShown: Boolean(timelapseState.warningShown),
        sampleStep: Math.max(1, Math.round(Number(timelapseState.sampleStep) || 1)),
        lastCaptureToken: Number.isFinite(Number(timelapseState.lastCaptureToken))
          ? Math.round(Number(timelapseState.lastCaptureToken))
          : -1,
        // Persist timelapse frames in autosave as well so reopening can export
        // from the original drawing start, not just after reopening.
        snapshots: serializeProjectTimelapseSnapshots(),
      },
    };
  }

  function deserializeProjectHistoryList(list, historyLimit) {
    if (!Array.isArray(list) || !list.length) {
      return [];
    }
    const safeLimit = normalizeProjectHistoryLimit(historyLimit, history.limit);
    const restored = [];
    for (let index = 0; index < list.length; index += 1) {
      const payload = list[index];
      if (!payload || typeof payload !== 'object') {
        continue;
      }
      try {
        const snapshot = deserializeDocumentPayload(payload);
        synchronizeImportedSnapshotPalette(snapshot);
        restored.push(compressHistorySnapshot(snapshot));
      } catch (error) {
        // Ignore invalid history entries.
      }
    }
    if (restored.length > safeLimit) {
      return restored.slice(restored.length - safeLimit);
    }
    return restored;
  }

  function deserializeProjectTimelapseSnapshots(list) {
    if (!Array.isArray(list) || !list.length) {
      return [];
    }
    const restored = [];
    for (let index = 0; index < list.length; index += 1) {
      const entry = list[index];
      if (!entry || typeof entry !== 'object') {
        continue;
      }
      const width = Math.max(1, Math.floor(Number(entry.width) || 0));
      const height = Math.max(1, Math.floor(Number(entry.height) || 0));
      if (!width || !height || typeof entry.pixels !== 'string' || !entry.pixels.length) {
        continue;
      }
      try {
        const raw = decodeBase64(entry.pixels);
        if (raw.length !== width * height * 4) {
          continue;
        }
        const pixels = new Uint8ClampedArray(raw.length);
        pixels.set(raw);
        restored.push({
          width,
          height,
          pixels: compressUint8Array(pixels, { clamped: true }),
        });
      } catch (error) {
        // Ignore invalid timelapse entries.
      }
    }
    return restored;
  }

  function parseProjectSessionPayload(payload) {
    if (!payload || typeof payload !== 'object') {
      return null;
    }
    const historyLimit = normalizeProjectHistoryLimit(payload.historyLimit, history.limit);
    const historyPast = deserializeProjectHistoryList(payload.historyPast, historyLimit);
    const historyFuture = deserializeProjectHistoryList(payload.historyFuture, historyLimit);
    const timelapsePayload = payload.timelapse && typeof payload.timelapse === 'object'
      ? payload.timelapse
      : {};
    const timelapseSnapshots = deserializeProjectTimelapseSnapshots(timelapsePayload.snapshots);
    return {
      historyLimit,
      historyPast,
      historyFuture,
      timelapse: {
        enabled: Boolean(timelapsePayload.enabled),
        fps: normalizeTimelapseFps(timelapsePayload.fps),
        warningShown: Boolean(timelapsePayload.warningShown),
        sampleStep: Math.max(1, Math.round(Number(timelapsePayload.sampleStep) || 1)),
        lastCaptureToken: Number.isFinite(Number(timelapsePayload.lastCaptureToken))
          ? Math.round(Number(timelapsePayload.lastCaptureToken))
          : -1,
        snapshots: timelapseSnapshots,
      },
    };
  }

  function snapshotFromDocumentText(text) {
    if (!text || typeof text !== 'string') {
      throw new Error('Document text is empty');
    }
    const parsed = JSON.parse(text);
    const hasPackagedDocument = Boolean(parsed && typeof parsed === 'object' && parsed.document && typeof parsed.document === 'object');
    const payload = hasPackagedDocument ? parsed.document : parsed;
    const snapshot = deserializeDocumentPayload(payload);
    const projectSession = hasPackagedDocument
      ? parseProjectSessionPayload(parsed.session)
      : null;
    const dotStats = hasPackagedDocument
      ? resolvePackagedProjectDotStats(parsed)
      : null;
    return {
      snapshot,
      projectSession,
      dotStats,
    };
  }

  function normalizeAutosaveProjectId(value) {
    if (typeof value !== 'string') {
      return '';
    }
    const trimmed = value.trim();
    return trimmed || '';
  }

  function createAutosaveProjectId() {
    if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
      return `local-${crypto.randomUUID()}`;
    }
    return `local-${Date.now().toString(36)}-${Math.floor(Math.random() * 1e9).toString(36)}`;
  }

  async function storeAutosaveProjectId(projectId) {
    if (!AUTOSAVE_SUPPORTED) return;
    const normalizedId = normalizeAutosaveProjectId(projectId);
    try {
      const db = await openAutosaveDatabase();
      await new Promise((resolve, reject) => {
        const tx = db.transaction([AUTOSAVE_STORE_NAME], 'readwrite');
        const store = tx.objectStore(AUTOSAVE_STORE_NAME);
        const request = normalizedId
          ? store.put(normalizedId, AUTOSAVE_ACTIVE_PROJECT_KEY)
          : store.delete(AUTOSAVE_ACTIVE_PROJECT_KEY);
        request.onerror = () => reject(request.error);
        tx.oncomplete = () => {
          db.close();
          resolve();
        };
        tx.onerror = () => {
          const error = tx.error;
          db.close();
          reject(error);
        };
      });
    } catch (error) {
      console.warn('Failed to store autosave project id', error);
    }
  }

  async function loadStoredAutosaveProjectId() {
    if (!AUTOSAVE_SUPPORTED) return '';
    try {
      const db = await openAutosaveDatabase();
      return await new Promise((resolve, reject) => {
        let value = '';
        const tx = db.transaction([AUTOSAVE_STORE_NAME], 'readonly');
        const store = tx.objectStore(AUTOSAVE_STORE_NAME);
        const request = store.get(AUTOSAVE_ACTIVE_PROJECT_KEY);
        request.onsuccess = () => {
          value = normalizeAutosaveProjectId(request.result || '');
        };
        request.onerror = () => {
          reject(request.error);
        };
        tx.oncomplete = () => {
          db.close();
          resolve(value);
        };
        tx.onerror = () => {
          const error = tx.error;
          db.close();
          reject(error);
        };
      });
    } catch (error) {
      console.warn('Failed to load autosave project id', error);
      return '';
    }
  }

  function setActiveAutosaveProjectId(projectId, { persist = true } = {}) {
    const normalizedId = normalizeAutosaveProjectId(projectId) || createAutosaveProjectId();
    const changed = autosaveProjectId !== normalizedId;
    autosaveProjectId = normalizedId;
    if (persist && changed) {
      storeAutosaveProjectId(normalizedId).catch(error => {
        console.warn('Failed to persist autosave project id', error);
      });
    }
    return normalizedId;
  }

  async function ensureActiveAutosaveProjectId(preferredId = '') {
    const preferred = normalizeAutosaveProjectId(preferredId);
    if (preferred) {
      return setActiveAutosaveProjectId(preferred);
    }
    if (autosaveProjectId) {
      return autosaveProjectId;
    }
    const stored = await loadStoredAutosaveProjectId();
    if (stored) {
      autosaveProjectId = stored;
      return stored;
    }
    return setActiveAutosaveProjectId(createAutosaveProjectId());
  }

  async function storeAutosaveHandle(handle) {
    if (!FILE_HANDLE_AUTOSAVE_SUPPORTED) return;
    try {
      const db = await openAutosaveDatabase();
      await new Promise((resolve, reject) => {
        const tx = db.transaction([AUTOSAVE_STORE_NAME], 'readwrite');
        const store = tx.objectStore(AUTOSAVE_STORE_NAME);
        const request = store.put(handle, AUTOSAVE_HANDLE_KEY);
        request.onerror = () => reject(request.error);
        tx.oncomplete = () => {
          db.close();
          resolve();
        };
        tx.onerror = () => {
          const error = tx.error;
          db.close();
          reject(error);
        };
      });
    } catch (error) {
      console.warn('Failed to store autosave handle', error);
    }
  }

  async function loadStoredAutosaveHandle() {
    if (!FILE_HANDLE_AUTOSAVE_SUPPORTED) return null;
    try {
      const db = await openAutosaveDatabase();
      return await new Promise((resolve, reject) => {
        let value = null;
        const tx = db.transaction([AUTOSAVE_STORE_NAME], 'readonly');
        const store = tx.objectStore(AUTOSAVE_STORE_NAME);
        const request = store.get(AUTOSAVE_HANDLE_KEY);
        request.onsuccess = () => {
          value = request.result || null;
        };
        request.onerror = () => {
          reject(request.error);
        };
        tx.oncomplete = () => {
          db.close();
          resolve(value);
        };
        tx.onerror = () => {
          const error = tx.error;
          db.close();
          reject(error);
        };
      });
    } catch (error) {
      console.warn('Autosave handle load failed', error);
      return null;
    }
  }

