  async function loadRecentProjectsMetadata() {
    if (!AUTOSAVE_SUPPORTED) return [];
    try {
      const db = await openAutosaveDatabase();
      return await new Promise((resolve, reject) => {
        let entries = [];
        const tx = db.transaction([RECENT_PROJECTS_STORE], 'readonly');
        const store = tx.objectStore(RECENT_PROJECTS_STORE);
        const request = store.getAll();
        request.onsuccess = () => {
          entries = Array.isArray(request.result) ? request.result.slice() : [];
        };
        request.onerror = () => {
          reject(request.error);
        };
        tx.oncomplete = () => {
          db.close();
          entries.sort((a, b) => {
            const aTime = typeof a?.updatedAt === 'string' ? a.updatedAt : '';
            const bTime = typeof b?.updatedAt === 'string' ? b.updatedAt : '';
            return bTime.localeCompare(aTime);
          });
          resolve(entries);
        };
        tx.onerror = () => {
          const error = tx.error;
          db.close();
          reject(error);
        };
      });
    } catch (error) {
      console.warn('Failed to load recent projects', error);
      return [];
    }
  }

  async function saveRecentProjectsList(existingEntries, nextEntries) {
    if (!AUTOSAVE_SUPPORTED) return;
    const existingIds = new Set((existingEntries || []).map(entry => entry?.id).filter(Boolean));
    const nextIds = new Set((nextEntries || []).map(entry => entry?.id).filter(Boolean));
    try {
      const db = await openAutosaveDatabase();
      await new Promise((resolve, reject) => {
        const tx = db.transaction([RECENT_PROJECTS_STORE], 'readwrite');
        const store = tx.objectStore(RECENT_PROJECTS_STORE);
        (nextEntries || []).forEach(entry => {
          if (!entry || !entry.id) {
            return;
          }
          store.put(entry, entry.id);
        });
        existingIds.forEach(id => {
          if (!nextIds.has(id)) {
            store.delete(id);
          }
        });
        tx.oncomplete = () => {
          db.close();
          resolve();
        };
        tx.onerror = () => {
          const error = tx.error;
          db.close();
          reject(error);
        };
      });
    } catch (error) {
      console.warn('Failed to update recent projects', error);
    }
  }

  async function sanitizeRecentProjectsStore({ announce = false } = {}) {
    if (!AUTOSAVE_SUPPORTED) {
      return { entries: [], changed: false, removedCount: 0, repairedCount: 0 };
    }
    const existingEntries = await loadRecentProjectsMetadata();
    const sanitizedEntries = [];
    const seenIds = new Set();
    let changed = false;
    let removedCount = 0;
    let repairedCount = 0;
    const nowIso = new Date().toISOString();

    for (let index = 0; index < existingEntries.length; index += 1) {
      const original = existingEntries[index];
      if (!original || typeof original !== 'object') {
        changed = true;
        removedCount += 1;
        continue;
      }
      const normalizedId = normalizeAutosaveProjectId(original.id || '');
      if (!normalizedId || seenIds.has(normalizedId)) {
        changed = true;
        removedCount += 1;
        continue;
      }

      const hasProjectPayload = Boolean(original.project && typeof original.project === 'object');
      if (!hasProjectPayload) {
        changed = true;
        removedCount += 1;
        continue;
      }

      const nextEntry = { ...original, id: normalizedId };
      let entryChanged = original.id !== normalizedId;
      let parsedSnapshot = null;

      try {
        const parsed = snapshotFromDocumentText(JSON.stringify(original.project));
        parsedSnapshot = parsed?.snapshot || null;
        if (!parsedSnapshot) {
          throw new Error('Snapshot missing in stored project payload');
        }
      } catch (error) {
        changed = true;
        removedCount += 1;
        continue;
      }

      const fallbackFileName = normalizeDocumentName(
        parsedSnapshot?.documentName
        || original.fileName
        || original.name
        || DEFAULT_DOCUMENT_NAME
      );
      if (nextEntry.fileName !== fallbackFileName) {
        nextEntry.fileName = fallbackFileName;
        entryChanged = true;
      }
      const fallbackName = extractDocumentBaseName(fallbackFileName);
      if (nextEntry.name !== fallbackName) {
        nextEntry.name = fallbackName;
        entryChanged = true;
      }
      const parsedUpdatedAt = Date.parse(typeof original.updatedAt === 'string' ? original.updatedAt : '');
      if (!Number.isFinite(parsedUpdatedAt)) {
        nextEntry.updatedAt = nowIso;
        entryChanged = true;
      }
      if (typeof nextEntry.thumbnail !== 'string' || nextEntry.thumbnail.length <= 0) {
        if (nextEntry.thumbnail !== null) {
          nextEntry.thumbnail = null;
          entryChanged = true;
        }
      }
      if (Object.prototype.hasOwnProperty.call(nextEntry, 'handle')) {
        delete nextEntry.handle;
        entryChanged = true;
      }
      seenIds.add(normalizedId);
      if (entryChanged) {
        changed = true;
        repairedCount += 1;
      }
      sanitizedEntries.push(nextEntry);
    }

    sanitizedEntries.sort((a, b) => {
      const aTime = typeof a?.updatedAt === 'string' ? a.updatedAt : '';
      const bTime = typeof b?.updatedAt === 'string' ? b.updatedAt : '';
      return bTime.localeCompare(aTime);
    });
    const limitedEntries = sanitizedEntries.slice(0, RECENT_PROJECT_LIMIT);
    if (limitedEntries.length !== existingEntries.length) {
      changed = true;
    }

    if (changed) {
      await saveRecentProjectsList(existingEntries, limitedEntries);
    }
    setRecentProjectsCache(changed ? limitedEntries : existingEntries);
    if (announce && (removedCount > 0 || repairedCount > 0)) {
      updateAutosaveStatus(
        `端末内プロジェクトを整理しました（修復 ${repairedCount} / 除外 ${removedCount}）`,
        removedCount > 0 ? 'warn' : 'info'
      );
    }
    return {
      entries: changed ? limitedEntries : existingEntries,
      changed,
      removedCount,
      repairedCount,
    };
  }

  async function removeRecentProjectEntry(projectId, { announce = false, reason = '' } = {}) {
    if (!AUTOSAVE_SUPPORTED) return false;
    const normalizedId = normalizeAutosaveProjectId(projectId || '');
    if (!normalizedId) return false;
    const existingEntries = await loadRecentProjectsMetadata();
    const nextEntries = existingEntries.filter(entry => entry?.id !== normalizedId);
    if (nextEntries.length === existingEntries.length) {
      return false;
    }
    await saveRecentProjectsList(existingEntries, nextEntries);
    setRecentProjectsCache(nextEntries);
    if (announce) {
      const reasonSuffix = reason ? `（${reason}）` : '';
      updateAutosaveStatus(`読込できない端末内プロジェクトを除外しました${reasonSuffix}`, 'warn');
    }
    return true;
  }

  function setRecentProjectsCache(entries) {
    recentProjectsCache.clear();
    if (Array.isArray(entries)) {
      entries.forEach(entry => {
        if (entry && entry.id) {
          recentProjectsCache.set(entry.id, entry);
        }
      });
    }
    syncStartupResumeState(entries || []);
    renderRecentProjectsList(entries || []);
  }

  function syncStartupResumeState(entries = []) {
    const resumeButton = dom.startup?.resumeButton;
    const resumeHint = dom.startup?.resumeHint;
    if (!(resumeButton instanceof HTMLButtonElement)) {
      if (resumeHint instanceof HTMLElement) {
        resumeHint.textContent = '';
      }
      return;
    }
    const firstEntry = Array.isArray(entries) && entries.length ? entries[0] : null;
    if (!firstEntry || !firstEntry.id) {
      resumeButton.disabled = true;
      if (resumeHint instanceof HTMLElement) {
        resumeHint.textContent = localizeText(
          'まだ保存データがありません。まずは新規作成またはファイルを開いてください。',
          'No saved data yet. Create a new project or open a file.'
        );
      }
      return;
    }
    resumeButton.disabled = false;
    const displayLabel = firstEntry.fileName || firstEntry.name || DEFAULT_DOCUMENT_NAME;
    const updatedAt = Date.parse(firstEntry.updatedAt || '');
    const atLabel = Number.isFinite(updatedAt)
      ? formatUpdateHistoryDate(updatedAt, '')
      : '';
    if (resumeHint instanceof HTMLElement) {
      resumeHint.textContent = atLabel
        ? localizeText(`最近: ${displayLabel}（${atLabel}）`, `Recent: ${displayLabel} (${atLabel})`)
        : localizeText(`最近: ${displayLabel}`, `Recent: ${displayLabel}`);
    }
  }

  function renderRecentProjectsList(entries) {
    const section = dom.startup?.recentSection;
    const list = dom.startup?.recentList;
    if (!section || !list) {
      return;
    }
    list.innerHTML = '';
    if (!AUTOSAVE_SUPPORTED || !entries || entries.length === 0) {
      section.hidden = true;
      return;
    }
    section.hidden = false;
    entries.forEach(entry => {
      if (!entry || !entry.id) {
        return;
      }
      const displayLabel = entry.fileName || entry.name || DEFAULT_DOCUMENT_NAME;
      const card = document.createElement('article');
      card.className = 'startup-recent-card';
      card.dataset.projectId = entry.id;
      card.setAttribute('role', 'listitem');
      const openButton = document.createElement('button');
      openButton.type = 'button';
      openButton.className = 'startup-recent-card__open';
      openButton.dataset.startupRecentOpenId = entry.id;
      openButton.setAttribute('aria-label', localizeText(`${displayLabel} を開く`, `Open ${displayLabel}`));
      const thumb = document.createElement('div');
      thumb.className = 'startup-recent-card__thumb';
      if (entry.thumbnail) {
        const img = new Image();
        img.src = entry.thumbnail;
        img.alt = localizeText(
          `${entry.fileName || entry.name || 'プロジェクト'} のプレビュー`,
          `${entry.fileName || entry.name || 'Project'} preview`
        );
        img.decoding = 'async';
        thumb.appendChild(img);
      } else {
        const placeholder = document.createElement('span');
        placeholder.className = 'startup-recent-card__thumb-placeholder';
        placeholder.textContent = localizeText('プレビューなし', 'No Preview');
        thumb.appendChild(placeholder);
      }
      const nameNode = document.createElement('span');
      nameNode.className = 'startup-recent-card__name';
      nameNode.textContent = displayLabel;
      nameNode.title = displayLabel;
      const metaNode = document.createElement('span');
      metaNode.className = 'startup-recent-card__meta';
      const updatedAt = Date.parse(entry.updatedAt || '');
      metaNode.textContent = Number.isFinite(updatedAt)
        ? formatUpdateHistoryDate(updatedAt, localizeText('保存時刻不明', 'Saved time unavailable'))
        : localizeText('保存時刻不明', 'Saved time unavailable');
      const deleteButton = document.createElement('button');
      deleteButton.type = 'button';
      deleteButton.className = 'startup-recent-card__delete';
      deleteButton.dataset.startupRecentDeleteId = entry.id;
      deleteButton.textContent = '×';
      deleteButton.title = localizeText('端末内プロジェクトを削除', 'Delete local project');
      deleteButton.setAttribute('aria-label', localizeText(`${displayLabel} を削除`, `Delete ${displayLabel}`));
      openButton.appendChild(thumb);
      openButton.appendChild(nameNode);
      openButton.appendChild(metaNode);
      card.appendChild(openButton);
      card.appendChild(deleteButton);
      list.appendChild(card);
    });
  }

  async function refreshRecentProjectsUI(options = {}) {
    const section = dom.startup?.recentSection;
    const list = dom.startup?.recentList;
    if (!section || !list) {
      return;
    }
    if (!AUTOSAVE_SUPPORTED) {
      recentProjectsCache.clear();
      list.innerHTML = '';
      section.hidden = true;
      return;
    }
    const shouldSanitize = options?.sanitize !== false;
    if (shouldSanitize) {
      await sanitizeRecentProjectsStore({ announce: false });
      return;
    }
    const entries = await loadRecentProjectsMetadata();
    setRecentProjectsCache(entries);
  }

  function blendChannelByMode(dst, src, blendMode) {
    switch (blendMode) {
      case 'multiply':
        return dst * src;
      case 'screen':
        return dst + src - (dst * src);
      case 'overlay':
        return dst <= 0.5 ? (2 * dst * src) : (1 - (2 * (1 - dst) * (1 - src)));
      case 'hard-light':
        return src <= 0.5 ? (2 * dst * src) : (1 - (2 * (1 - dst) * (1 - src)));
      case 'soft-light': {
        const d = dst <= 0.25
          ? (((16 * dst) - 12) * dst + 4) * dst
          : Math.sqrt(dst);
        return src <= 0.5
          ? dst - ((1 - (2 * src)) * dst * (1 - dst))
          : dst + (((2 * src) - 1) * (d - dst));
      }
      case 'darken':
        return Math.min(dst, src);
      case 'lighten':
        return Math.max(dst, src);
      case 'color-dodge':
        return src >= 1 ? 1 : Math.min(1, dst / (1 - src));
      case 'color-burn':
        return src <= 0 ? 0 : 1 - Math.min(1, (1 - dst) / src);
      case 'difference':
        return Math.abs(dst - src);
      case 'exclusion':
        return dst + src - (2 * dst * src);
      case 'normal':
      default:
        return src;
    }
  }

  function compositeLayerPixelNormalized(data, destBase, srcR, srcG, srcB, srcA, opacity, normalizedBlendMode) {
    if (opacity <= 0 || srcA <= 0) {
      return;
    }
    const srcAlpha = (srcA / 255) * opacity;
    if (srcAlpha <= 0) {
      return;
    }
    const dstAlpha = data[destBase + 3] / 255;
    const outAlpha = srcAlpha + dstAlpha * (1 - srcAlpha);
    if (outAlpha <= 0) {
      data[destBase] = 0;
      data[destBase + 1] = 0;
      data[destBase + 2] = 0;
      data[destBase + 3] = 0;
      return;
    }

    if (dstAlpha <= 0 || normalizedBlendMode === DEFAULT_LAYER_BLEND_MODE) {
      const srcFactor = srcAlpha / outAlpha;
      const dstFactor = (dstAlpha * (1 - srcAlpha)) / outAlpha;
      data[destBase] = Math.round(srcR * srcFactor + data[destBase] * dstFactor);
      data[destBase + 1] = Math.round(srcG * srcFactor + data[destBase + 1] * dstFactor);
      data[destBase + 2] = Math.round(srcB * srcFactor + data[destBase + 2] * dstFactor);
      data[destBase + 3] = Math.round(outAlpha * 255);
      return;
    }

    const dstR = data[destBase] / 255;
    const dstG = data[destBase + 1] / 255;
    const dstB = data[destBase + 2] / 255;
    const srcRNorm = srcR / 255;
    const srcGNorm = srcG / 255;
    const srcBNorm = srcB / 255;
    const blendedR = blendChannelByMode(dstR, srcRNorm, normalizedBlendMode);
    const blendedG = blendChannelByMode(dstG, srcGNorm, normalizedBlendMode);
    const blendedB = blendChannelByMode(dstB, srcBNorm, normalizedBlendMode);
    const dstWeight = (1 - srcAlpha) * dstAlpha;
    const srcWeight = (1 - dstAlpha) * srcAlpha;
    const blendWeight = srcAlpha * dstAlpha;

    data[destBase] = Math.round((((dstWeight * dstR) + (srcWeight * srcRNorm) + (blendWeight * blendedR)) / outAlpha) * 255);
    data[destBase + 1] = Math.round((((dstWeight * dstG) + (srcWeight * srcGNorm) + (blendWeight * blendedG)) / outAlpha) * 255);
    data[destBase + 2] = Math.round((((dstWeight * dstB) + (srcWeight * srcBNorm) + (blendWeight * blendedB)) / outAlpha) * 255);
    data[destBase + 3] = Math.round(outAlpha * 255);
  }

  function compositeLayerPixel(data, destBase, srcR, srcG, srcB, srcA, layerOpacity, blendMode) {
    const parsedOpacity = Number(layerOpacity);
    const opacity = Number.isFinite(parsedOpacity) ? clamp(parsedOpacity, 0, 1) : 1;
    const normalizedBlendMode = normalizeLayerBlendMode(blendMode);
    compositeLayerPixelNormalized(data, destBase, srcR, srcG, srcB, srcA, opacity, normalizedBlendMode);
  }

  async function generateSnapshotThumbnail(snapshot) {
    if (!snapshot || !snapshot.frames || !snapshot.frames.length) {
      return null;
    }
    const width = Math.max(1, Math.floor(Number(snapshot.width) || 0));
    const height = Math.max(1, Math.floor(Number(snapshot.height) || 0));
    if (!Number.isFinite(width) || !Number.isFinite(height) || width <= 0 || height <= 0) {
      return null;
    }
    const frameIndex = clamp(Number(snapshot.activeFrame) || 0, 0, snapshot.frames.length - 1);
    const frame = snapshot.frames[frameIndex];
    if (!frame || !Array.isArray(frame.layers)) {
      return null;
    }
    const offscreen = document.createElement('canvas');
    offscreen.width = width;
    offscreen.height = height;
    const offscreenCtx = offscreen.getContext('2d', { willReadFrequently: true });
    if (!offscreenCtx) {
      return null;
    }
    const imageData = offscreenCtx.createImageData(width, height);
    const data = imageData.data;
    const palette = Array.isArray(snapshot.palette) ? snapshot.palette : [];
    frame.layers.forEach(layer => {
      if (!layer) {
        return;
      }
      const opacity = 1;
      const blendMode = normalizeLayerBlendMode(layer.blendMode);
      const indices = layer.indices instanceof Int16Array ? layer.indices : null;
      const direct = layer.direct instanceof Uint8ClampedArray ? layer.direct : null;
      if (!indices && !direct) {
        return;
      }
      for (let y = 0; y < height; y += 1) {
        const rowOffset = y * width;
        for (let x = 0; x < width; x += 1) {
          const pixelIndex = rowOffset + x;
          let srcA = 0;
          let srcR = 0;
          let srcG = 0;
          let srcB = 0;
          if (indices) {
            const paletteIndex = indices[pixelIndex];
            if (paletteIndex >= 0) {
              const color = palette[paletteIndex];
              if (!color) {
                continue;
              }
              srcR = color.r;
              srcG = color.g;
              srcB = color.b;
              srcA = color.a;
            }
          }
          if (srcA === 0 && direct) {
            const base = pixelIndex * 4;
            srcA = direct[base + 3];
            if (srcA > 0) {
              srcR = direct[base];
              srcG = direct[base + 1];
              srcB = direct[base + 2];
            }
          }
          if (srcA <= 0) {
            continue;
          }
          const destBase = pixelIndex * 4;
          compositeLayerPixelNormalized(data, destBase, srcR, srcG, srcB, srcA, opacity, blendMode);
        }
      }
    });
    offscreenCtx.putImageData(imageData, 0, 0);

    const previewCanvas = document.createElement('canvas');
    previewCanvas.width = THUMBNAIL_CANVAS_SIZE;
    previewCanvas.height = THUMBNAIL_CANVAS_SIZE;
    const previewCtx = previewCanvas.getContext('2d');
    if (!previewCtx) {
      return null;
    }
    previewCtx.fillStyle = 'rgba(12, 20, 32, 0.92)';
    previewCtx.fillRect(0, 0, previewCanvas.width, previewCanvas.height);
    const padding = Math.round((THUMBNAIL_CANVAS_SIZE - THUMBNAIL_MAX_EDGE) / 2);
    const scale = Math.min(
      (THUMBNAIL_CANVAS_SIZE - padding * 2) / width,
      (THUMBNAIL_CANVAS_SIZE - padding * 2) / height,
    );
    const drawWidth = Math.max(1, Math.round(width * scale));
    const drawHeight = Math.max(1, Math.round(height * scale));
    const offsetX = Math.round((THUMBNAIL_CANVAS_SIZE - drawWidth) / 2);
    const offsetY = Math.round((THUMBNAIL_CANVAS_SIZE - drawHeight) / 2);
    previewCtx.imageSmoothingEnabled = false;
    previewCtx.drawImage(offscreen, 0, 0, width, height, offsetX, offsetY, drawWidth, drawHeight);
    return previewCanvas.toDataURL('image/png');
  }

  function getDotStatsApi() {
    return window.PiXiEEDDotStats && typeof window.PiXiEEDDotStats === 'object'
      ? window.PiXiEEDDotStats
      : null;
  }

  function createEmptyTrackedDotStats(dotStatsApi = getDotStatsApi()) {
    if (dotStatsApi && typeof dotStatsApi.normalizeDotStats === 'function') {
      const normalized = dotStatsApi.normalizeDotStats({ totalDots: 0, frameDots: [] });
      if (normalized) {
        return normalized;
      }
    }
    return {
      totalDots: 0,
      frameDots: [],
    };
  }

  function setTrackedProjectDotBaseline(snapshot, dotStats = null) {
    const dotStatsApi = getDotStatsApi();
    const normalizedDotStats = dotStatsApi && typeof dotStatsApi.normalizeDotStats === 'function'
      ? (dotStatsApi.normalizeDotStats(dotStats || { totalDots: 0, frameDots: [] }) || createEmptyTrackedDotStats(dotStatsApi))
      : (dotStats || createEmptyTrackedDotStats(null));
    projectDotCumulativeStats = normalizedDotStats;
    if (!snapshot || !dotStatsApi || typeof dotStatsApi.cloneEditorSnapshot !== 'function') {
      projectDotBaselineSnapshot = null;
      return;
    }
    try {
      projectDotBaselineSnapshot = dotStatsApi.cloneEditorSnapshot(snapshot);
    } catch (error) {
      console.warn('Failed to clone dot tracking baseline snapshot', error);
      projectDotBaselineSnapshot = null;
    }
  }

  function resolveTrackedProjectDotStats(snapshot = null) {
    const dotStatsApi = getDotStatsApi();
    if (!dotStatsApi || typeof dotStatsApi.normalizeDotStats !== 'function') {
      return null;
    }
    const baseStats = dotStatsApi.normalizeDotStats(projectDotCumulativeStats || createEmptyTrackedDotStats(dotStatsApi))
      || createEmptyTrackedDotStats(dotStatsApi);
    const currentSnapshot = snapshot && typeof snapshot === 'object'
      ? snapshot
      : makeHistorySnapshot({ clonePixelData: false });
    let deltaStats = createEmptyTrackedDotStats(dotStatsApi);
    try {
      if (typeof dotStatsApi.countEditorSnapshotDiff === 'function') {
        deltaStats = dotStatsApi.countEditorSnapshotDiff(currentSnapshot, projectDotBaselineSnapshot);
      } else if (typeof dotStatsApi.countEditorSnapshot === 'function') {
        deltaStats = dotStatsApi.countEditorSnapshot(currentSnapshot);
      }
    } catch (error) {
      console.warn('Failed to compute tracked project dot stats', error);
      deltaStats = createEmptyTrackedDotStats(dotStatsApi);
    }
    if (typeof dotStatsApi.combineDotStats === 'function') {
      const combined = dotStatsApi.combineDotStats(baseStats, deltaStats);
      return dotStatsApi.normalizeDotStats(combined) || combined;
    }
    return dotStatsApi.normalizeDotStats(deltaStats) || deltaStats;
  }

  function buildPackagedProjectPayload(snapshot, { session = null, updatedAt = '' } = {}) {
    const resolvedDotStats = resolveTrackedProjectDotStats(snapshot);
    const payload = serializeDocumentSnapshot(snapshot);
    const packagedSession = session && typeof session === 'object'
      ? session
      : buildProjectSessionPayload();
    const packaged = {
      type: PROJECT_PACKAGE_TYPE,
      packageVersion: PROJECT_PACKAGE_VERSION,
      version: DOCUMENT_FILE_VERSION,
      document: payload,
      session: packagedSession,
      updatedAt: updatedAt || new Date().toISOString(),
    };
    if (resolvedDotStats) {
      packaged.dotStats = resolvedDotStats;
    }
    return packaged;
  }

  function resolvePackagedProjectDotStats(packagedPayload, snapshot = null) {
    const dotStatsApi = getDotStatsApi();
    if (!dotStatsApi || typeof dotStatsApi.normalizeDotStats !== 'function') {
      return null;
    }
    return dotStatsApi.normalizeDotStats(packagedPayload?.dotStats || null);
  }

  function schedulePackagedProjectDotSync(projectId, dotStats) {
    const resolvedProjectId = normalizeAutosaveProjectId(projectId || '');
    if (!resolvedProjectId || !dotStats || dotStats.totalDots <= 0) {
      return;
    }
    const dotStatsApi = window.PiXiEEDDotStats && typeof window.PiXiEEDDotStats === 'object'
      ? window.PiXiEEDDotStats
      : null;
    if (!dotStatsApi || typeof dotStatsApi.syncProjectDotCount !== 'function') {
      return;
    }
    window.setTimeout(() => {
      dotStatsApi.syncProjectDotCount({
        projectId: resolvedProjectId,
        dotCount: dotStats.totalDots,
        app: 'pixiedraw',
      }).catch(error => {
        console.warn('Failed to sync PiXiEEDraw dot total', error);
      });
    }, 0);
  }

  async function recordRecentProjectSnapshot(
    snapshot,
    packagedPayload,
    {
      projectId = '',
      skipThumbnail = false,
      thumbnailIntervalMs = LOCAL_PROJECT_THUMBNAIL_UPDATE_INTERVAL_MS,
    } = {}
  ) {
    if (!AUTOSAVE_SUPPORTED) {
      return null;
    }
    if (isResidentMultiConnectedRoom()) {
      return null;
    }
    if (!snapshot || typeof snapshot !== 'object') {
      return null;
    }
    try {
      const resolvedProjectId = setActiveAutosaveProjectId(projectId || autosaveProjectId || createAutosaveProjectId());
      const packaged = packagedPayload && typeof packagedPayload === 'object'
        ? packagedPayload
        : buildPackagedProjectPayload(snapshot);
      const existingEntries = await loadRecentProjectsMetadata();
      const previousEntry = existingEntries.find(entry => entry?.id === resolvedProjectId) || null;
      const workingEntries = existingEntries
        .filter(entry => entry && entry.id && entry.id !== resolvedProjectId);
      const fileName = normalizeDocumentName(snapshot?.documentName || DEFAULT_DOCUMENT_NAME);
      const displayName = extractDocumentBaseName(fileName);
      const nowTs = Date.now();
      const previousUpdatedAt = previousEntry?.updatedAt ? Date.parse(previousEntry.updatedAt) : NaN;
      const safeThumbnailInterval = Math.max(
        0,
        Math.round(Number(thumbnailIntervalMs) || LOCAL_PROJECT_THUMBNAIL_UPDATE_INTERVAL_MS)
      );
      const shouldRefreshThumbnail =
        !skipThumbnail
        && (
          !previousEntry?.thumbnail
          || !Number.isFinite(previousUpdatedAt)
          || (nowTs - previousUpdatedAt >= safeThumbnailInterval)
        );
      const thumbnail = shouldRefreshThumbnail
        ? (await generateSnapshotThumbnail(snapshot))
        : previousEntry.thumbnail;
      const dotStats = resolvePackagedProjectDotStats(packaged, snapshot);
      const updatedEntry = {
        id: resolvedProjectId,
        name: displayName,
        fileName,
        updatedAt: packaged.updatedAt || new Date().toISOString(),
        thumbnail: thumbnail || null,
        project: packaged,
      };
      if (dotStats) {
        updatedEntry.dotStats = dotStats;
      }
      workingEntries.unshift(updatedEntry);
      const limited = workingEntries.slice(0, RECENT_PROJECT_LIMIT);
      await saveRecentProjectsList(existingEntries, limited);
      setRecentProjectsCache(limited);
      if (dotStats) {
        setTrackedProjectDotBaseline(snapshot, dotStats);
        schedulePackagedProjectDotSync(resolvedProjectId, dotStats);
      }
      return updatedEntry;
    } catch (error) {
      console.warn('Failed to record recent project snapshot', error);
      return null;
    }
  }

  async function openRecentProject(entry, options = {}) {
    if (!entry || typeof entry !== 'object') {
      return false;
    }
    const hideStartupOnSuccess = options.hideStartup !== false;
    const silent = options.silent === true;
    if (!ensureCurrentClientCanReplaceActiveProject({ announce: !silent })) {
      return false;
    }
    try {
      if (entry.project && typeof entry.project === 'object') {
        const loaded = await loadDocumentFromText(JSON.stringify(entry.project), null, {
          projectId: entry.id || '',
          suppressAutosaveStatus: true,
          openedFromRecent: true,
        });
        if (!loaded) {
          await removeRecentProjectEntry(entry.id || '', {
            announce: !silent,
            reason: 'データ形式が壊れていたため',
          });
          return false;
        }
        if (!silent) {
          updateAutosaveStatus('自動保存: 端末内プロジェクトを開きました', 'success');
        }
        if (hideStartupOnSuccess) {
          hideStartupScreen();
        }
        return true;
      }

      if (entry.handle) {
        const loaded = await loadDocumentFromHandle(entry.handle, {
          projectId: entry.id || '',
          suppressAutosaveStatus: true,
          openedFromRecent: true,
        });
        if (!loaded) {
          await removeRecentProjectEntry(entry.id || '', {
            announce: !silent,
            reason: '旧ファイル権限が無効なため',
          });
          return false;
        }
        if (!silent) {
          updateAutosaveStatus('自動保存: プロジェクトを開きました', 'success');
        }
        if (hideStartupOnSuccess) {
          hideStartupScreen();
        }
        return true;
      }

      updateAutosaveStatus('プロジェクトを開けませんでした', 'error');
      return false;
    } catch (error) {
      console.warn('Failed to open recent project', error);
      if (entry.project && typeof entry.project === 'object') {
        await removeRecentProjectEntry(entry.id || '', {
          announce: !silent,
          reason: '読込時に例外が発生したため',
        });
      }
      updateAutosaveStatus('プロジェクトを開けませんでした', 'error');
      return false;
    }
  }

  function serializeDocumentSnapshot(snapshot) {
    const palette = snapshot.palette.map(color => normalizeColorValue(color));
    // Personal view/tool/color preferences stay in local session storage instead of shared project payloads.
    const serialized = {
      version: DOCUMENT_FILE_VERSION,
      width: snapshot.width,
      height: snapshot.height,
      palette,
      frames: snapshot.frames.map(frame => ({
        id: frame.id,
        name: frame.name,
        duration: frame.duration,
        layers: frame.layers.map(layer => ({
          id: layer.id,
          name: layer.name,
          blendMode: normalizeLayerBlendMode(layer.blendMode),
          indices: encodeTypedArray(layer.indices),
          direct: encodeTypedArray(layer.direct),
        })),
      })),
      documentName: normalizeDocumentName(snapshot.documentName),
      dualLeftRail: false,
    };
    if (snapshot.playback && typeof snapshot.playback === 'object') {
      serialized.playback = {
        isPlaying: Boolean(snapshot.playback.isPlaying),
        lastFrame: Number(snapshot.playback.lastFrame) || 0,
      };
    }
    return serialized;
  }

  function deserializeDocumentPayload(payload) {
    if (!payload || typeof payload !== 'object') {
      throw new Error('Invalid document payload');
    }
    const width = clamp(
      Math.round(Number(payload.width) || state.width || DEFAULT_CANVAS_SIZE),
      1,
      4096
    );
    const height = clamp(
      Math.round(Number(payload.height) || state.height || DEFAULT_CANVAS_SIZE),
      1,
      4096
    );
    const pixelCount = width * height;
    const paletteSource = Array.isArray(payload.palette) ? payload.palette : [];
    const palette = paletteSource.length ? paletteSource.map(color => normalizeColorValue(color)) : state.palette.map(color => ({ ...color }));

    const framesSource = Array.isArray(payload.frames) ? payload.frames : [];
    if (!framesSource.length) {
      throw new Error('Document has no frames');
    }

    const frames = framesSource.map((frame, frameIndex) => {
      if (!frame || !Array.isArray(frame.layers) || !frame.layers.length) {
        throw new Error(`Frame ${frameIndex} has no layers`);
      }
      const layers = frame.layers.map((layer, layerIndex) => {
        if (!layer || typeof layer.indices !== 'string') {
          throw new Error(`Layer ${layerIndex} is missing index data`);
        }
        const indicesBytes = decodeBase64(layer.indices);
        if (indicesBytes.length !== pixelCount * 2) {
          throw new Error('Layer pixel data mismatch');
        }
        const indicesView = new Int16Array(indicesBytes.buffer, indicesBytes.byteOffset, indicesBytes.byteLength / 2);
        const indices = new Int16Array(indicesView.length);
        indices.set(indicesView);
        let direct = null;
        if (typeof layer.direct === 'string' && layer.direct.length > 0) {
          const directBytes = decodeBase64(layer.direct);
          if (directBytes.length !== pixelCount * 4) {
            throw new Error('Layer direct pixel data mismatch');
          }
          direct = new Uint8ClampedArray(directBytes.length);
          direct.set(directBytes);
        }
        return {
          id: typeof layer.id === 'string' ? layer.id : `layer-${frameIndex}-${layerIndex}`,
          name: typeof layer.name === 'string' ? layer.name : getDefaultLayerName(layerIndex + 1),
          visible: layer.visible !== false,
          opacity: 1,
          blendMode: normalizeLayerBlendMode(layer.blendMode),
          indices,
          direct,
        };
      });
      return {
        id: typeof frame.id === 'string' ? frame.id : `frame-${frameIndex + 1}`,
        name: typeof frame.name === 'string' ? frame.name : getDefaultFrameName(frameIndex + 1),
        duration: clamp(Number(frame.duration) || 1000 / 12, 16, 2000),
        layers,
      };
    });

    const activeFrameIndex = clamp(Math.round(Number(payload.activeFrame) || 0), 0, frames.length - 1);
    const activeFrame = frames[activeFrameIndex];
    let activeLayerId = typeof payload.activeLayer === 'string' ? payload.activeLayer : activeFrame.layers[activeFrame.layers.length - 1].id;
    if (!activeFrame.layers.some(layer => layer.id === activeLayerId)) {
      activeLayerId = activeFrame.layers[activeFrame.layers.length - 1].id;
    }

    let selectionMask = null;
    if (typeof payload.selectionMask === 'string') {
      const maskBytes = decodeBase64(payload.selectionMask);
      if (maskBytes.length === pixelCount) {
        selectionMask = new Uint8Array(maskBytes.length);
        selectionMask.set(maskBytes);
      }
    }

    const selectionBounds = validateBoundsObject(payload.selectionBounds);
    const activeTool = normalizeToolId(payload.tool, state.tool);
    const selectSameMode = normalizeSelectSameMode(payload.selectSameMode, state.selectSameMode);
    const customBrush = deserializeCustomBrushPayload(payload.customBrush);
    const requestedBrushShape = normalizeBrushShape(payload.brushShape, BRUSH_SHAPE_SQUARE);
    const brushShape = requestedBrushShape === BRUSH_SHAPE_CUSTOM && !customBrush
      ? BRUSH_SHAPE_SQUARE
      : requestedBrushShape;
    const colorMode = normalizeColorMode(payload.colorMode, state.colorMode);
    const fallbackActivePaletteIndex = clamp(
      Number.isFinite(state.activePaletteIndex) ? Math.round(state.activePaletteIndex) : 0,
      0,
      palette.length - 1
    );
    const parsedActivePaletteIndex = Number(payload.activePaletteIndex);
    const activePaletteIndex = clamp(
      Number.isFinite(parsedActivePaletteIndex) ? Math.round(parsedActivePaletteIndex) : fallbackActivePaletteIndex,
      0,
      palette.length - 1
    );
    const parsedSecondaryPaletteIndex = Number(payload.secondaryPaletteIndex);
    const secondaryPaletteIndex = clamp(
      Number.isFinite(parsedSecondaryPaletteIndex) ? Math.round(parsedSecondaryPaletteIndex) : activePaletteIndex,
      0,
      palette.length - 1
    );
    const fallbackActiveRgb = palette[activePaletteIndex]
      ? normalizeColorValue(palette[activePaletteIndex])
      : normalizeColorValue(state.activeRgb);
    const activeRgb = normalizeColorValue(payload.activeRgb || fallbackActiveRgb);
    const backgroundMode = payload.backgroundMode === 'light' || payload.backgroundMode === 'pink' ? payload.backgroundMode : 'dark';
    const uiTheme = normalizeUiTheme(payload.uiTheme, state.uiTheme);
    let activeToolGroup = TOOL_GROUPS[payload.activeToolGroup] ? payload.activeToolGroup : (TOOL_TO_GROUP[activeTool] || state.activeToolGroup);
    if (!TOOL_GROUPS[activeToolGroup]?.tools?.includes(activeTool)) {
      activeToolGroup = TOOL_TO_GROUP[activeTool] || 'pen';
    }
    const lastGroupTool = normalizeLastGroupTool(payload.lastGroupTool);
    const activeLeftTab = LEFT_TAB_KEYS.includes(payload.activeLeftTab) ? payload.activeLeftTab : state.activeLeftTab;
    const activeRightTab = RIGHT_TAB_KEYS.includes(payload.activeRightTab) ? payload.activeRightTab : state.activeRightTab;
    const documentName = normalizeDocumentName(
      typeof payload.documentName === 'string' ? payload.documentName : (typeof payload.name === 'string' ? payload.name : state.documentName),
    );

    return {
      width,
      height,
      scale: normalizeZoomScale(payload.scale, state.scale || MIN_ZOOM_SCALE),
      pan: {
        x: Math.round(Number(payload.pan?.x) || 0),
        y: Math.round(Number(payload.pan?.y) || 0),
      },
      tool: activeTool,
      brushSize: clamp(Math.round(Number(payload.brushSize) || state.brushSize || 1), 1, 64),
      brushShape,
      selectSameMode,
      customBrush,
      colorMode,
      palette,
      activePaletteIndex,
      secondaryPaletteIndex,
      activeRgb,
      frames,
      activeFrame: activeFrameIndex,
      activeLayer: activeLayerId,
      selectionMask,
      selectionBounds,
      showGrid: Boolean(payload.showGrid ?? state.showGrid),
      showMajorGrid: Boolean(payload.showMajorGrid ?? state.showMajorGrid),
      gridScreenStep: clamp(Math.round(Number(payload.gridScreenStep) || state.gridScreenStep || 8), 1, 256),
      majorGridSpacing: clamp(Math.round(Number(payload.majorGridSpacing) || state.majorGridSpacing || 16), 2, 512),
      backgroundMode,
      uiTheme,
      activeToolGroup,
      lastGroupTool,
      activeLeftTab,
      activeRightTab,
      showPixelGuides: Boolean(payload.showPixelGuides ?? state.showPixelGuides),
      mirror: normalizeMirrorAxisState(payload.mirror, width, height),
      showVirtualCursor: Boolean(payload.showVirtualCursor ?? state.showVirtualCursor),
      showChecker: Boolean(payload.showChecker ?? state.showChecker),
      onionSkin: normalizeOnionSkinState(payload.onionSkin ?? state.onionSkin),
      dualLeftRail: false,
      playback: typeof payload.playback === 'object' && payload.playback
        ? {
          isPlaying: Boolean(payload.playback.isPlaying),
          lastFrame: Number(payload.playback.lastFrame) || 0,
        }
        : { isPlaying: false, lastFrame: 0 },
      documentName,
    };
  }

  // -------------------------------------------------------------------------
  // Export helpers
  // -------------------------------------------------------------------------

  function getActiveFrameCompositePixels() {
    const frame = getActiveFrame();
    if (!frame) {
      return null;
    }
    const pixels = compositeFramePixels(frame, state.width, state.height, state.palette);
    return { frame, pixels };
  }

  function getPixfindFramePair() {
    if (!Array.isArray(state.frames) || state.frames.length < 2) {
      return null;
    }
    const originalFrame = state.frames[0];
    const diffFrame = state.frames[1];
    if (!originalFrame || !diffFrame) {
      return null;
    }
    return { originalFrame, diffFrame };
  }

  function getPixfindSendDisabledReason() {
    const exportReason = getMultiExportDisabledReason('pixfind');
    if (exportReason) {
      return exportReason;
    }
    if (!pixfindModeEnabled) {
      return localizeText('間違い探しモードをONにしてください', 'Turn on PiXFiND mode first');
    }
    if (!getPixfindFramePair()) {
      return localizeText(
        'フレーム2がありません。間違い探しモードをONにすると自動で作成されます',
        'Frame 2 is missing. It is created automatically when PiXFiND mode is enabled.'
      );
    }
    return '';
  }

  function setPixfindHelpExpanded(expanded) {
    const next = Boolean(expanded);
    if (dom.controls.pixfindHelpText instanceof HTMLElement) {
      dom.controls.pixfindHelpText.hidden = !next;
      dom.controls.pixfindHelpText.setAttribute('aria-hidden', String(!next));
    }
    if (dom.controls.togglePixfindHelp instanceof HTMLButtonElement) {
      dom.controls.togglePixfindHelp.setAttribute('aria-expanded', String(next));
      dom.controls.togglePixfindHelp.classList.toggle('is-active', next);
      dom.controls.togglePixfindHelp.textContent = next
        ? localizeText('間違い探しモードの説明を閉じる', 'Hide PiXFiND Mode Help')
        : localizeText('間違い探しモードの説明', 'PiXFiND Mode Help');
    }
  }

  function updatePixfindModeUI() {
    const modeControl = dom.controls.togglePixfindMode;
    const sendDisabledReason = getPixfindSendDisabledReason();
    if (modeControl instanceof HTMLInputElement) {
      modeControl.checked = pixfindModeEnabled;
    }
    if (dom.controls.sendToPixfind) {
      dom.controls.sendToPixfind.disabled = Boolean(sendDisabledReason);
      if (sendDisabledReason) {
        dom.controls.sendToPixfind.title = sendDisabledReason;
      } else {
        dom.controls.sendToPixfind.removeAttribute('title');
      }
    }
    if (dom.controls.pixfindActionReason) {
      dom.controls.pixfindActionReason.textContent = sendDisabledReason || localizeText('PiXFiNDへ送信できます', 'Ready to send to PiXFiND');
    }
  }

  function ensurePixfindDiffFrame({ quiet = false, recordHistory = true, forceRecreate = false } = {}) {
    if (!Array.isArray(state.frames) || !state.frames.length) {
      if (!quiet) {
        updateAutosaveStatus(localizeText('PiXFiND用の原本フレームがありません', 'No original frame found for PiXFiND'), 'warn');
      }
      return false;
    }
    const originalFrame = state.frames[0];
    if (!originalFrame || !Array.isArray(originalFrame.layers) || !originalFrame.layers.length) {
      if (!quiet) {
        updateAutosaveStatus(localizeText('PiXFiND用の原本フレームを作成できませんでした', 'Failed to prepare the original frame for PiXFiND'), 'warn');
      }
      return false;
    }
    const hadDiffFrame = Boolean(state.frames[1]);
    if (hadDiffFrame && !forceRecreate) {
      return true;
    }
    const preferredLayerIndex = originalFrame.layers.findIndex(layer => layer.id === state.activeLayer);
    if (recordHistory) {
      beginHistory(hadDiffFrame ? 'resetPixfindFrame2' : 'createPixfindFrame2');
    }
    const diffFrame = createFrame(getDefaultFrameName(2), originalFrame.layers, state.width, state.height);
    if (Number.isFinite(originalFrame.duration) && originalFrame.duration > 0) {
      diffFrame.duration = originalFrame.duration;
    }
    if (hadDiffFrame) {
      state.frames[1] = diffFrame;
    } else {
      state.frames.splice(1, 0, diffFrame);
    }
    state.activeFrame = 1;
    if (diffFrame.layers.length) {
      const targetLayerIndex = preferredLayerIndex >= 0
        ? clamp(preferredLayerIndex, 0, diffFrame.layers.length - 1)
        : diffFrame.layers.length - 1;
      state.activeLayer = diffFrame.layers[targetLayerIndex].id;
    }
    markHistoryDirty();
    scheduleSessionPersist();
    renderFrameList();
    renderLayerList();
    requestRender();
    requestOverlayRender();
    if (recordHistory) {
      commitHistory();
    }
    updatePixfindModeUI();
    if (!quiet) {
      updateAutosaveStatus(
        hadDiffFrame
          ? localizeText('PiXFiND用にフレーム2をフレーム1から作り直しました', 'Rebuilt Frame 2 from Frame 1 for PiXFiND')
          : localizeText('PiXFiND用にフレーム2を作成しました。フレーム2を編集して送信してください', 'Created Frame 2 for PiXFiND. Edit Frame 2 and send it.'),
        'success'
      );
    }
    return true;
  }

  function setPixfindModeEnabled(enabled, { confirmFirst = true, confirmOverwrite = true, quiet = false } = {}) {
    if (!canCurrentClientEditProjectStructure()) {
      setMultiStatus(localizeText('参加/視聴モードでは間違い探し設定はマスターのみ変更できます', 'In participant/viewer mode, only the master can change PiXFiND settings'), 'warn');
      return false;
    }
    const next = Boolean(enabled);
    if (next === pixfindModeEnabled) {
      updatePixfindModeUI();
      return true;
    }
    if (next && confirmFirst && !pixfindModeFirstEnableConfirmed) {
      const accepted = window.confirm(
        localizeText(
          '間違い探しモードを初めてONにします。フレーム1を原本、フレーム2を差分として使います。続けますか？',
          'Enable PiXFiND mode for the first time? Frame 1 will be original and Frame 2 will be diff. Continue?'
        )
      );
      if (!accepted) {
        return false;
      }
      pixfindModeFirstEnableConfirmed = true;
    }
    if (next && confirmOverwrite && Array.isArray(state.frames) && state.frames.length >= 2) {
      const acceptedOverwrite = window.confirm(
        localizeText(
          '間違い探しモードをONにすると、現在のフレーム2はフレーム1の内容で上書きされます。続けますか？',
          'Enabling PiXFiND mode overwrites current Frame 2 with Frame 1 content. Continue?'
        )
      );
      if (!acceptedOverwrite) {
        return false;
      }
    }
    pixfindModeEnabled = next;
    if (next) {
      const prepared = ensurePixfindDiffFrame({ quiet: true, recordHistory: true, forceRecreate: true });
      const pair = getPixfindFramePair();
      if (pair && state.activeFrame !== 1) {
        setActiveFrameIndex(1, { wrap: false, persist: false, render: true });
      }
      if (!quiet) {
        if (prepared && pair) {
          updateAutosaveStatus(
            localizeText(
              '間違い探しモードをONにしました。フレーム1=原本、フレーム2=差分です',
              'PiXFiND mode enabled. Frame 1 = original, Frame 2 = diff.'
            ),
            'info'
          );
        } else {
          updateAutosaveStatus(
            localizeText(
              '間違い探しモードをONにしましたが、フレーム2を用意できませんでした',
              'PiXFiND mode enabled, but Frame 2 could not be prepared.'
            ),
            'warn'
          );
        }
      }
    } else {
      if (!quiet) {
        updateAutosaveStatus(localizeText('間違い探しモードをOFFにしました', 'PiXFiND mode disabled'), 'info');
      }
    }
    updatePixfindModeUI();
    scheduleSessionPersist();
    return true;
  }

  function syncPixfindSnapshotAfterDocumentReset() {
    updatePixfindModeUI();
  }

  function exportProjectToPixfind() {
    if (!ensureCurrentClientCanExportProject({ announce: true, format: 'pixfind' })) {
      return;
    }
    if (!pixfindModeEnabled) {
      updateAutosaveStatus(localizeText('間違い探しモードをONにしてください', 'Turn on PiXFiND mode first'), 'warn');
      return;
    }
    const pair = getPixfindFramePair();
    if (!pair) {
      updateAutosaveStatus(localizeText('PiXFiND出力にはフレーム1とフレーム2が必要です', 'PiXFiND export requires Frame 1 and Frame 2'), 'warn');
      return;
    }
    try {
      const basePixels = compositeFramePixels(pair.originalFrame, state.width, state.height, state.palette);
      const diffPixels = compositeFramePixels(pair.diffFrame, state.width, state.height, state.palette);
      const baseCanvas = createFrameCanvas(basePixels, state.width, state.height);
      const diffCanvas = createFrameCanvas(diffPixels, state.width, state.height);
      const originalDataUrl = baseCanvas.toDataURL('image/png');
      const diffDataUrl = diffCanvas.toDataURL('image/png');
      if (!originalDataUrl || !diffDataUrl) {
        throw new Error('Missing PiXFiND data URL');
      }
      try {
        const payload = {
          originalDataUrl,
          diffDataUrl,
          canvasSize: state.width === state.height ? state.width : `${state.width}x${state.height}`,
          width: state.width,
          height: state.height,
          createdAt: new Date().toISOString(),
        };
        localStorage.setItem(PIXFIND_UPLOAD_KEY, JSON.stringify(payload));
      } catch (error) {
        console.warn('pixfind upload store failed', error);
      }
      markDocumentDurablySaved();
      window.location.href = '../pixfind/index.html#creator';
    } catch (error) {
      console.error('PiXFiND export failed', error);
      updateAutosaveStatus(localizeText('PiXFiND出力に失敗しました', 'PiXFiND export failed'), 'error');
    }
  }

  async function exportProjectAsGridPng() {
    if (!ensureCurrentClientCanExportProject({ announce: true, format: 'gridpng' })) {
      return;
    }
    const frameCount = state.frames.length;
    if (!frameCount) {
      updateAutosaveStatus('グリッド分割で書き出すフレームがありません', 'warn');
      return;
    }
    try {
      const { width, height } = state;
      const candidates = getExportScaleCandidates();
      const selectedScale = applyExportScaleConstraints(candidates);
      syncExportScaleInputs();
      exportGridTileWidth = normalizeExportGridTileSize(exportGridTileWidth, 8);
      exportGridTileHeight = normalizeExportGridTileSize(exportGridTileHeight, 8);
      syncExportGridInputs();
      const framePixels = compositeDocumentFrames(state.frames, width, height, state.palette);
      // Grid split size is defined in source pixels, then mapped to export scale.
      // This keeps tile count stable even when export scale is > 1.
      const rowSegments = buildGridRowSegmentsTopToBottom(height, exportGridTileHeight);
      const columnSegments = buildGridColumnSegmentsRightToLeft(width, exportGridTileWidth);
      const tileCountPerFrame = rowSegments.length * columnSegments.length;
      if (!tileCountPerFrame) {
        updateAutosaveStatus('分割サイズの設定が無効です', 'warn');
        return;
      }
      const total = tileCountPerFrame * frameCount;
      const rowDigits = Math.max(2, String(rowSegments.length).length);
      const columnDigits = Math.max(2, String(columnSegments.length).length);
      let exportedCount = 0;
      let wasCancelled = false;
      let hadFailure = false;

      for (let frameIndex = 0; frameIndex < frameCount; frameIndex += 1) {
        if (wasCancelled || hadFailure) {
          break;
        }
        const frameCanvas = createFrameCanvas(framePixels[frameIndex], width, height);
        const outputCanvas = scaleCanvasNearestNeighbor(frameCanvas, selectedScale);
        for (let rowIndex = 0; rowIndex < rowSegments.length; rowIndex += 1) {
          if (wasCancelled || hadFailure) {
            break;
          }
          const rowSegment = rowSegments[rowIndex];
          const rowNumber = String(rowIndex + 1).padStart(rowDigits, '0');
          for (let columnIndex = 0; columnIndex < columnSegments.length; columnIndex += 1) {
            const columnSegment = columnSegments[columnIndex];
            const columnNumber = String(columnIndex + 1).padStart(columnDigits, '0');
            const exportX = columnSegment.start * selectedScale;
            const exportY = rowSegment.start * selectedScale;
            const exportWidth = columnSegment.size * selectedScale;
            const exportHeight = rowSegment.size * selectedScale;
            const blob = await canvasRegionToBlob(
              outputCanvas,
              exportX,
              exportY,
              exportWidth,
              exportHeight,
              'image/png'
            );
            const suffixParts = [];
            if (frameCount > 1) {
              suffixParts.push(String(frameIndex + 1));
            }
            suffixParts.push(`r${rowNumber}`, `c${columnNumber}`);
            if (selectedScale > 1) {
              suffixParts.push(`x${selectedScale}`);
            }
            const suffix = suffixParts.join('_');
            const deliveryResult = await triggerDownloadFromBlob(
              blob,
              createExportFileName('png', suffix),
              {
                mimeType: 'image/png',
                fileExtensions: ['.png'],
                shareTitle: state.documentName || 'PiXiEEDraw',
                shareText: `グリッド分割PNGを書き出しました (r${rowIndex + 1}, c${columnIndex + 1})`,
                allowFilePicker: true,
                allowBoundDirectory: true,
              }
            );
            switch (deliveryResult) {
              case 'gallery':
              case 'native':
              case 'directory':
              case 'picker':
              case 'download':
              case 'share':
              case 'window':
                exportedCount += 1;
                break;
              case 'picker-cancel':
              case 'share-cancel':
                wasCancelled = true;
                break;
              default:
                hadFailure = true;
                break;
            }
            if (wasCancelled || hadFailure) {
              break;
            }
          }
        }
      }

      const detailParts = [];
      detailParts.push(`分割 ${exportGridTileWidth}×${exportGridTileHeight}px`);
      if (frameCount > 1) {
        detailParts.push(`全${frameCount}フレーム`);
      }
      if (selectedScale > 1) {
        detailParts.push(`倍率 ×${selectedScale}`);
      }
      detailParts.push(`右上→左 / 上→下`);
      const detail = detailParts.length ? ` (${detailParts.join(' / ')})` : '';

      if (exportedCount === total) {
        updateAutosaveStatus(`グリッド分割PNGを書き出しました${detail}`, 'success');
      } else if (wasCancelled) {
        const remaining = total - exportedCount;
        updateAutosaveStatus(remaining === total
          ? 'グリッド分割PNGの書き出しをキャンセルしました'
          : `グリッド分割PNGを書き出しましたが ${remaining} 件はキャンセルされました`, 'warn');
      } else if (exportedCount > 0 && hadFailure) {
        updateAutosaveStatus(`グリッド分割PNGを書き出しましたが ${total - exportedCount} 件エクスポートできませんでした`, 'warn');
      } else {
        updateAutosaveStatus('グリッド分割PNGの書き出しに失敗しました', 'error');
      }

      if (exportedCount > 0) {
        markDocumentDurablySaved();
        if (exportedCount === total && !wasCancelled && !hadFailure) {
          const companionResult = await maybeSaveProjectCompanionAfterExport('gridpng', {
            exportedCount,
            wasCancelled,
          });
          announceProjectCompanionSaveResult('gridpng', companionResult);
        }
        showExportInterstitialAfterImageExport();
      }
    } catch (error) {
      console.error('Grid PNG export failed', error);
      updateAutosaveStatus('グリッド分割PNGの書き出しに失敗しました', 'error');
    }
  }

  async function exportProjectAsPng() {
    if (!ensureCurrentClientCanExportProject({ announce: true, format: 'png' })) {
      return;
    }
    const frameCount = state.frames.length;
    if (!frameCount) {
      updateAutosaveStatus('PNGを書き出すフレームがありません', 'warn');
      return;
    }
    try {
      const { width, height } = state;
      const candidates = getExportScaleCandidates();
      const selectedScale = applyExportScaleConstraints(candidates);
      syncExportScaleInputs();
      const framePixels = compositeDocumentFrames(state.frames, width, height, state.palette);
      const includeOriginal = shouldExportOriginalCompanion('png', selectedScale);
      const tasks = [];
      const hasMultipleFrames = frameCount > 1;
      for (let index = 0; index < frameCount; index += 1) {
        const baseCanvas = createFrameCanvas(framePixels[index], width, height);
        const variants = [{ scale: selectedScale, isOriginal: false }];
        if (includeOriginal) {
          variants.push({ scale: 1, isOriginal: true });
        }
        for (let variantIndex = 0; variantIndex < variants.length; variantIndex += 1) {
          const variant = variants[variantIndex];
          const outputCanvas = scaleCanvasNearestNeighbor(baseCanvas, variant.scale);
          const blob = await canvasToBlob(outputCanvas, 'image/png');
          if (!blob) {
            throw new Error('Failed to create PNG blob');
          }
          let suffix = hasMultipleFrames ? String(index + 1) : '';
          if (variant.scale > 1 || includeOriginal) {
            suffix = suffix ? `${suffix}_x${variant.scale}` : `x${variant.scale}`;
          }
          tasks.push({
            blob,
            filename: createExportFileName('png', suffix),
            shareText: `フレーム${index + 1}のPNGを書き出しました${variant.scale > 1 ? ` (×${variant.scale})` : ''}`,
          });
        }
      }

      const result = await deliverExportTasks(tasks, {
        mimeType: 'image/png',
        fileExtensions: ['.png'],
        shareTitle: state.documentName || 'PiXiEEDraw',
        shareText: 'PNGを書き出しました',
      });
      const detailParts = [];
      if (frameCount > 1) {
        detailParts.push(`全${frameCount}フレーム`);
      }
      if (selectedScale > 1) {
        detailParts.push(`×${selectedScale}`);
      }
      if (includeOriginal) {
        detailParts.push('原寸も追加');
      }
      const detail = detailParts.length ? ` (${detailParts.join(' / ')})` : '';

      if (result.exportedCount === result.total) {
        updateAutosaveStatus(`PNGを書き出しました${detail}`, 'success');
      } else if (result.wasCancelled) {
        const remaining = result.total - result.exportedCount;
        updateAutosaveStatus(remaining === result.total
          ? 'PNGの書き出しをキャンセルしました'
          : `PNGを書き出しましたが ${remaining} 件はキャンセルされました`, 'warn');
      } else if (result.exportedCount > 0 && result.hadFailure) {
        updateAutosaveStatus(`PNGを書き出しましたが ${result.total - result.exportedCount} 件エクスポートできませんでした`, 'warn');
      } else {
        updateAutosaveStatus('PNGの書き出しに失敗しました', 'error');
      }
      if (result.exportedCount > 0) {
        markDocumentDurablySaved();
        let skipInterstitial = false;
        if (result.exportedCount === result.total && !result.wasCancelled && !result.hadFailure) {
          const companionResult = await maybeSaveProjectCompanionAfterExport('png', {
            exportedCount: result.exportedCount,
            wasCancelled: result.wasCancelled,
          });
          announceProjectCompanionSaveResult('png', companionResult);
          skipInterstitial = await maybeRedirectToContestPostAfterExport('png', {
            primaryBlob: tasks[0]?.blob || null,
            companionResult,
          });
        }
        if (!skipInterstitial) {
          showExportInterstitialAfterImageExport();
        }
      }
    } catch (error) {
      console.error('PNG export failed', error);
      updateAutosaveStatus('PNGの書き出しに失敗しました', 'error');
    }
  }

